INSERT INTO `comments` VALUES (1, 2, 'dongyi001', 'plant', 1, '钩藤确实是治疗惊风的良药，我孩子小时候用过，效果很好！', NULL, NULL, NULL, 10, 2, 'approved', '2026-03-04 04:47:10', '2026-03-12 20:06:01');
INSERT INTO `comments` VALUES (2, 3, 'herb_fan', 'plant', 2, '透骨草在我们侗寨很常见，老人们常用来治疗跌打损伤。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (3, 4, 'culture_lover', 'plant', 5, '七叶一枝花是珍贵的药材，现在野外越来越少了，需要保护。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (4, 2, 'dongyi001', 'knowledge', 1, '药浴疗法真的很舒服，泡完之后全身轻松，推荐大家试试。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (5, 3, 'herb_fan', 'knowledge', 2, '艾灸疗法对宫寒很有效，我坚持艾灸三个月，身体好多了。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (6, 5, 'test', 'knowledge', 4, '蛇伤急救方很实用，我们山区经常遇到蛇，学习了！', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (7, 2, 'dongyi001', 'inheritor', 1, '吴明德老先生是真正的侗医大师，医术精湛，医德高尚。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (8, 3, 'herb_fan', 'inheritor', 2, '杨秀珍奶奶治好了我多年的妇科病，非常感谢！', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (9, 4, 'culture_lover', 'inheritor', 3, '石文昌医生的正骨手法很厉害，我父亲的腰伤就是他治好的。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (10, 5, 'test', 'resource', 1, '入门指南写得很详细，对初学者很有帮助。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (11, 2, 'dongyi001', 'resource', 2, '药浴视频教程很实用，跟着学了几次，已经掌握了基本方法。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
INSERT INTO `comments` VALUES (12, 3, 'herb_fan', 'resource', 3, '草药图谱很精美，每种药材都有详细说明，值得收藏。', NULL, NULL, NULL, 0, 0, 'approved', '2026-03-04 04:47:10', '2026-03-04 04:47:10');
