INSERT INTO `feedback` VALUES (1, 2, 'dongyi001', '建议', '希望增加更多药用植物介绍', '平台内容很丰富，但希望能增加更多侗族地区特有的药用植物介绍，比如一些民间常用的草药，这样能更好地传承侗族医药文化。', 'dongyi001@example.com', 'resolved', '感谢您的建议！我们正在整理更多侗族特有药用植物的资料，预计下月会新增20种植物介绍，敬请期待。', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (2, 3, 'herb_fan', '问题', '关于药浴疗法的使用疑问', '请问药浴疗法对孕妇是否安全？我妻子怀孕3个月，想使用药浴缓解疲劳，但不确定是否安全。', 'herb_fan@example.com', 'resolved', '孕妇使用药浴需谨慎，建议在专业医师指导下进行。部分药材可能不适合孕妇使用，建议先咨询当地侗医或中医师。', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (3, 4, 'culture_lover', '建议', '建议增加视频教程', '平台内容很专业，但建议增加一些视频教程，比如药材识别、炮制方法、疗法操作等，这样学习起来更直观。', 'culture_lover@example.com', 'resolved', '1', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (4, 5, 'test', '问题', '测验题目难度设置', '测验题目难度设置很合理，但希望能增加更多高难度题目，满足专业人士的学习需求。', 'test@example.com', 'pending', NULL, '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (5, NULL, '游客', '建议', '平台界面优化建议', '建议优化移动端显示效果，在手机上浏览时部分图片显示不完整，希望能改进。', 'visitor@example.com', 'resolved', '感谢您的反馈！我们已优化移动端显示效果，修复了图片显示问题，欢迎再次访问体验。', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (6, 2, 'dongyi001', '问题', '关于药材图片版权', '请问平台上的药材图片来源是哪里？是否可以用于学术研究？需要标注出处吗？', 'dongyi001@example.com', 'pending', NULL, '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (7, 3, 'herb_fan', '建议', '增加药材购买渠道信息', '希望能增加药材的购买渠道信息，方便用户购买正宗的侗族药材。', 'herb_fan@example.com', 'pending', NULL, '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (8, 4, 'culture_lover', '其他', '传承人联系方式', '希望能提供传承人的联系方式或预约咨询渠道，方便向传承人请教问题。', 'culture_lover@example.com', 'resolved', '感谢您的关注！出于隐私保护考虑，我们暂不公开传承人联系方式。如有需要，可通过平台留言，我们会代为转达。', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (9, NULL, '游客', '问题', '注册账号问题', '注册时提示用户名已存在，但更换多个用户名都提示相同错误，请问如何解决？', 'newuser@example.com', 'resolved', '您遇到的问题可能是系统缓存导致，请尝试清除浏览器缓存或更换浏览器重新注册。如仍有问题，请联系管理员。', '2026-03-04 04:47:10', '2026-04-29 16:54:30');
INSERT INTO `feedback` VALUES (10, 5, 'test', '建议', '增加收藏夹分类功能', '建议增加收藏夹分类功能，方便用户按类别管理收藏的药材、知识等内容。', 'test@example.com', 'pending', NULL, '2026-03-04 04:47:10', '2026-04-29 16:54:30');
