INSERT INTO `inheritors` VALUES (1, '谭锦宁', '自治区级', '谭锦宁，侗族，出生于广西三江侗族自治县。2002年创立谭氏侗族医药传承工作室，2015年被认定为侗族医药代表性传承人，2016年获自治区级非物质文化遗产保护性示范户。长期从事侗族医药临床与传承工作，擅长将传统侗药与现代养生结合。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"优秀\"等次。', '侗族医药、骨伤治疗、蛇伤救治、药浴疗法', 30, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor1/800/600\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor1b/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]', '[\"成立谭氏侗族医药传承工作室\",\"创办侗药养生体验基地\",\"治疗骨伤蛇伤患者数千例\",\"培养侗医药传承人\"]', '[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估优秀）\",\"侗族医药保护性示范户\",\"三江侗族自治县非遗传承基地负责人\"]', '2026-03-08 01:14:22', NULL, 32, 2, 95, '[{\"id\":1773664704366,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682001,\"time\":\"2026-03-08\",\"content\":\"创建传承人：谭锦宁\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (2, '龙宗花', '自治区级', '龙宗花，侗族，广西三江侗族自治县人。出身侗医世家，专注于侗族医药特别是妇科及养生疗法的传承，是侗族医药自治区级代表性传承人。长期从事侗族妇科调理与养生保健工作，将传统侗医理论与现代临床实践相结合。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"合格\"等次。', '侗族医药、妇科调理、养生保健、药浴', 32, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor2/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]', '[\"侗族妇科调理传承\",\"养生保健疗法推广\",\"培养侗医药传承人\"]', '[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估合格）\",\"侗族医药传承人\",\"三江侗族自治县侗医药传承基地成员\"]', '2026-03-08 01:14:22', NULL, 2, 1, 88, '[{\"id\": 1773145682002, \"time\": \"2026-03-08\", \"content\": \"创建传承人：龙宗花\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (3, '吴伟文', '自治区级', '吴伟文，侗族，广西三江侗族自治县人。侗族医药自治区级代表性传承人，长期从事侗族医药临床与传承工作，擅长侗药配方与药浴疗法。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"合格\"等次。', '侗族医药、草药配方、药浴疗法', 28, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor3/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]', '[\"侗药配方传承\",\"药浴疗法推广\",\"培养侗医药传承人\"]', '[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估合格）\",\"侗族医药传承人\"]', '2026-03-08 01:14:22', NULL, 35, 1, 82, '[{\"id\": 1773145682003, \"time\": \"2026-03-08\", \"content\": \"创建传承人：吴伟文\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (4, '韦丽祥', '市级', '韦丽祥，侗族，广西三江侗族自治县人。明朝《谭氏医药秘籍》第10代传承人，夜郎侗医药研究传承中心法人代表。柳州市第三批非物质文化遗产项目代表性传承人，擅长侗族医药、骨伤治疗及疑难杂症诊治，精通传统接骨术。', '侗族医药、骨伤治疗、疑难杂症、传统接骨', 35, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor4/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"}]', '[\"传承明朝《谭氏医药秘籍》\",\"创办夜郎侗医药研究传承中心\",\"传统接骨术治疗骨伤患者\",\"培养侗医药传承人\"]', '[\"柳州市第三批非物质文化遗产项目代表性传承人\",\"明朝《谭氏医药秘籍》第10代传承人\",\"夜郎侗医药研究传承中心法人\"]', '2026-03-08 01:14:22', NULL, 2, 1, 90, '[{\"id\": 1773145682004, \"time\": \"2026-03-08\", \"content\": \"创建传承人：韦丽祥\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (5, '吴新菊', '县级', '吴新菊，侗族，广西三江侗族自治县人。侗族鼻炎疗法传承人，三江侗族自治县第七批县级非物质文化遗产项目代表性传承人，柳州市第七批市级非物质文化遗产代表性传承人推荐人选。专注于侗族鼻炎疗法的传承与发展，擅长鼻腔给药、侗药熏蒸等特色疗法。', '侗族医药、鼻炎疗法、鼻腔给药、侗药熏蒸', 15, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor5/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/41efbfddfa3e493195ef3c233ffd63db.pdf\",\"name\":\"三政办发〔2020〕111号+三江侗族自治县人民政府办公室关于公布第五批县级非物质文化遗产项目代表传承人名单的通知.pdf\",\"size\":498424,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/32e975883ca542de8160e43ac0e44423.pdf\",\"name\":\"三江侗族自治县人民政府办公室关于公布 第五批县级非物质文化遗产项目 代表传承人名单的通知.pdf\",\"size\":504340,\"type\":\"pdf\"}]', '[\"侗族鼻炎疗法传承\",\"鼻腔给药特色疗法\",\"侗药熏蒸治疗鼻炎\"]', '[\"三江侗族自治县第七批县级非物质文化遗产项目代表性传承人\",\"柳州市第七批市级非物质文化遗产代表性传承人推荐人选\",\"侗族鼻炎疗法传承人\"]', '2026-03-08 01:14:22', NULL, 6, 0, 75, '[{\"id\":1773666853161,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682005,\"time\":\"2026-03-08\",\"content\":\"创建传承人：吴新菊\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (6, '吴雄娟', '县级', '吴雄娟，侗族，广西三江侗族自治县人。三江侗族自治县第五批县级非物质文化遗产项目代表性传承人，专注于侗族医药特别是草药配方与妇科调理的传承。', '侗族医药、草药配方、妇科调理、药浴疗法', 12, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor6/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/eb60f9e96baf4475a30e5fea09a00571.pdf\",\"name\":\"关于第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体拟推荐名单的公示.pdf\",\"size\":619932,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/4e8a3c07202045cd822f527fd308203e.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示第七批市级非物质文化遗产项目代表性传承人推荐名单的公告.pdf\",\"size\":1084248,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/3898e48bf8de4fb9ac812f881154376d.pdf\",\"name\":\"三江侗族自治县文化体育广电和旅游局关于公布第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体名单的通知.pdf\",\"size\":641964,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/24dd2db8e50b4172ba2a3c1b034174c1.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示第九批市级非物质文化遗产代表性项目名录推荐项目名单的公告.pdf\",\"size\":802515,\"type\":\"pdf\"}]', '[\"侗药配方传承\",\"妇科调理疗法\",\"药浴疗法推广\"]', '[\"三江侗族自治县第五批县级非物质文化遗产项目代表性传承人\",\"侗族医药传承人\"]', '2026-03-08 01:14:22', NULL, 2, 0, 68, '[{\"id\":1773667081521,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682006,\"time\":\"2026-03-08\",\"content\":\"创建传承人：吴雄娟\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (7, '韦海生', '县级', '韦海生，侗族，广西三江侗族自治县人。侗药浸泡药浴疗法传承人，三江侗族自治县第七批县级非物质文化遗产项目代表性传承人。专注于侗药浸泡药浴疗法的传承与发展，擅长风湿调理、皮肤病治疗等。', '侗药浸泡药浴疗法、风湿调理、皮肤病治疗', 18, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor7/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/eb60f9e96baf4475a30e5fea09a00571.pdf\",\"name\":\"关于第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体拟推荐名单的公示.pdf\",\"size\":619932,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/3898e48bf8de4fb9ac812f881154376d.pdf\",\"name\":\"三江侗族自治县文化体育广电和旅游局关于公布第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体名单的通知.pdf\",\"size\":641964,\"type\":\"pdf\"}]', '[\"侗药浸泡药浴疗法传承\",\"风湿调理治疗\",\"皮肤病侗药治疗\"]', '[\"三江侗族自治县第七批县级非物质文化遗产项目代表性传承人\",\"侗药浸泡药浴疗法传承人\"]', '2026-03-08 01:14:22', NULL, 0, 0, 72, '[{\"id\": 1773145682007, \"time\": \"2026-03-08\", \"content\": \"创建传承人：韦海生\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (8, '欧良春', '市级', '欧良春，侗族，湖南省怀化市人。怀化市第六批市级非物质文化遗产代表性传承人推荐人选，长期从事侗族医药临床工作，擅长中风瘫痪、颈腰椎病治疗及蛇伤解毒。', '侗族医药、中风瘫痪、颈腰椎病、蛇伤解毒', 25, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor8/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/68e75b5e7c5541018987cb7a0614a82d.pdf\",\"name\":\"关于第六批市级非物质文化遗产代表性项目代表性传承人推荐名单的公示.pdf\",\"size\":525239,\"type\":\"pdf\"}]', '[\"中风瘫痪侗医治疗\",\"颈腰椎病特色疗法\",\"蛇伤解毒救治\"]', '[\"怀化市第六批市级非物质文化遗产代表性传承人推荐人选\",\"侗族医药传承人\"]', '2026-03-08 01:14:22', NULL, 2, 1, 78, '[{\"id\":1773667360786,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682008,\"time\":\"2026-03-08\",\"content\":\"创建传承人：欧良春\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (9, '吴东克', '市级', '吴东克，侗族，1986年出生，贵州省黔东南苗族侗族自治州人。侗医药第五代传承人，贵州侗医坊民族医药研究所所长。怀化市第六批市级非物质文化遗产代表性传承人推荐人选，专注于侗药识别、临床配方及侗药研发工作。', '侗族医药、侗药识别、临床配方、侗药研发', 15, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor9/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/68e75b5e7c5541018987cb7a0614a82d.pdf\",\"name\":\"关于第六批市级非物质文化遗产代表性项目代表性传承人推荐名单的公示.pdf\",\"size\":525239,\"type\":\"pdf\"}]', '[\"侗药识别与分类研究\",\"临床配方优化\",\"侗药新产品研发\",\"创办侗医坊民族医药研究所\"]', '[\"怀化市第六批市级非物质文化遗产代表性传承人推荐人选\",\"侗医药第五代传承人\",\"贵州侗医坊民族医药研究所所长\"]', '2026-03-08 01:14:22', NULL, 7, 1, 85, '[{\"id\": 1773145682009, \"time\": \"2026-03-08\", \"content\": \"创建传承人：吴东克\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (10, '唐光先', '市级', '唐光先，侗族，湖南省怀化市人。侗族唐氏武医推拿术传承人，怀化市第七批市级非物质文化遗产代表性传承人推荐人选。省级非物质文化遗产项目\"侗族唐氏武医推拿术\"代表性传承人，擅长推拿疗法与康养保健。', '侗族唐氏武医推拿术、推拿疗法、康养保健', 30, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor10/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/92d1d5ce05424ebea288243dedea004f.pdf\",\"name\":\"怀化市第七批市级非物质文化遗产代表性传承人推荐名单公示.pdf\",\"size\":450116,\"type\":\"pdf\"}]', '[\"侗族唐氏武医推拿术传承\",\"推拿疗法治疗颈腰椎病\",\"康养保健技术推广\"]', '[\"怀化市第七批市级非物质文化遗产代表性传承人推荐人选\",\"省级非物质文化遗产项目代表性传承人\",\"侗族唐氏武医推拿术传承人\"]', '2026-03-08 01:14:22', NULL, 5, 2, 92, '[{\"id\":1773667421865,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682010,\"time\":\"2026-03-08\",\"content\":\"创建传承人：唐光先\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (11, '李娟', '市级', '李娟，侗族，湖南省怀化市人。侗族唐氏武医推拿术传承人，怀化市第八批市级非物质文化遗产代表性传承人推荐人选。师从唐光先学习侗族唐氏武医推拿术，专注于推拿疗法的传承与发展。', '侗族唐氏武医推拿术、推拿疗法', 10, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor11/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/54ba8261fafe421bbc98288e3665b2ac.pdf\",\"name\":\"怀化市第八批市级非物质文化遗产代表性传承人推荐名单公示.pdf\",\"size\":472852,\"type\":\"pdf\"}]', '[\"侗族唐氏武医推拿术学习传承\",\"推拿疗法临床实践\"]', '[\"怀化市第八批市级非物质文化遗产代表性传承人推荐人选\",\"侗族唐氏武医推拿术传承人\"]', '2026-03-08 01:14:22', NULL, 1, 0, 70, '[{\"id\":1773667438479,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682011,\"time\":\"2026-03-08\",\"content\":\"创建传承人：李娟\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (12, '粟万成', '市级', '粟万成，侗族，湖南省怀化市人。侗医火针疗法第六代传承人，怀化市第八批市级非物质文化遗产代表性传承人推荐人选。主持制定《侗医火针技术操作规范》国家标准，致力于民族医药标准化建设。', '侗医火针疗法、针灸、民族医药标准化', 20, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor12/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/54ba8261fafe421bbc98288e3665b2ac.pdf\",\"name\":\"怀化市第八批市级非物质文化遗产代表性传承人推荐名单公示.pdf\",\"size\":472852,\"type\":\"pdf\"}]', '[\"侗医火针疗法传承\",\"主持制定《侗医火针技术操作规范》国家标准\",\"民族医药标准化建设\",\"培养火针疗法传承人\"]', '[\"怀化市第八批市级非物质文化遗产代表性传承人推荐人选\",\"侗医火针疗法第六代传承人\",\"国家标准制定者\"]', '2026-03-08 01:14:22', NULL, 8, 3, 98, '[{\"id\": 1773145682012, \"time\": \"2026-03-08\", \"content\": \"创建传承人：粟万成\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (13, '明更华', '市级', '明更华，侗族，1967年出生，湖南省怀化市人。明太公侗家红药制作技艺第五代传承人，怀化市第八批市级非物质文化遗产代表性传承人推荐人选。专注于侗药制剂工艺的传承与创新。', '明太公侗家红药制作技艺、侗药制剂', 25, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor13/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"documents/pdf/inheritors/54ba8261fafe421bbc98288e3665b2ac.pdf\",\"name\":\"怀化市第八批市级非物质文化遗产代表性传承人推荐名单公示.pdf\",\"size\":472852,\"type\":\"pdf\"}]', '[\"明太公侗家红药制作技艺传承\",\"侗药制剂工艺创新\",\"培养侗药制剂传承人\"]', '[\"怀化市第八批市级非物质文化遗产代表性传承人推荐人选\",\"明太公侗家红药制作技艺第五代传承人\"]', '2026-03-08 01:14:22', NULL, 2, 1, 76, '[{\"id\": 1773145682013, \"time\": \"2026-03-08\", \"content\": \"创建传承人：明更华\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (14, '姚绍炎', '县级', '姚绍炎，侗族，1937年出生，湖南省新晃侗族自治县人。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人，2024年度考核合格。专注于伤科骨折治疗，擅长侗族正骨术与草药外敷。', '伤科骨折、侗族正骨、草药外敷', 50, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor14/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/cb3a16548aec4476a287075eae7586ce.pdf\",\"name\":\"2024年度新晃县级非遗代表性传承人考核合格人员公示.pdf\",\"size\":1467813,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"}]', '[\"侗族正骨术传承\",\"草药外敷治疗骨折\",\"治疗骨折患者数千例\"]', '[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"2024年度考核合格\",\"伤科骨折传承人\"]', '2026-03-08 01:14:22', NULL, 4, 1, 80, '[{\"id\":1773667633651,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682014,\"time\":\"2026-03-08\",\"content\":\"创建传承人：姚绍炎\",\"operator\":\"系统\"}]');
INSERT INTO `inheritors` VALUES (15, '杨清阳', '县级', '杨清阳，侗族，1939年出生，湖南省新晃侗族自治县人。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人，2024年度考核合格。专注于侗族草药识别与临床治疗，擅长药浴疗法。', '侗族草药识别、临床治疗、药浴', 55, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor15/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/cb3a16548aec4476a287075eae7586ce.pdf\",\"name\":\"2024年度新晃县级非遗代表性传承人考核合格人员公示.pdf\",\"size\":1467813,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"}]', '[\"侗族草药识别传承\",\"临床治疗实践\",\"药浴疗法推广\"]', '[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"2024年度考核合格\",\"新晃侗医药传承人\"]', '2026-03-08 01:14:22', NULL, 3, 2, 88, '[{\"id\": 1773145682015, \"time\": \"2026-03-08\", \"content\": \"创建传承人：杨清阳\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (16, '吴谋焕', '县级', '吴谋焕，侗族，湖南省新晃侗族自治县人。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人，2024年度考核合格。专注于侗族医药特别是跌打损伤与药浴疗法的传承。', '侗族医药、跌打损伤、药浴疗法', 20, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor16/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/cb3a16548aec4476a287075eae7586ce.pdf\",\"name\":\"2024年度新晃县级非遗代表性传承人考核合格人员公示.pdf\",\"size\":1467813,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"}]', '[\"跌打损伤侗医治疗\",\"药浴疗法传承\"]', '[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"2024年度考核合格\",\"新晃侗医药传承人\"]', '2026-03-08 01:14:22', NULL, 5, 0, 65, '[{\"id\": 1773145682016, \"time\": \"2026-03-08\", \"content\": \"创建传承人：吴谋焕\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (17, '张祥坤', '县级', '张祥坤，侗族，1987年出生，湖南省新晃侗族自治县人。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人（增补），年轻一代侗医药传承人代表。专注于侗族医药特别是草药配方的传承与发展。', '侗族医药、草药配方', 8, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor17/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/cb3a16548aec4476a287075eae7586ce.pdf\",\"name\":\"2024年度新晃县级非遗代表性传承人考核合格人员公示.pdf\",\"size\":1467813,\"type\":\"pdf\"}]', '[\"侗药配方学习传承\",\"年轻一代侗医药传承\"]', '[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人（增补）\",\"年轻一代侗医药传承人\"]', '2026-03-08 01:14:22', NULL, 3, 0, 58, '[{\"id\": 1773145682017, \"time\": \"2026-03-08\", \"content\": \"创建传承人：张祥坤\", \"operator\": \"系统\"}]');
INSERT INTO `inheritors` VALUES (18, '钟泽国', '县级', '钟泽国，侗族，湖南省新晃侗族自治县人（已故）。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人，生前专注于侗族医药特别是跌打损伤与药浴疗法的传承工作。', '侗族医药、跌打损伤、药浴疗法', 35, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor18/800/600\", \"size\": 0, \"type\": \"image\"}]', '[{\"path\":\"/documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/bb05e2d59dc348bda97644cd52560390.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人增补人员公示.pdf\",\"size\":823864,\"type\":\"pdf\"}]', '[\"跌打损伤侗医治疗\",\"药浴疗法传承\",\"培养侗医药传承人\"]', '[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"侗医药传承人（已故）\"]', '2026-03-08 01:14:22', NULL, 5, 2, 70, '[{\"id\":1773668017493,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682018,\"time\":\"2026-03-08\",\"content\":\"创建传承人：钟泽国\",\"operator\":\"系统\"}]');
INSERT INTO `knowledge` VALUES (1, '侗族药浴养生方', '药方', '药浴疗法', '风湿骨痛', '全草类', '侗族药浴是侗族传统疗法的重要组成部分，通过药物煎汤浸泡全身或局部，达到防治疾病的目的。药浴能促进血液循环，祛风除湿，舒筋活络，是侗族人民长期与疾病斗争中积累的宝贵经验。', '透骨草30g、艾叶30g、钩藤20g、血藤20g、杜仲15g、金银花15g', '将药物加水煎煮30分钟，倒入浴桶中，加水调至适宜温度（40-45℃），浸泡全身20-30分钟，每周2-3次。', '[\"准备药材：透骨草、艾叶、钩藤、血藤、杜仲、金银花\",\"加水煎煮30分钟\",\"将药液倒入浴桶\",\"调节水温至40-45℃\",\"全身浸泡20-30分钟\",\"浴后擦干保暖\"]', '[]', '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', '[]', '[2,13,1,7,8,12]', '[{\"id\":1,\"time\":\"2024-03-10\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 156, '2026-03-04 04:47:10', NULL, 12, 1);
INSERT INTO `knowledge` VALUES (2, '侗医艾灸疗法', '疗法', '艾灸疗法', '妇科疾病', '叶类', '艾灸疗法是侗族传统外治法之一，以艾叶为主要材料，点燃后熏灼穴位，通过温热刺激达到治病保健的目的。侗族艾灸对妇科疾病、风湿疼痛有显著疗效。', '艾叶适量', '将艾叶制成艾条或艾柱，点燃后对准穴位熏灼，距离皮肤2-3cm，以患者感觉温热舒适为度，每次15-20分钟。', '[\"选取穴位：关元、气海、三阴交等\",\"点燃艾条\",\"对准穴位熏灼\",\"距离皮肤2-3cm\",\"每次15-20分钟\",\"注意防止烫伤\"]', NULL, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[13]', '[{\"id\":1,\"time\":\"2024-03-10\",\"content\":\"创建知识条目\",\"operator\":\"系统\"},{\"id\":2,\"time\":\"2024-03-11\",\"content\":\"更新内容描述\",\"operator\":\"管理员\"}]', 142, '2026-03-04 04:47:10', NULL, 47, 2);
INSERT INTO `knowledge` VALUES (3, '侗族跌打损伤方', '药方', '推拿疗法', '跌打损伤', '全草类', '侗族民间治疗跌打损伤的经验方，具有活血化瘀、消肿止痛的功效。此方在侗族地区流传已久，对各种跌打损伤有良好疗效。', '透骨草30g、八角莲15g、七叶一枝花15g、白及15g、血藤20g', '将药物捣烂，加适量白酒调匀，外敷患处，每日换药1-2次。也可煎水内服，每日一剂，分两次服用。', '[\"准备药材：透骨草、八角莲、七叶一枝花、白及、血藤\",\"将药物捣烂\",\"加适量白酒调匀\",\"外敷患处\",\"每日换药1-2次\",\"严重者可配合内服\"]', NULL, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[2,4,5,10,7]', '[{\"id\": 1773144251003, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族跌打损伤方\", \"operator\": \"系统\"}]', 138, '2026-03-04 04:47:10', NULL, 11, 2);
INSERT INTO `knowledge` VALUES (4, '侗医蛇伤急救方', '药方', '外治疗法', '毒蛇咬伤', '根茎类', '侗族地区山林茂密，蛇虫众多，侗医积累了丰富的蛇伤治疗经验。八角莲是治疗蛇伤的要药，配合其他药物使用，效果显著。', '八角莲30g、七叶一枝花20g、半夏10g、车前草30g', '将八角莲、七叶一枝花捣烂外敷伤口周围；同时用车前草、半夏煎水内服，每日一剂。严重者需及时送医。', '[\"立即绑扎伤口近心端\",\"清洗伤口\",\"八角莲、七叶一枝花捣烂外敷\",\"车前草、半夏煎水内服\",\"密切观察病情\",\"严重者及时送医\"]', NULL, '[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[4,5,17,18]', '[{\"id\": 1773144251004, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医蛇伤急救方\", \"operator\": \"系统\"}]', 167, '2026-03-04 04:47:10', NULL, 5, 1);
INSERT INTO `knowledge` VALUES (5, '侗族小儿惊风方', '药方', '内服疗法', '儿科疾病', '藤本类', '小儿惊风是侗族地区常见儿科急症，侗医常用钩藤等药物治疗，效果显著。此方在侗族民间流传已久，是侗医儿科的代表性方剂。', '钩藤15g、天麻10g、金银花10g、茯苓10g', '将药物加水煎煮，取汁分2-3次服用，每日一剂。症状严重者需及时就医。', '[\"准备药材：钩藤、天麻、金银花、茯苓\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"注意观察患儿情况\",\"严重者及时就医\"]', NULL, NULL, NULL, '[1,11,12,15]', '[{\"id\": 1773144251005, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿惊风方\", \"operator\": \"系统\"}]', 125, '2026-03-04 04:47:10', NULL, 7, 1);
INSERT INTO `knowledge` VALUES (6, '侗医风湿痹痛方', '药方', '药浴疗法', '风湿骨痛', '全草类', '风湿痹痛是侗族地区常见病，与当地潮湿气候有关。侗医常用祛风除湿的药物治疗，配合药浴效果更佳。', '九节茶30g、血藤30g、杜仲20g、钩藤20g、透骨草30g', '药物加水煎煮，取汁分两次内服，每日一剂。药渣可加水煎煮后用于药浴。', '[\"准备药材：九节茶、血藤、杜仲、钩藤、透骨草\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"用于药浴\",\"坚持治疗2-4周\"]', NULL, NULL, NULL, '[3,7,8,1,2]', '[{\"id\": 1773144251006, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医风湿痹痛方\", \"operator\": \"系统\"}]', 148, '2026-03-04 04:47:10', NULL, 2, 0);
INSERT INTO `knowledge` VALUES (7, '侗族产后调理方', '药方', '内服疗法', '妇科疾病', '藤本类', '侗族妇女产后常用中药调理身体，促进恢复。此方具有补血活血、温经散寒的功效，是侗族产后调理的经典方。', '血藤30g、艾叶20g、杜仲20g、何首乌15g、黄精15g', '将药物加水煎煮，取汁分两次服用，每日一剂，连服7-14天。', '[\"准备药材：血藤、艾叶、杜仲、何首乌、黄精\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"连服7-14天\",\"注意休息保暖\"]', NULL, NULL, NULL, '[7,13,8,16,9]', '[{\"id\": 1773144251007, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族产后调理方\", \"operator\": \"系统\"}]', 132, '2026-03-04 04:47:10', NULL, 1, 1);
INSERT INTO `knowledge` VALUES (8, '侗医感冒发热方', '药方', '内服疗法', '感冒发热', '花类', '侗族民间治疗感冒发热的经验方，具有清热解毒、疏风解表的功效。此方对风热感冒效果尤佳。', '金银花30g、鱼腥草20g、车前草20g、艾叶10g', '将药物加水煎煮，取汁分2-3次服用，每日一剂。发热严重者可每日两剂。', '[\"准备药材：金银花、鱼腥草、车前草、艾叶\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"多饮温水\",\"注意休息\"]', NULL, NULL, NULL, '[12,19,18,13]', '[{\"id\": 1773144251008, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医感冒发热方\", \"operator\": \"系统\"}]', 145, '2026-03-04 04:47:10', NULL, 2, 1);
INSERT INTO `knowledge` VALUES (9, '侗族胃寒呕吐方', '药方', '内服疗法', '消化系统疾病', '果实类', '侗族地区气候潮湿，胃寒呕吐较为常见。侗医常用温中散寒的药物治疗，效果显著。', '吴茱萸10g、艾叶15g、茯苓15g、半夏10g', '将药物加水煎煮，取汁分两次服用，每日一剂。呕吐严重者可少量多次服用。', '[\"准备药材：吴茱萸、艾叶、茯苓、半夏\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"少量多次服用\",\"忌食生冷\"]', NULL, NULL, NULL, '[20,13,15,17]', '[{\"id\": 1773144251009, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族胃寒呕吐方\", \"operator\": \"系统\"}]', 118, '2026-03-04 04:47:10', NULL, 1, 1);
INSERT INTO `knowledge` VALUES (10, '侗医咳嗽痰多方', '药方', '内服疗法', '呼吸系统疾病', '根茎类', '侗族民间治疗咳嗽的经验方，对痰湿咳嗽效果尤佳。此方具有燥湿化痰、止咳平喘的功效。', '半夏10g、茯苓15g、鱼腥草20g、金银花15g', '将药物加水煎煮，取汁分两次服用，每日一剂。咳嗽严重者可每日两剂。', '[\"准备药材：半夏、茯苓、鱼腥草、金银花\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食辛辣油腻\",\"注意保暖\"]', NULL, NULL, NULL, '[17,15,19,12]', '[{\"id\": 1773144251010, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医咳嗽痰多方\", \"operator\": \"系统\"}]', 126, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `knowledge` VALUES (11, '侗族糖尿病调理方', '药方', '内服疗法', '糖尿病', '全草类', '侗医称糖尿病为\"消渴症\"，常用滋阴清热、生津止渴的药物治疗。石斛是治疗消渴症的要药。', '石斛15g、黄精20g、茯苓15g、何首乌15g', '将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用，配合饮食调理。', '[\"准备药材：石斛、黄精、茯苓、何首乌\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"配合饮食调理\"]', NULL, NULL, NULL, '[14,9,15,16]', '[{\"id\": 1773144251011, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族糖尿病调理方\", \"operator\": \"系统\"}]', 108, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `knowledge` VALUES (12, '侗医失眠多梦方', '药方', '内服疗法', '神经系统疾病', '菌类', '侗族民间治疗失眠的经验方，具有养心安神、滋阴清热的功效。此方对阴虚火旺型失眠效果尤佳。', '茯苓20g、何首乌15g、天麻10g、黄精15g', '将药物加水煎煮，取汁于睡前服用，每日一剂。', '[\"准备药材：茯苓、何首乌、天麻、黄精\",\"加水煎煮30分钟\",\"取汁于睡前服用\",\"每日一剂\",\"保持心情舒畅\",\"睡前避免剧烈活动\"]', NULL, NULL, NULL, '[15,16,11,9]', '[{\"id\": 1773144251012, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医失眠多梦方\", \"operator\": \"系统\"}]', 112, '2026-03-04 04:47:10', NULL, 2, 0);
INSERT INTO `knowledge` VALUES (13, '侗族腰膝酸软方', '药方', '内服疗法', '骨科疾病', '皮类', '侗族民间治疗腰膝酸软的经验方，具有补肝肾、强筋骨的功效。杜仲是补肾强腰的要药。', '杜仲30g、血藤20g、何首乌15g、黄精15g', '将药物加水煎煮，取汁分两次服用，每日一剂。也可泡酒服用。', '[\"准备药材：杜仲、血藤、何首乌、黄精\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可泡酒服用\",\"坚持服用2-4周\"]', NULL, NULL, NULL, '[8,7,16,9]', '[{\"id\": 1773144251013, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族腰膝酸软方\", \"operator\": \"系统\"}]', 134, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (14, '侗医皮肤瘙痒方', '药方', '外治疗法', '皮肤病', '花类', '侗族民间治疗皮肤瘙痒的经验方，具有祛风止痒、清热解毒的功效。可内服外洗配合使用。', '金银花30g、艾叶30g、车前草30g、三颗针20g', '将药物加水煎煮，取汁分两次内服；药渣加水煎煮后外洗患处，每日一次。', '[\"准备药材：金银花、艾叶、车前草、三颗针\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"外洗患处\",\"每日一次\"]', NULL, NULL, NULL, '[12,13,18,6]', '[{\"id\": 1773144251014, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医皮肤瘙痒方\", \"operator\": \"系统\"}]', 98, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (15, '侗族拔罐疗法', '疗法', '拔罐疗法', '风湿骨痛', NULL, '拔罐疗法是侗族传统外治法之一，通过负压吸附皮肤，达到祛风除湿、活血化瘀的目的。侗族拔罐对风湿疼痛、跌打损伤有显著疗效。', NULL, '选用竹罐或玻璃罐，用火燃烧法或抽气法产生负压，吸附于患处或穴位，留罐10-15分钟。', '[\"患者取舒适体位\",\"选择拔罐部位\",\"清洁皮肤\",\"用火燃烧法产生负压\",\"吸附于患处\",\"留罐10-15分钟\"]', NULL, NULL, NULL, NULL, '[{\"id\": 1773144251015, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族拔罐疗法\", \"operator\": \"系统\"}]', 156, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (16, '侗医推拿疗法', '疗法', '推拿疗法', '跌打损伤', NULL, '推拿疗法是侗族传统外治法之一，通过手法作用于人体体表，达到舒筋活络、行气活血的目的。侗族推拿对跌打损伤、风湿疼痛有显著疗效。', NULL, '根据病情选择推、拿、按、摩、揉、捏等手法，每次治疗20-30分钟，每日或隔日一次。', '[\"患者取舒适体位\",\"暴露治疗部位\",\"医者双手涂抹介质\",\"运用推、拿、按、摩等手法\",\"重点治疗患处\",\"每次20-30分钟\"]', NULL, NULL, NULL, NULL, '[{\"id\": 1773144251016, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医推拿疗法\", \"operator\": \"系统\"}]', 143, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (17, '侗族熏蒸疗法', '疗法', '熏蒸疗法', '风湿骨痛', '叶类', '熏蒸疗法是侗族传统外治法之一，通过药物燃烧或煎煮产生的蒸汽熏蒸患处，达到祛风除湿、活血化瘀的目的。', '艾叶50g、透骨草50g、钩藤30g', '将药物加水煎煮，用蒸汽熏蒸患处，每次20-30分钟，每日一次。', '[\"准备药材：艾叶、透骨草、钩藤\",\"加水煎煮\",\"产生蒸汽\",\"熏蒸患处\",\"每次20-30分钟\",\"注意防止烫伤\"]', NULL, NULL, NULL, '[13,2,1]', '[{\"id\": 1773144251017, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族熏蒸疗法\", \"operator\": \"系统\"}]', 128, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (18, '侗医刮痧疗法', '疗法', '刮痧疗法', '感冒发热', NULL, '刮痧疗法是侗族传统外治法之一，通过刮拭皮肤达到活血化瘀、祛风解表的目的。侗族刮痧对感冒发热、中暑有显著疗效。', '刮痧油适量', '用刮痧板蘸取刮痧油，沿经络方向刮拭，以皮肤出现红色瘀点为度。', '[\"准备刮痧板和刮痧油\",\"患者取舒适体位\",\"暴露刮痧部位\",\"蘸取刮痧油\",\"沿经络方向刮拭\",\"以皮肤出现瘀点为度\"]', NULL, NULL, NULL, NULL, '[{\"id\": 1773144251018, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医刮痧疗法\", \"operator\": \"系统\"}]', 135, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (19, '侗族小儿推拿疗法', '疗法', '推拿疗法', '儿科疾病', NULL, '小儿推拿是侗族儿科常用疗法，通过特定手法作用于小儿特定穴位，达到治病保健的目的。对小儿消化不良、发热、咳嗽等有良好疗效。', NULL, '根据病情选择推、揉、捏、拿等手法，作用于小儿特定穴位，每次15-20分钟。', '[\"患儿取舒适体位\",\"医者双手清洁温暖\",\"选择适当手法\",\"作用于特定穴位\",\"力度轻柔\",\"每次15-20分钟\"]', NULL, NULL, NULL, NULL, '[{\"id\": 1773144251019, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿推拿疗法\", \"operator\": \"系统\"}]', 118, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (20, '侗医火疗疗法', '疗法', '火疗疗法', '风湿骨痛', '叶类', '火疗疗法是侗族传统外治法之一，通过药物燃烧产生的热量作用于患处，达到祛风除湿、温经散寒的目的。', '艾叶、透骨草、吴茱萸各适量', '将药物研末，用白酒调匀，铺于患处，点燃后快速扑灭，利用余热熏蒸患处。', '[\"准备药物：艾叶、透骨草、吴茱萸\",\"研末用白酒调匀\",\"铺于患处\",\"点燃后快速扑灭\",\"利用余热熏蒸\",\"注意防止烫伤\"]', NULL, NULL, NULL, '[13,2,20]', '[{\"id\": 1773144251020, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医火疗疗法\", \"operator\": \"系统\"}]', 98, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (21, '侗族黄疸病方', '药方', '内服疗法', '肝胆疾病', '根茎类', '侗医治疗黄疸的经验方，具有清热利湿、利胆退黄的功效。茵陈是治疗黄疸的要药，配伍其他药物效果更佳。', '茵陈30g、金钱草30g、虎杖20g、郁金15g', '将药物加水煎煮，取汁分两次服用，每日一剂。黄疸严重者可每日两剂。', '[\"准备药材：茵陈、金钱草、虎杖、郁金\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食油腻\",\"定期复查肝功能\"]', NULL, NULL, NULL, '[45,46,47,48]', '[{\"id\": 1773144251021, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族黄疸病方\", \"operator\": \"系统\"}]', 105, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (22, '侗医水肿方', '药方', '内服疗法', '水肿', '菌类', '侗族民间治疗水肿的经验方，具有利水渗湿、健脾益气的功效。茯苓、泽泻是利水消肿的要药。', '茯苓30g、泽泻20g、猪苓15g、薏苡仁30g', '将药物加水煎煮，取汁分两次服用，每日一剂。水肿严重者可每日两剂。', '[\"准备药材：茯苓、泽泻、猪苓、薏苡仁\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"限制盐分摄入\",\"定期监测体重\"]', NULL, NULL, NULL, '[15,33,34,32]', '[{\"id\": 1773144251022, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医水肿方\", \"operator\": \"系统\"}]', 92, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (23, '侗族便秘方', '药方', '内服疗法', '消化系统疾病', '根茎类', '侗族民间治疗便秘的经验方，具有润肠通便、清热泻下的功效。桃仁、何首乌是润肠通便的要药。', '桃仁15g、何首乌20g、火麻仁15g、当归10g', '将药物加水煎煮，取汁分两次服用，每日一剂。便秘严重者可每日两剂。', '[\"准备药材：桃仁、何首乌、火麻仁、当归\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"多饮水\",\"多食蔬菜水果\"]', NULL, NULL, NULL, '[58,16]', '[{\"id\": 1773144251023, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族便秘方\", \"operator\": \"系统\"}]', 88, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (24, '侗医头痛方', '药方', '内服疗法', '神经系统疾病', '根茎类', '侗族民间治疗头痛的经验方，具有平肝息风、通络止痛的功效。天麻、钩藤是治疗头痛的要药。', '天麻15g、钩藤20g、川芎10g、白芷10g', '将药物加水煎煮，取汁分两次服用，每日一剂。头痛严重者可每日两剂。', '[\"准备药材：天麻、钩藤、川芎、白芷\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"保持心情舒畅\",\"避免过度劳累\"]', NULL, NULL, NULL, '[11,1]', '[{\"id\": 1773144251024, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医头痛方\", \"operator\": \"系统\"}]', 95, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (25, '侗族痛经方', '药方', '内服疗法', '妇科疾病', '花类', '侗族妇女治疗痛经的经验方，具有活血化瘀、温经止痛的功效。益母草、红花是治疗痛经的要药。', '益母草30g、红花10g、艾叶15g、当归15g', '将药物加水煎煮，取汁分两次服用，每日一剂。于月经前3-5天开始服用。', '[\"准备药材：益母草、红花、艾叶、当归\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"月经前3-5天开始服用\",\"注意保暖\"]', NULL, NULL, NULL, '[59,57]', '[{\"id\": 1773144251025, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族痛经方\", \"operator\": \"系统\"}]', 112, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (26, '侗医跌打损伤内服方', '药方', '内服疗法', '跌打损伤', '根茎类', '侗族民间治疗跌打损伤的内服方，具有活血化瘀、消肿止痛的功效。乳香、没药是活血止痛的要药。', '乳香10g、没药10g、血藤20g、延胡索15g', '将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。', '[\"准备药材：乳香、没药、血藤、延胡索\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"忌食辛辣刺激\"]', NULL, NULL, NULL, '[53,54,7,52]', '[{\"id\": 1773144251026, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医跌打损伤内服方\", \"operator\": \"系统\"}]', 108, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (27, '侗族小儿疳积方', '药方', '内服疗法', '儿科疾病', '根茎类', '侗族民间治疗小儿疳积的经验方，具有健脾消积、和胃化滞的功效。白术、茯苓是健脾消积的要药。', '白术15g、茯苓15g、陈皮10g、山楂15g', '将药物加水煎煮，取汁分2-3次服用，每日一剂。也可研末冲服。', '[\"准备药材：白术、茯苓、陈皮、山楂\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"也可研末冲服\",\"调整饮食结构\"]', NULL, NULL, NULL, '[21,15,23]', '[{\"id\": 1773144251027, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿疳积方\", \"operator\": \"系统\"}]', 86, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (28, '侗医阳痿方', '药方', '内服疗法', '男科疾病', '皮类', '侗族民间治疗阳痿的经验方，具有补肾壮阳、益精填髓的功效。杜仲、肉桂是补肾壮阳的要药。', '杜仲30g、肉桂10g、枸杞子20g、淫羊藿15g', '将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。', '[\"准备药材：杜仲、肉桂、枸杞子、淫羊藿\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"保持心情舒畅\"]', NULL, NULL, NULL, '[8,42]', '[{\"id\": 1773144251028, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医阳痿方\", \"operator\": \"系统\"}]', 78, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (29, '侗族月经不调方', '药方', '内服疗法', '妇科疾病', '花类', '侗族妇女治疗月经不调的经验方，具有活血调经、补气养血的功效。益母草、鸡血藤是调经的要药。', '益母草30g、鸡血藤30g、当归15g、白芍15g', '将药物加水煎煮，取汁分两次服用，每日一剂。于月经干净后开始服用。', '[\"准备药材：益母草、鸡血藤、当归、白芍\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"月经干净后开始服用\",\"连服7-14天\"]', NULL, NULL, NULL, '[59,61]', '[{\"id\": 1773144251029, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族月经不调方\", \"operator\": \"系统\"}]', 98, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (30, '侗医胃痛方', '药方', '内服疗法', '消化系统疾病', '果实类', '侗族民间治疗胃痛的经验方，具有温中散寒、理气止痛的功效。吴茱萸、高良姜是温胃止痛的要药。', '吴茱萸10g、高良姜15g、陈皮10g、木香10g', '将药物加水煎煮，取汁分两次服用，每日一剂。胃痛严重者可每日两剂。', '[\"准备药材：吴茱萸、高良姜、陈皮、木香\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食生冷油腻\",\"少食多餐\"]', NULL, NULL, NULL, '[20,44,23,26]', '[{\"id\": 1773144251030, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医胃痛方\", \"operator\": \"系统\"}]', 92, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (31, '侗族关节炎方', '药方', '药浴疗法', '风湿骨痛', '全草类', '侗族民间治疗关节炎的经验方，具有祛风除湿、活血通络的功效。配合药浴使用效果更佳。', '透骨草50g、九节茶50g、血藤30g、杜仲30g', '将药物加水煎煮30分钟，取汁用于药浴，浸泡患处20-30分钟，每日一次。', '[\"准备药材：透骨草、九节茶、血藤、杜仲\",\"加水煎煮30分钟\",\"取汁用于药浴\",\"浸泡患处20-30分钟\",\"每日一次\",\"坚持治疗2-4周\"]', NULL, NULL, NULL, '[2,3,7,8]', '[{\"id\": 1773144251031, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族关节炎方\", \"operator\": \"系统\"}]', 115, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (32, '侗医湿疹方', '药方', '外治疗法', '皮肤病', '花类', '侗族民间治疗湿疹的经验方，具有清热解毒、祛风止痒的功效。可内服外洗配合使用。', '金银花30g、地肤子30g、白鲜皮20g、苦参15g', '将药物加水煎煮，取汁分两次内服；药渣加水煎煮后外洗患处，每日一次。', '[\"准备药材：金银花、地肤子、白鲜皮、苦参\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"外洗患处\",\"每日一次\"]', NULL, NULL, NULL, '[12,41]', '[{\"id\": 1773144251032, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医湿疹方\", \"operator\": \"系统\"}]', 88, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (33, '侗族贫血方', '药方', '内服疗法', '血液系统疾病', '根茎类', '侗族民间治疗贫血的经验方，具有补气养血、健脾益气的功效。黄精、何首乌是补血的要药。', '黄精30g、何首乌20g、当归15g、黄芪20g', '将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用。', '[\"准备药材：黄精、何首乌、当归、黄芪\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"配合饮食调理\"]', NULL, NULL, NULL, '[9,16]', '[{\"id\": 1773144251033, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族贫血方\", \"operator\": \"系统\"}]', 82, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (34, '侗医高血压方', '药方', '内服疗法', '心血管疾病', '藤本类', '侗族民间治疗高血压的经验方，具有平肝潜阳、清热降压的功效。钩藤、天麻是降压的要药。', '钩藤30g、天麻15g、菊花15g、夏枯草20g', '将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用，定期监测血压。', '[\"准备药材：钩藤、天麻、菊花、夏枯草\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"定期监测血压\"]', NULL, NULL, NULL, '[1,11]', '[{\"id\": 1773144251034, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医高血压方\", \"operator\": \"系统\"}]', 96, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (35, '侗族小儿发热方', '药方', '内服疗法', '儿科疾病', '花类', '侗族民间治疗小儿发热的经验方，具有清热解毒、疏风解表的功效。金银花、鱼腥草是清热解毒的要药。', '金银花15g、鱼腥草15g、连翘10g、薄荷5g', '将药物加水煎煮，取汁分多次服用，每日一剂。发热严重者可每日两剂。', '[\"准备药材：金银花、鱼腥草、连翘、薄荷\",\"加水煎煮15分钟\",\"取汁分多次服用\",\"每日一剂\",\"发热严重者可每日两剂\",\"多饮水\"]', NULL, NULL, NULL, '[12,19]', '[{\"id\": 1773144251035, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿发热方\", \"operator\": \"系统\"}]', 108, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `knowledge` VALUES (36, '侗医腰腿痛方', '药方', '内服疗法', '骨科疾病', '皮类', '侗族民间治疗腰腿痛的经验方，具有补肾强腰、活血通络的功效。杜仲、牛膝是强腰健骨的要药。', '杜仲30g、牛膝20g、血藤20g、延胡索15g', '将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。', '[\"准备药材：杜仲、牛膝、血藤、延胡索\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"避免过度劳累\"]', NULL, NULL, NULL, '[8,60,7,52]', '[{\"id\": 1773144251036, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医腰腿痛方\", \"operator\": \"系统\"}]', 102, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `knowledge` VALUES (37, '侗族产后缺乳方', '药方', '内服疗法', '妇科疾病', '全草类', '侗族妇女治疗产后缺乳的经验方，具有通经下乳、补气养血的功效。木通、冬葵子是通乳的要药。', '木通10g、冬葵子15g、王不留行15g、黄芪20g', '将药物加水煎煮，取汁分两次服用，每日一剂。配合食疗效果更佳。', '[\"准备药材：木通、冬葵子、王不留行、黄芪\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"配合食疗效果更佳\",\"保持心情舒畅\"]', NULL, NULL, NULL, '[36,39]', '[{\"id\": 1773144251037, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族产后缺乳方\", \"operator\": \"系统\"}]', 86, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `knowledge` VALUES (38, '侗医肩周炎方', '药方', '药浴疗法', '风湿骨痛', '全草类', '侗族民间治疗肩周炎的经验方，具有祛风除湿、活血通络的功效。配合药浴和推拿使用效果更佳。', '透骨草50g、艾叶50g、桂枝30g、羌活20g', '将药物加水煎煮30分钟，取汁用于药浴，浸泡肩部20-30分钟，每日一次。配合推拿按摩。', '[\"准备药材：透骨草、艾叶、桂枝、羌活\",\"加水煎煮30分钟\",\"取汁用于药浴\",\"浸泡肩部20-30分钟\",\"每日一次\",\"配合推拿按摩\"]', NULL, NULL, NULL, '[2,13]', '[{\"id\": 1773144251038, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医肩周炎方\", \"operator\": \"系统\"}]', 98, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `knowledge` VALUES (39, '侗族小儿腹泻方', '药方', '内服疗法', '儿科疾病', '根茎类', '侗族民间治疗小儿腹泻的经验方，具有健脾止泻、化湿止泻的功效。白术、茯苓是健脾止泻的要药。', '白术10g、茯苓10g、陈皮5g、车前子10g', '将药物加水煎煮，取汁分多次服用，每日一剂。腹泻严重者可每日两剂。', '[\"准备药材：白术、茯苓、陈皮、车前子\",\"加水煎煮15分钟\",\"取汁分多次服用\",\"每日一剂\",\"腹泻严重者可每日两剂\",\"注意饮食卫生\"]', NULL, NULL, NULL, '[21,15,23]', '[{\"id\": 1773144251039, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿腹泻方\", \"operator\": \"系统\"}]', 92, '2026-03-04 04:47:10', NULL, 0, 1);
INSERT INTO `knowledge` VALUES (40, '侗医药线点灸疗法', '疗法', '外治疗法', '风湿骨痛', '全草类', '药线点灸是侗族独特的灸法，以浸泡药液的苎麻线点燃后快速点灸穴位，兼具药物与温热双重作用，对风湿骨痛、关节僵硬有显著疗效。', '苎麻线、硫黄、麝香、冰片等', '将苎麻线浸泡于药液中7天以上，取出晾干备用。使用时点燃药线，快速点灸患处或穴位，每穴点灸3-5次，以皮肤微红为度。', '[\"制备药线：苎麻线浸泡药液7天\",\"取出晾干备用\",\"点燃药线\",\"快速点灸穴位或患处\",\"每穴点灸3-5次\",\"以皮肤微红为度\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 88, '2026-03-04 04:47:10', NULL, 5, 0);
INSERT INTO `knowledge` VALUES (41, '侗医角吸疗法', '疗法', '外治疗法', '风湿骨痛', '全草类', '角吸疗法是侗族传统拔罐疗法的变体，使用牛角作为吸具，利用负压吸附患处皮肤，达到祛风散寒、活血通络的目的。', '黄牛角、茶油', '将牛角尖端磨平，内壁涂茶油，点燃酒精棉球放入角内，迅速扣在患处，利用负压吸附皮肤，留置10-15分钟后取下。', '[\"准备牛角：磨平尖端，内壁涂茶油\",\"点燃酒精棉球放入角内\",\"迅速扣在患处\",\"利用负压吸附皮肤\",\"留置10-15分钟\",\"取下牛角\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 76, '2026-03-04 04:47:10', NULL, 7, 0);
INSERT INTO `knowledge` VALUES (42, '侗医刮痧疗法', '疗法', '外治疗法', '感冒发热', '全草类', '侗医刮痧疗法使用特制刮具配合茶油或姜汁，在体表特定部位刮拭，使皮肤出现红色粟粒状出血点，达到疏通经络、清热解毒的功效。', '牛角刮板、茶油或姜汁', '在刮拭部位涂抹茶油或姜汁，用刮板以45度角沿经络方向刮拭，力度由轻到重，每部位刮20-30次，以出痧为度。', '[\"在刮拭部位涂抹茶油或姜汁\",\"用刮板以45度角沿经络方向刮拭\",\"力度由轻到重\",\"每部位刮20-30次\",\"以出痧为度\",\"刮后注意保暖避风\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 82, '2026-03-04 04:47:10', NULL, 5, 0);
INSERT INTO `knowledge` VALUES (43, '侗医熏蒸疗法', '疗法', '外治疗法', '风湿骨痛', '全草类', '侗医熏蒸疗法利用药物煎煮产生的蒸汽熏蒸患处，通过皮肤吸收药力，达到祛风除湿、温经散寒的效果，是侗族地区治疗风湿病的常用方法。', '透骨草50g、艾叶50g、威灵仙30g、独活20g', '将药物放入熏蒸器中加水煎煮，待蒸汽充足后，将患处置于蒸汽上方熏蒸，温度以患者感觉温热舒适为度，每次20-30分钟。', '[\"将药物放入熏蒸器\",\"加水煎煮产生蒸汽\",\"将患处置于蒸汽上方\",\"温度以温热舒适为度\",\"每次熏蒸20-30分钟\",\"熏蒸后擦干保暖\"]', NULL, NULL, NULL, '[2]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 95, '2026-03-04 04:47:10', NULL, 6, 0);
INSERT INTO `knowledge` VALUES (44, '侗医火针疗法', '疗法', '外治疗法', '风湿骨痛', '全草类', '火针疗法是侗医特色外治法，将特制针具在火上烧红后快速刺入穴位或患处，利用温热刺激达到温经散寒、通络止痛的效果，对寒湿痹痛效果显著。', '特制火针、酒精灯', '将火针在酒精灯上烧红，快速刺入预定穴位，深度0.3-0.5寸，迅速拔出，每次选3-5个穴位，术后注意消毒防护。', '[\"选定穴位3-5个\",\"消毒穴位皮肤\",\"将火针在酒精灯上烧红\",\"快速刺入穴位0.3-0.5寸\",\"迅速拔出\",\"术后消毒防护\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 70, '2026-03-04 04:47:10', NULL, 2, 0);
INSERT INTO `knowledge` VALUES (45, '侗族风湿骨痛方', '药方', '内服疗法', '风湿骨痛', '根茎类', '侗族民间治疗风湿骨痛的经典方剂，具有祛风除湿、活血通络、消肿止痛的功效。此方在侗族地区广泛应用，是侗医骨伤科的代表性方剂。', '威灵仙20g、独活15g、秦艽15g、防己10g、牛膝15g', '将药物加水煎煮30分钟，取汁分两次温服，每日一剂。配合药浴或外敷效果更佳。', '[\"准备药材：威灵仙、独活、秦艽、防己、牛膝\",\"加水煎煮30分钟\",\"取汁分两次温服\",\"每日一剂\",\"配合药浴或外敷\",\"注意保暖避寒\"]', NULL, NULL, NULL, '[2,7]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 110, '2026-03-04 04:47:10', NULL, 8, 1);
INSERT INTO `knowledge` VALUES (46, '侗族感冒发热方', '药方', '内服疗法', '感冒发热', '全草类', '侗族民间治疗感冒发热的经验方，具有疏风解表、清热解毒的功效。此方药性平和，老少皆宜，是侗族家庭常备方剂。', '金银花15g、连翘15g、板蓝根15g、薄荷10g、甘草6g', '将药物加水煎煮20分钟，取汁分2-3次服用，每日一剂。发热重者可每日两剂。', '[\"准备药材：金银花、连翘、板蓝根、薄荷、甘草\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"发热重者可每日两剂\",\"多饮温水注意休息\"]', NULL, NULL, NULL, '[12,14]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 125, '2026-03-04 04:47:10', NULL, 10, 2);
INSERT INTO `knowledge` VALUES (47, '侗族胃寒腹痛方', '药方', '内服疗法', '消化系统', '根茎类', '侗族民间治疗胃寒腹痛的经验方，具有温中散寒、理气止痛的功效。高良姜、吴茱萸是温中散寒的要药。', '高良姜15g、吴茱萸6g、香附10g、木香6g', '将药物加水煎煮25分钟，取汁分两次温服，每日一剂。空腹服用效果更佳。', '[\"准备药材：高良姜、吴茱萸、香附、木香\",\"加水煎煮25分钟\",\"取汁分两次温服\",\"每日一剂\",\"空腹服用效果更佳\",\"忌食生冷食物\"]', NULL, NULL, NULL, '[30,28]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 98, '2026-03-04 04:47:10', NULL, 4, 0);
INSERT INTO `knowledge` VALUES (48, '侗族失眠多梦方', '药方', '内服疗法', '神经系统', '根茎类', '侗族民间治疗失眠多梦的经验方，具有养心安神、清热除烦的功效。酸枣仁是养心安神的要药。', '酸枣仁20g、茯神15g、夜交藤15g、合欢皮10g', '将药物加水煎煮30分钟，取汁于睡前1小时服用，每日一剂。', '[\"准备药材：酸枣仁、茯神、夜交藤、合欢皮\",\"加水煎煮30分钟\",\"取汁于睡前1小时服用\",\"每日一剂\",\"保持作息规律\",\"睡前避免过度用脑\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 78, '2026-03-04 04:47:10', NULL, 3, 0);
INSERT INTO `knowledge` VALUES (49, '侗族湿疹方', '药方', '外治疗法', '皮肤疾病', '全草类', '侗族民间治疗湿疹的经验方，具有清热燥湿、祛风止痒的功效。可内服与外洗配合使用。', '苦参30g、地肤子20g、白鲜皮15g、蛇床子15g', '内服：加水煎煮取汁分两次服用；外洗：将药物煎水，待温后擦洗患处，每日2次。', '[\"准备药材：苦参、地肤子、白鲜皮、蛇床子\",\"加水煎煮30分钟\",\"取汁分两部分\",\"内服分两次服用\",\"外洗擦洗患处\",\"每日2次\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 85, '2026-03-04 04:47:10', NULL, 5, 0);
INSERT INTO `knowledge` VALUES (50, '侗族腰痛方', '药方', '内服疗法', '风湿骨痛', '根茎类', '侗族民间治疗腰痛的经验方，具有补肾强腰、活血通络的功效。杜仲、牛膝是补肾强腰的要药。', '杜仲20g、牛膝15g、续断15g、狗脊15g', '将药物加水煎煮30分钟，取汁分两次温服，每日一剂。配合腰部药浴效果更佳。', '[\"准备药材：杜仲、牛膝、续断、狗脊\",\"加水煎煮30分钟\",\"取汁分两次温服\",\"每日一剂\",\"配合腰部药浴\",\"注意腰部保暖\"]', NULL, NULL, NULL, '[7]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 102, '2026-03-04 04:47:10', NULL, 6, 1);
INSERT INTO `knowledge` VALUES (51, '侗族痛经方', '药方', '内服疗法', '妇科疾病', '全草类', '侗族妇女治疗痛经的经验方，具有温经散寒、活血止痛的功效。此方在侗族妇女中广泛使用，效果显著。', '当归15g、川芎10g、艾叶10g、香附10g、延胡索10g', '将药物加水煎煮25分钟，取汁分两次温服，每日一剂。经前3天开始服用效果更佳。', '[\"准备药材：当归、川芎、艾叶、香附、延胡索\",\"加水煎煮25分钟\",\"取汁分两次温服\",\"每日一剂\",\"经前3天开始服用\",\"经期注意保暖避寒\"]', NULL, NULL, NULL, '[13]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 115, '2026-03-04 04:47:10', NULL, 7, 1);
INSERT INTO `knowledge` VALUES (52, '侗族咳嗽方', '药方', '内服疗法', '呼吸系统', '全草类', '侗族民间治疗咳嗽的经验方，具有润肺止咳、化痰平喘的功效。根据寒咳热咳辨证加减使用。', '桔梗10g、杏仁10g、百部10g、款冬花10g、甘草6g', '将药物加水煎煮20分钟，取汁分2-3次服用，每日一剂。寒咳加生姜3片，热咳加黄芩10g。', '[\"准备药材：桔梗、杏仁、百部、款冬花、甘草\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"寒咳加生姜，热咳加黄芩\",\"注意避风寒\"]', NULL, NULL, NULL, '[]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 90, '2026-03-04 04:47:10', NULL, 4, 0);
INSERT INTO `knowledge` VALUES (53, '侗族高血压方', '药方', '内服疗法', '心脑血管', '根茎类', '侗族民间辅助治疗高血压的经验方，具有平肝潜阳、清热降压的功效。此方为辅助调理方，不能替代西药降压治疗。', '天麻15g、钩藤20g、石决明30g、菊花10g', '将石决明先煎30分钟，再加入其他药物煎煮20分钟，取汁分两次服用，每日一剂。', '[\"准备药材：天麻、钩藤、石决明、菊花\",\"石决明先煎30分钟\",\"加入其他药物煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"定期监测血压\"]', NULL, NULL, NULL, '[1,11]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 80, '2026-03-04 04:47:10', NULL, 3, 0);
INSERT INTO `knowledge` VALUES (54, '侗族糖尿病调理方', '药方', '内服疗法', '内分泌', '全草类', '侗族民间辅助调理糖尿病的经验方，具有滋阴润燥、生津止渴的功效。此方为辅助调理方，需配合正规治疗。', '黄精20g、天花粉15g、麦冬15g、山药20g', '将药物加水煎煮30分钟，取汁分两次服用，每日一剂。需配合饮食控制和正规治疗。', '[\"准备药材：黄精、天花粉、麦冬、山药\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"配合饮食控制\",\"需配合正规治疗\"]', NULL, NULL, NULL, '[20,24]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 72, '2026-03-04 04:47:10', NULL, 2, 0);
INSERT INTO `knowledge` VALUES (55, '侗族跌打外敷方', '药方', '外治疗法', '跌打损伤', '全草类', '侗族民间治疗跌打损伤的外敷方，具有活血化瘀、消肿止痛的功效。与内服方配合使用，内外兼治效果更佳。', '三七粉20g、红花15g、栀子15g、大黄15g', '将药物研成细粉，用白酒或米醋调成糊状，外敷患处，用纱布固定，每日换药1次。', '[\"准备药材：三七粉、红花、栀子大黄\",\"将药物研成细粉\",\"用白酒或米醋调成糊状\",\"外敷患处\",\"用纱布固定\",\"每日换药1次\"]', NULL, NULL, NULL, '[2,5]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 105, '2026-03-04 04:47:10', NULL, 7, 1);
INSERT INTO `knowledge` VALUES (56, '侗族小儿疳积方', '药方', '内服疗法', '儿科疾病', '全草类', '侗族民间治疗小儿疳积的经验方，具有健脾消积、杀虫止泻的功效。疳积是侗族地区小儿常见病，多因喂养不当所致。', '使君子10g、槟榔6g、神曲10g、山楂10g、白术10g', '将药物加水煎煮15分钟，取汁分多次少量服用，每日一剂。配合推拿捏脊效果更佳。', '[\"准备药材：使君子、槟榔、神曲、山楂、白术\",\"加水煎煮15分钟\",\"取汁分多次少量服用\",\"每日一剂\",\"配合推拿捏脊\",\"调整饮食习惯\"]', NULL, NULL, NULL, '[21,15]', '[{\"id\":1,\"time\":\"2026-04-01\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]', 88, '2026-03-04 04:47:10', NULL, 4, 0);
