INSERT INTO `plants` VALUES (1, '钩藤', 'Meix kgaox', 'Uncaria rhynchophylla', '藤本类', '内服', '生于山谷、溪边、疏林下，分布于贵州、广西、湖南等地', '清热平肝，息风定惊。用于头痛眩晕，感冒夹惊，惊痫抽搐，妊娠子痫。', '侗族民间流传，一位老猎人发现山中藤蔓能治小儿惊风。其孙突发高热惊厥，老猎人取此藤煎水服用，孩子很快平静下来。从此侗家人便知道这种带钩的藤能治惊风，代代相传至今。', '[{\"name\": \"gouteng1.jpg\", \"path\": \"images/plants/gouteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"gouteng2.jpg\", \"path\": \"images/plants/gouteng2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"正德堂本草语-钩藤.mp4\", \"path\": \"videos/plants/正德堂本草语-钩藤.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广西三江\",\"湖南通道\"]', 'medium', '2026-03-04 04:47:10', NULL, 14, 2, 95, '[{\"id\": 1773145682001, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：钩藤\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (2, '透骨草', 'Nyenc nyenc', 'Phryma leptostachya', '全草类', '外用', '生于山坡、林缘、路旁，喜阴湿环境', '祛风除湿，舒筋活血，止痛。用于风湿痹痛，筋骨挛缩，寒湿脚气，疮癣肿毒。', '传说古时一位侗族药农上山采药，不慎扭伤脚踝，疼痛难忍。他发现路边一种小草，捣烂敷在患处，片刻后疼痛减轻，能继续行走。因能透入筋骨治病，故名透骨草。侗医常用其治疗跌打损伤。', '[{\"name\": \"tougucao1.jpg\", \"path\": \"images/plants/tougucao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"tougucao2.jpg\", \"path\": \"images/plants/tougucao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"贵州深山里的神奇草药透骨香，轻轻一碰香飘满山，看看你认识它吗.mp4\", \"path\": \"videos/plants/贵州深山里的神奇草药透骨香，轻轻一碰香飘满山，看看你认识它吗.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黎平\",\"广西龙胜\",\"湖南新晃\"]', 'easy', '2026-03-04 04:47:10', NULL, 10, 1, 85, '[{\"id\": 1773145682002, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：透骨草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (3, '九节茶', 'Jus jeenv', 'Sarcandra glabra', '全草类', '内服', '生于山坡林下、沟谷阴湿处，海拔400-1500米', '清热凉血，活血消斑，祛风通络。用于血热紫斑，紫癜，风湿痹痛，跌打损伤。', '侗族地区流传着一个故事：一位侗族老人患风湿多年，行动不便。一天他在山中休息，看到一只受伤的山羊啃食一种植物后伤势好转。老人也尝试服用，风湿果然减轻。因茎有九节，故名九节茶。', '[{\"name\": \"jiujiecha1.jpg\", \"path\": \"images/plants/jiujiecha1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jiujiecha2.jpg\", \"path\": \"images/plants/jiujiecha2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"果实红彤彤的草珊瑚，又名九节茶、九节风，你知道它有什么作用吗 草珊瑚 九节茶 植物科普 一日一植物 药用植物 中草药 药材 草药 采药 草本植物 - 抖音.mp4\", \"path\": \"videos/plants/果实红彤彤的草珊瑚，又名九节茶、九节风，你知道它有什么作用吗 草珊瑚 九节茶 植物科普 一日一植物 药用植物 中草药 药材 草药 采药 草本植物 - 抖音.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州从江\",\"广西融水\",\"湖南靖州\"]', 'medium', '2026-03-04 04:47:10', NULL, 21, 2, 88, '[{\"id\": 1773145682003, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：九节茶\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (4, '八角莲', 'Begs lianx', 'Dysosma versipellis', '根茎类', '外用', '生于深山密林下阴湿处，海拔600-2000米', '清热解毒，化痰散结，祛瘀消肿。用于痈肿疔疮，瘰疬，咽喉肿痛，跌打损伤，毒蛇咬伤。', '八角莲是侗医治疗毒蛇咬伤的要药。传说古时侗寨有人被毒蛇咬伤，生命垂危。一位侗族药师用八角莲捣烂外敷，患者转危为安。从此八角莲成为侗家必备的蛇伤良药，被誉为\"蛇伤圣药\"。', '[{\"name\": \"bajiaolian1.jpg\", \"path\": \"images/plants/bajiaolian1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"bajiaolian2.jpg\", \"path\": \"images/plants/bajiaolian2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中草药——八角莲-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/中草药——八角莲-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州雷山\",\"广西资源\",\"湖南城步\"]', 'hard', '2026-03-04 04:47:10', NULL, 6, 1, 60, '[{\"id\": 1773145682004, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：八角莲\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (5, '七叶一枝花', 'Qit yev yix faix', 'Paris polyphylla', '根茎类', '内服', '生于林下阴湿处，海拔700-2800米', '清热解毒，消肿止痛，凉肝定惊。用于疔疮痈肿，咽喉肿痛，蛇虫咬伤，跌扑伤痛，惊风抽搐。', '侗族民间称其为\"重楼\"，是治疗疮痈肿毒的特效药。相传古时侗寨流行恶疮，一位侗族药师梦见仙人指点，在深山找到七叶一枝花，治愈了众多患者。从此侗家人将其视为神药。', '[{\"name\": \"qiyeyizhihua1.jpg\", \"path\": \"images/plants/qiyeyizhihua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"qiyeyizhihua2.jpg\", \"path\": \"images/plants/qiyeyizhihua2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"七叶一枝花学名“重楼”，珍贵的蛇药植物，用途与价值了解吗？.mp4\", \"path\": \"videos/plants/七叶一枝花学名“重楼”，珍贵的蛇药植物，用途与价值了解吗？.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州台江\",\"广西兴安\",\"湖南桑植\"]', 'hard', '2026-03-04 04:47:10', NULL, 73, 2, 98, '[{\"id\": 1773145682005, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：七叶一枝花\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (6, '三颗针', 'Samx kebp zenl', 'Berberis julianae', '根皮类', '内服', '生于山坡灌丛中，海拔1000-2500米', '清热燥湿，泻火解毒。用于湿热泻痢，黄疸，湿疹，咽痛目赤，聤耳流脓，痈肿疮毒。', '三颗针因茎上有三叉刺而得名。侗族民间常用其根皮治疗肠胃疾病。传说一位侗族猎人在山中吃了不洁食物，腹痛难忍。他发现三颗针的根皮嚼服后腹痛立止，从此侗家人便用它治疗腹泻痢疾。', '[{\"name\": \"sankezhen1.jpg\", \"path\": \"images/plants/sankezhen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"sankezhen2.jpg\", \"path\": \"images/plants/sankezhen2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"【三颗针】为小檗科植物的根皮或茎皮 每一层叶子底下就长三颗针，这就是小时候上山最头疼的植物。它在你的家乡又叫什么名字呢？今日野寻记带你了解三颗针这味本草.mp4\", \"path\": \"videos/plants/【三颗针】为小檗科植物的根皮或茎皮 每一层叶子底下就长三颗针，这就是小时候上山最头疼的植物。它在你的家乡又叫什么名字呢？今日野寻记带你了解三颗针这味本草.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州剑河\",\"广西三江\",\"湖南芷江\"]', 'easy', '2026-03-04 04:47:10', NULL, 28, 1, 90, '[{\"id\": 1773145682006, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：三颗针\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (7, '血藤', 'Xeex tongc', 'Spatholobus suberectus', '藤本类', '内服', '生于山谷林下、灌丛中，攀援于树上', '补血，活血，通络。用于月经不调，血虚萎黄，麻木瘫痪，风湿痹痛。', '血藤是侗族妇女的常用药。传说古时侗寨一位妇女产后血虚，面色苍白，身体虚弱。侗族药师让她服用血藤煎剂，不久身体恢复健康，面色红润。因能补血活血，侗家人称其为\"血藤\"。', '[{\"name\": \"xueteng1.jpg\", \"path\": \"images/plants/xueteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"xueteng2.jpg\", \"path\": \"images/plants/xueteng2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"大血藤植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"path\": \"videos/plants/大血藤植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州榕江\",\"广西融安\",\"湖南会同\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 1, 82, '[{\"id\": 1773145682007, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：血藤\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (8, '杜仲', 'Dus zhong', 'Eucommia ulmoides', '皮类', '内服', '生于山地林中，海拔300-1500米', '补肝肾，强筋骨，安胎。用于肾虚腰痛，筋骨无力，妊娠漏血，胎动不安。', '杜仲是贵州道地药材，侗族地区广泛分布。侗族民间常用杜仲治疗腰膝酸痛。传说一位侗族老人腰痛多年，服用杜仲后腰痛消失，行走自如。从此杜仲成为侗家强腰健骨的良药。', '[{\"name\": \"duzhong1.jpg\", \"path\": \"images/plants/duzhong1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"duzhong2.jpg\", \"path\": \"images/plants/duzhong2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"【百草故事】植物黄金——杜仲.mp4\", \"path\": \"videos/plants/【百草故事】植物黄金——杜仲.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州遵义\",\"贵州黔东南\",\"湖南慈利\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 72, '[{\"id\": 1773145682008, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：杜仲\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (9, '黄精', 'Wangc jingl', 'Polygonatum sibiricum', '根茎类', '内服', '生于林下、灌丛或阴湿山坡，海拔800-2800米', '补气养阴，健脾，润肺，益肾。用于脾胃气虚，体倦乏力，胃阴不足，口干食少，肺虚燥咳，精血不足，腰膝酸软。', '黄精是侗族常用的滋补药。传说古时侗寨一位老人体弱多病，常年服用黄精后身体强健，活到百岁。侗家人认为黄精能延年益寿，将其视为\"仙草\"，常用于煲汤滋补。', '[{\"name\": \"huangjing1.jpg\", \"path\": \"images/plants/huangjing1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huangjing2.jpg\", \"path\": \"images/plants/huangjing2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"黄精.mp4\", \"path\": \"videos/plants/黄精.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州施秉\",\"广西龙胜\",\"湖南通道\"]', 'easy', '2026-03-04 04:47:10', NULL, 6, 0, 70, '[{\"id\": 1773145682009, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：黄精\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (10, '白及', 'Begc jil', 'Bletilla striata', '根茎类', '内服', '生于林下、草丛中，海拔100-3200米', '收敛止血，消肿生肌。用于咯血，吐血，外伤出血，疮疡肿毒，皮肤皲裂。', '白及是侗医治疗外伤出血的常用药。传说古时侗族猎人在山中受伤，血流不止。他用白及粉末敷在伤口，血立刻止住，伤口很快愈合。从此白及成为侗家必备的外伤止血药。', '[{\"name\": \"baiji1.jpg\", \"path\": \"images/plants/baiji1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"baiji2.jpg\", \"path\": \"images/plants/baiji2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中兽药之白及.mp4\", \"path\": \"videos/plants/中兽药之白及.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州镇远\",\"广西全州\",\"湖南新宁\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 1, 80, '[{\"id\": 1773145682010, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：白及\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (11, '天麻', 'Qianc mabl', 'Gastrodia elata', '根茎类', '内服', '生于林下阴湿处，海拔1200-2000米，多与蜜环菌共生', '息风止痉，平抑肝阳，祛风通络。用于肝风内动，惊痫抽搐，眩晕头痛，肢体麻木，手足不遂。', '天麻是贵州道地药材，黔东南是天麻的主产区。侗族民间常用天麻治疗头晕头痛。传说一位侗族老人常年头痛，服用天麻后头痛消失。因天麻能治\"诸风\"，侗家人称其为\"定风神草\"。', '[{\"name\": \"tianma1.jpg\", \"path\": \"images/plants/tianma1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"tianma2.jpg\", \"path\": \"images/plants/tianma2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药材讲解天麻的功效与作用_高清1080P在线观看平台_腾讯视频.mp4\", \"path\": \"videos/plants/中药材讲解天麻的功效与作用_高清1080P在线观看平台_腾讯视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州大方\",\"贵州雷山\",\"云南昭通\"]', 'hard', '2026-03-04 04:47:10', NULL, 3, 1, 78, '[{\"id\": 1773145682011, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：天麻\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (12, '金银花', 'Jinl yinv faix', 'Lonicera japonica', '花类', '内服', '生于山坡灌丛、疏林中，适应性极强', '清热解毒，疏散风热。用于痈肿疔疮，喉痹，丹毒，热毒血痢，风热感冒，温病发热。', '金银花是侗族民间常用的清热解毒药。每年春夏之交，侗家人采摘金银花晒干备用。传说古时侗寨流行热病，一位侗族药师用金银花煎水给患者服用，热病很快消退。从此金银花成为侗家清热解毒的首选药。', '[{\"name\": \"jinyinhua1.jpg\", \"path\": \"images/plants/jinyinhua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jinyinhua2.jpg\", \"path\": \"images/plants/jinyinhua2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"金银花的功效作用全解析-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/金银花的功效作用全解析-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广西桂林\",\"湖南怀化\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 75, '[{\"id\": 1773145682012, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：金银花\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (13, '艾叶', 'Ngaix yev', 'Artemisia argyi', '叶类', '外用', '生于路旁、荒地、林缘，分布极广', '温经止血，散寒止痛；外用祛湿止痒。用于吐血，衄血，崩漏，月经过多，胎漏下血，少腹冷痛，经寒不调，宫冷不孕。', '艾叶是侗族艾灸疗法的主要材料。侗族民间常用艾叶熏蒸治疗风湿。传说古时侗族妇女产后腹痛，用艾叶熏蒸腹部后疼痛消失。从此艾叶成为侗家妇科良药，也是艾灸疗法的必备材料。', '[{\"name\": \"aiye1.jpg\", \"path\": \"images/plants/aiye1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"aiye2.jpg\", \"path\": \"images/plants/aiye2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中草药之艾叶，有关它的一切.mp4\", \"path\": \"videos/plants/中草药之艾叶，有关它的一切.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广西三江\",\"湖南通道\"]', 'easy', '2026-03-04 04:47:10', NULL, 4, 0, 68, '[{\"id\": 1773145682013, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：艾叶\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (14, '石斛', 'Xix huf', 'Dendrobium nobile', '全草类', '内服', '生于树上或岩石上，海拔500-1500米', '益胃生津，滋阴清热。用于热病津伤，口干烦渴，胃阴不足，食少干呕，病后虚热不退，阴虚火旺，骨蒸劳热。', '石斛是侗族地区的珍稀药材，被称为\"仙草\"。侗族民间常用石斛治疗口干舌燥。传说古时侗寨一位老人常年口渴，服用石斛后症状消失。因石斛生长在悬崖峭壁上，采摘困难，侗家人将其视为珍品。', '[{\"name\": \"shihu1.jpg\", \"path\": \"images/plants/shihu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"shihu2.jpg\", \"path\": \"images/plants/shihu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"石斛的功效与作用有哪些？这些好处你知道吗？正确认识石斛很重要.mp4\", \"path\": \"videos/plants/石斛的功效与作用有哪些？这些好处你知道吗？正确认识石斛很重要.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州赤水\",\"广西靖西\",\"云南文山\"]', 'hard', '2026-03-04 04:47:10', NULL, 2, 0, 58, '[{\"id\": 1773145682014, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：石斛\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (15, '茯苓', 'Fuf lix', 'Poria cocos', '菌类', '内服', '生于松树根部，海拔700-1500米', '利水渗湿，健脾，宁心。用于水肿尿少，痰饮眩悸，脾虚食少，便溏泄泻，心神不安，惊悸失眠。', '茯苓是侗族常用的健脾利湿药。侗族地区松林茂密，盛产茯苓。传说古时侗寨有人患水肿病，服用茯苓后水肿消退。侗家人常用茯苓煲汤，既美味又养生，是侗族食疗的重要材料。', '[{\"name\": \"fuling1.jpg\", \"path\": \"images/plants/fuling1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"fuling2.jpg\", \"path\": \"images/plants/fuling2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"茯苓 深度解读 你想知道的关于茯苓一切的东西都在这里能学到.mp4\", \"path\": \"videos/plants/茯苓 深度解读 你想知道的关于茯苓一切的东西都在这里能学到.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州锦屏\",\"安徽岳西\",\"云南普洱\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 65, '[{\"id\": 1773145682015, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：茯苓\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (16, '何首乌', 'Hoc soux wux', 'Polygonum multiflorum', '根茎类', '内服', '生于山坡灌丛、石缝中，海拔200-3000米', '解毒，消痈，润肠通便。用于瘰疬疮痈，风疹瘙痒，肠燥便秘；制首乌补肝肾，益精血，乌须发。', '何首乌是侗族常用的滋补药。传说古时一位侗族老人头发全白，服用何首乌后头发变黑，身体强健。侗家人认为何首乌能乌发延年，常用其泡酒或煲汤，是侗族养生保健的重要药材。', '[{\"name\": \"heshouwu1.jpg\", \"path\": \"images/plants/heshouwu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"heshouwu2.jpg\", \"path\": \"images/plants/heshouwu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药本草何首乌的功效与作用及禁忌_高清1080P在线观看平台_腾讯视频.mp4\", \"path\": \"videos/plants/中药本草何首乌的功效与作用及禁忌_高清1080P在线观看平台_腾讯视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广西河池\",\"湖南湘西\"]', 'medium', '2026-03-04 04:47:10', NULL, 3, 0, 62, '[{\"id\": 1773145682016, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：何首乌\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (17, '半夏', 'Bany xax', 'Pinellia ternata', '根茎类', '内服', '生于林下、草丛中，海拔2500米以下', '燥湿化痰，降逆止呕，消痞散结。用于湿痰寒痰，咳喘痰多，痰饮眩悸，风痰眩晕，痰厥头痛，呕吐反胃。', '半夏是侗医治疗咳嗽的常用药。传说古时侗寨有人患痰咳不止，服用半夏后咳嗽消失。侗族药师常用半夏配伍其他药物治疗各种咳嗽。因半夏有毒，侗医在用药前会进行炮制，确保用药安全。', '[{\"name\": \"banxia1.jpg\", \"path\": \"images/plants/banxia1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"banxia2.jpg\", \"path\": \"images/plants/banxia2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"每天学习认识一味中药材——半夏.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——半夏.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"四川南充\",\"甘肃陇南\"]', 'hard', '2026-03-04 04:47:10', NULL, 2, 0, 55, '[{\"id\": 1773145682017, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：半夏\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (18, '车前草', 'Cex qianl caox', 'Plantago asiatica', '全草类', '内服', '生于路旁、田边、荒地，分布极广', '清热利尿，祛痰，凉血，解毒。用于水肿尿少，热淋涩痛，暑湿泻痢，痰热咳嗽，吐血衄血，痈肿疮毒。', '车前草是侗族民间最常见的草药之一。传说古时一位侗族猎人在山中中暑，口渴难耐。他发现路边有一种草，嚼服后口渴减轻。因常生长在路边车辙中，故名车前草。侗家人常用其清热利尿。', '[{\"name\": \"cheqiancao1.jpg\", \"path\": \"images/plants/cheqiancao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"cheqiancao2.jpg\", \"path\": \"images/plants/cheqiancao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"在马路边发现的本草——车前草.mp4\", \"path\": \"videos/plants/在马路边发现的本草——车前草.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广西桂林\",\"湖南怀化\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 52, '[{\"id\": 1773145682018, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：车前草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (19, '鱼腥草', 'Yux xingl caox', 'Houttuynia cordata', '全草类', '内服', '生于沟边、溪边、林下阴湿处', '清热解毒，消痈排脓，利尿通淋。用于肺痈吐脓，痰热喘咳，热痢，热淋，痈肿疮毒。', '鱼腥草是侗族地区最常见的野菜和药材。侗家人喜欢用鱼腥草凉拌食用，也用它治疗肺热咳嗽。传说古时侗寨有人患肺痈，服用鱼腥草后痊愈。因有特殊腥味，故名鱼腥草，是侗家药食两用的佳品。', '[{\"name\": \"yuxingcao1.jpg\", \"path\": \"images/plants/yuxingcao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yuxingcao2.jpg\", \"path\": \"images/plants/yuxingcao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"鱼腥草的主要成分和用途-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/鱼腥草的主要成分和用途-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"院子里的中药11--鱼腥草（药食两用，肺痈要药）.mp4\", \"path\": \"videos/plants/院子里的中药11--鱼腥草（药食两用，肺痈要药）.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"四川雅安\",\"云南昭通\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 50, '[{\"id\": 1773145682019, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：鱼腥草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (20, '吴茱萸', 'Wuc zhuw yuv', 'Evodia rutaecarpa', '果实类', '内服', '生于山坡、路旁、林缘，海拔200-1500米', '散寒止痛，降逆止呕，助阳止泻。用于厥阴头痛，寒疝腹痛，寒湿脚气，经行腹痛，脘腹胀痛，呕吐吞酸，五更泄泻。', '吴茱萸是侗医治疗胃寒呕吐的常用药。传说古时侗寨有人患胃寒呕吐，服用吴茱萸后症状消失。侗族药师常用吴茱萸配伍其他药物治疗胃寒诸症。吴茱萸也是侗族传统药浴的重要材料。', '[{\"name\": \"wuzhuyu1.jpg\", \"path\": \"images/plants/wuzhuyu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"wuzhuyu2.jpg\", \"path\": \"images/plants/wuzhuyu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"认识中药，制吴茱萸.mp4\", \"path\": \"videos/plants/认识中药，制吴茱萸.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州铜仁\",\"广西百色\",\"湖南湘西\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 48, '[{\"id\": 1773145682020, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：吴茱萸\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (21, '白术', 'Begc suc', 'Atractylodes macrocephala', '根茎类', '内服', '生于山坡林下、灌丛中，海拔800-1800米', '健脾益气，燥湿利水，止汗，安胎。用于脾虚食少，腹胀泄泻，痰饮眩悸，水肿，自汗，胎动不安。', '白术是侗族常用的健脾药。传说古时侗寨有人脾虚泄泻，久治不愈。一位侗族药师让他服用白术，泄泻很快停止。从此白术成为侗家健脾益气的常用药，也是侗族食疗的重要材料。', '[{\"name\": \"baizhu1.jpg\", \"path\": \"images/plants/baizhu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"baizhu2.jpg\", \"path\": \"images/plants/baizhu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"白术.mp4\", \"path\": \"videos/plants/白术.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"浙江磐安\",\"安徽亳州\"]', 'medium', '2026-03-04 04:47:10', NULL, 5, 0, 45, '[{\"id\": 1773145682021, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：白术\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (22, '苍术', 'Cangl suc', 'Atractylodes lancea', '根茎类', '内服', '生于山坡灌丛、草丛中，海拔500-2000米', '燥湿健脾，祛风散寒，明目。用于湿阻中焦，脘腹胀满，泄泻，水肿，脚气痿躄，风湿痹痛，风寒感冒，夜盲。', '苍术是侗族民间常用的祛湿药。侗族地区气候潮湿，风湿病多发，侗医常用苍术配伍其他药物治疗风湿。传说一位侗族老人患风湿多年，服用苍术后症状明显改善。', '[{\"name\": \"cangzhu1.jpg\", \"path\": \"images/plants/cangzhu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"cangzhu2.jpg\", \"path\": \"images/plants/cangzhu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"每天学习认识一味中药材——苍术.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——苍术.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江苏茅山\",\"湖北罗田\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 42, '[{\"id\": 1773145682022, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：苍术\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (23, '厚朴', 'Houp pox', 'Magnolia officinalis', '皮类', '内服', '生于山地林中，海拔300-1500米', '燥湿消痰，下气除满。用于湿滞伤中，脘痞吐泻，食积气滞，腹胀便秘，痰饮喘咳。', '厚朴是侗医治疗腹胀的常用药。传说古时侗寨有人腹胀如鼓，疼痛难忍。侗族药师用厚朴配伍其他药物，患者服用后腹胀消退。从此厚朴成为侗家消胀除满的要药。', '[{\"name\": \"houpo1.jpg\", \"path\": \"images/plants/houpo1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"houpo2.jpg\", \"path\": \"images/plants/houpo2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"厚朴 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/厚朴 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"厚朴，很美的中药名，你知道她来自什么植物吗.mp4\", \"path\": \"videos/plants/厚朴，很美的中药名，你知道她来自什么植物吗.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"四川都江堰\",\"浙江龙泉\"]', 'hard', '2026-03-04 04:47:10', NULL, 4, 0, 40, '[{\"id\": 1773145682023, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：厚朴\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (24, '陈皮', 'Cencupil', 'Citrus reticulata', '果实类', '内服', '栽培于丘陵、低山地带，江河湖泊沿岸或平原', '理气健脾，燥湿化痰。用于脘腹胀满，食少吐泻，咳嗽痰多。', '陈皮是侗族民间常用的理气药。侗家人常在秋冬季节收集橘皮晒干备用。传说古时侗寨有人消化不良，服用陈皮后症状改善。陈皮也是侗族食疗的重要材料，常用于煲汤调味。', '[{\"name\": \"chenpi1.jpg\", \"path\": \"images/plants/chenpi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"chenpi2.jpg\", \"path\": \"images/plants/chenpi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"陈皮的功效与作用：古老的养生宝贝-健康视频-搜狐视频.mp4\", \"path\": \"videos/plants/陈皮的功效与作用：古老的养生宝贝-健康视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广东新会\",\"贵州黔东南\",\"四川眉山\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 38, '[{\"id\": 1773145682024, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：陈皮\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (25, '枳壳', 'Zix qox', 'Citrus aurantium', '果实类', '内服', '栽培于丘陵、低山地带', '理气宽中，行滞消胀。用于胸胁气滞，胀满疼痛，食积不化，痰饮内停，脏器下垂。', '枳壳是侗医治疗气滞的常用药。传说古时侗寨有人胸胁胀痛，服用枳壳后症状缓解。侗族药师常用枳壳配伍其他药物治疗各种气滞证。枳壳也是侗族传统药浴的材料之一。', '[{\"name\": \"zhiqiao1.jpg\", \"path\": \"images/plants/zhiqiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zhiqiao2.jpg\", \"path\": \"images/plants/zhiqiao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"枳壳.mp4\", \"path\": \"videos/plants/枳壳.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江西樟树\",\"四川遂宁\"]', 'easy', '2026-03-04 04:47:10', NULL, 3, 0, 35, '[{\"id\": 1773145682025, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：枳壳\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (26, '木香', 'Mux xangl', 'Aucklandia lappa', '根茎类', '内服', '生于高山草地、灌丛中，海拔2500-4000米', '行气止痛，健脾消食。用于胸胁胀痛，泻痢后重，食积不消，不思饮食。', '木香是侗医治疗腹痛的常用药。传说古时侗寨有人腹痛不止，服用木香后疼痛消失。侗族药师常用木香配伍其他药物治疗各种腹痛。木香也是侗族传统配方的重要组成部分。', '[{\"name\": \"muxiang1.jpg\", \"path\": \"images/plants/muxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"muxiang2.jpg\", \"path\": \"images/plants/muxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"木香 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/木香 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"云南丽江\",\"贵州黔东南\",\"四川阿坝\"]', 'hard', '2026-03-04 04:47:10', NULL, 2, 0, 32, '[{\"id\": 1773145682026, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：木香\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (27, '砂仁', 'Sax renl', 'Amomum villosum', '果实类', '内服', '生于山谷林下阴湿处，海拔100-800米', '化湿开胃，温脾止泻，理气安胎。用于湿浊中阻，脘痞不饥，脾胃虚寒，呕吐泄泻，妊娠恶阻，胎动不安。', '砂仁是侗族常用的化湿药。传说古时侗寨有人脾胃虚寒，食欲不振。侗族药师让他服用砂仁，食欲很快恢复。砂仁也是侗族孕妇常用的安胎药，被视为侗家妇科良药。', '[{\"name\": \"sharen1.jpg\", \"path\": \"images/plants/sharen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"sharen2.jpg\", \"path\": \"images/plants/sharen2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"砂仁 深度解读  教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/砂仁 深度解读  教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广东阳春\",\"云南西双版纳\",\"贵州黔东南\"]', 'medium', '2026-03-04 04:47:10', NULL, 3, 0, 30, '[{\"id\": 1773145682027, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：砂仁\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (28, '薏苡仁', 'Yiv yix renl', 'Coix lacryma-jobi', '种子类', '内服', '栽培于屋旁、河边、溪涧或阴湿山谷中', '利水渗湿，健脾止泻，除痹，排脓，解毒散结。用于水肿，脚气，小便不利，脾虚泄泻，湿痹拘挛，肺痈，肠痈，赘疣，癌肿。', '薏苡仁是侗族民间常用的利湿药，也是常见的杂粮。侗家人常用薏苡仁煲粥食用，既美味又养生。传说古时侗寨有人患水肿病，服用薏苡仁后水肿消退。薏苡仁是侗族药食两用的代表。', '[{\"name\": \"yiyiren1.jpg\", \"path\": \"images/plants/yiyiren1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yiyiren2.jpg\", \"path\": \"images/plants/yiyiren2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"药食同源的薏苡仁｜长在叶片里的小籽.mp4\", \"path\": \"videos/plants/药食同源的薏苡仁｜长在叶片里的小籽.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"福建浦城\",\"辽宁辽阳\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 28, '[{\"id\": 1773145682028, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：薏苡仁\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (29, '泽泻', 'Zec xeeb', 'Alisma orientale', '根茎类', '内服', '生于沼泽边缘、水塘、水沟等浅水处', '利水渗湿，泄热，化浊降脂。用于小便不利，水肿胀满，泄泻尿少，痰饮眩晕，热淋涩痛，高脂血症。', '泽泻是侗医治疗水肿的常用药。传说古时侗寨有人患水肿病，小便不利。侗族药师让他服用泽泻，水肿很快消退。泽泻也是侗族利水渗湿的重要药材。', '[{\"name\": \"zexie1.jpg\", \"path\": \"images/plants/zexie1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zexie2.jpg\", \"path\": \"images/plants/zexie2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"泽泻 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/泽泻 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"福建建瓯\",\"贵州黔东南\",\"四川彭山\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 25, '[{\"id\": 1773145682029, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：泽泻\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (30, '猪苓', 'Jux lix', 'Polyporus umbellatus', '菌类', '内服', '生于林中树根旁地上或腐木桩旁，海拔800-2000米', '利水渗湿。用于小便不利，水肿胀满，脚气，泄泻，淋浊，带下。', '猪苓是侗族常用的利水药。侗族地区山林茂密，盛产猪苓。传说古时侗寨有人小便不利，服用猪苓后症状改善。猪苓常与茯苓配伍使用，是侗医利水渗湿的经典组合。', '[{\"name\": \"zhuling1.jpg\", \"path\": \"images/plants/zhuling1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zhuling2.jpg\", \"path\": \"images/plants/zhuling2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"猪苓 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/猪苓 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"陕西留坝\",\"贵州黔东南\",\"云南丽江\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 22, '[{\"id\": 1773145682030, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：猪苓\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (31, '滑石', 'Huax six', 'Talcum', '矿物类', '外用', '产于变质岩地区，由富含镁的岩石经热液蚀变而成', '利尿通淋，清热解暑；外用祛湿敛疮。用于热淋，石淋，尿热涩痛，暑湿烦渴，湿热水泻；外治湿疹，湿疮，痱子。', '滑石是侗医治疗热淋的常用药。侗族民间常用滑石配伍其他药物治疗泌尿系统疾病。滑石也是侗族夏季常用的清热解暑药，常用于治疗痱子。', '[{\"name\": \"huashi1.jpg\", \"path\": \"images/plants/huashi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huashi2.jpg\", \"path\": \"images/plants/huashi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"滑石 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/滑石 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"山东平度\",\"广西桂林\",\"辽宁海城\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 20, '[{\"id\": 1773145682031, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：滑石\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (32, '木通', 'Mux tongl', 'Akebia quinata', '藤本类', '内服', '生于山坡、山沟、疏林、灌丛中，海拔250-2000米', '利尿通淋，清心除烦，通经下乳。用于淋证，水肿，心烦尿赤，口舌生疮，经闭乳少，湿热痹痛。', '木通是侗医治疗淋证的常用药。传说古时侗寨有人小便涩痛，服用木通后症状缓解。侗族药师常用木通配伍其他药物治疗泌尿系统疾病。木通也是侗族通经下乳的重要药材。', '[{\"name\": \"mutong1.jpg\", \"path\": \"images/plants/mutong1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"mutong2.jpg\", \"path\": \"images/plants/mutong2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"木通 深度解读 教你一些你能用到知识.mp4\", \"path\": \"videos/plants/木通 深度解读 教你一些你能用到知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 18, '[{\"id\": 1773145682032, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：木通\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (33, '瞿麦', 'Qux maix', 'Dianthus superbus', '全草类', '内服', '生于山坡、草地、路旁或林下，海拔500-2500米', '利尿通淋，破血通经。用于热淋，血淋，石淋，小便不通，淋沥涩痛，经闭瘀阻。', '瞿麦是侗族民间治疗淋证的常用药。传说古时侗寨有人患石淋，小便疼痛难忍。侗族药师让他服用瞿麦，症状逐渐改善。瞿麦也是侗族通经活血的重要药材。', '[{\"name\": \"qumai1.jpg\", \"path\": \"images/plants/qumai1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"qumai2.jpg\", \"path\": \"images/plants/qumai2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"869017da2b1e466ba51ddc393acf5c7d.mp4\", \"path\": \"videos/plants/869017da2b1e466ba51ddc393acf5c7d.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"河北安国\",\"安徽亳州\"]', 'easy', '2026-03-04 04:47:10', NULL, 9, 0, 15, '[{\"id\": 1773145682033, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：瞿麦\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (34, '萹蓄', 'Bianx xux', 'Polygonum aviculare', '全草类', '内服', '生于路旁、田边、荒地、水边湿地，分布极广', '利尿通淋，杀虫，止痒。用于热淋，小便短赤，淋沥涩痛，皮肤湿疹，阴痒带下。', '萹蓄是侗族民间最常见的草药之一。传说古时侗寨有人小便涩痛，服用萹蓄后症状缓解。萹蓄也是侗族治疗皮肤湿疹的常用药，外用内服均可。', '[{\"name\": \"bianxu1.jpg\", \"path\": \"images/plants/bianxu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"bianxu2.jpg\", \"path\": \"images/plants/bianxu2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"296 萹蓄——萹蓄——又名扁竹、粉节草、道生草、蚂蚁草.mp4\", \"path\": \"videos/plants/296 萹蓄——萹蓄——又名扁竹、粉节草、道生草、蚂蚁草.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"河南禹州\",\"山东平邑\"]', 'easy', '2026-03-04 04:47:10', NULL, 3, 0, 12, '[{\"id\": 1773145682034, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：萹蓄\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (35, '海金沙', 'Haix jinl sax', 'Lygodium japonicum', '孢子类', '内服', '生于山坡林下、灌丛中、溪边阴湿处，海拔100-1500米', '清利湿热，通淋止痛。用于热淋，砂淋，石淋，血淋，膏淋，尿道涩痛。', '海金沙是侗医治疗石淋的特效药。传说古时侗寨有人患肾结石，疼痛难忍。侗族药师让他服用海金沙，结石逐渐排出。海金沙是侗族治疗泌尿系统结石的重要药材。', '[{\"name\": \"haijinsha1.jpg\", \"path\": \"images/plants/haijinsha1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"haijinsha2.jpg\", \"path\": \"images/plants/haijinsha2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中草药——海金沙的作用和故事.mp4\", \"path\": \"videos/plants/中草药——海金沙的作用和故事.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"广东广宁\",\"浙江金华\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 10, '[{\"id\": 1773145682035, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：海金沙\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (36, '石韦', 'Xix weix', 'Pyrrosia lingua', '全草类', '内服', '生于林下岩石上或树干上，海拔100-1800米', '利尿通淋，清肺止咳，凉血止血。用于热淋，血淋，石淋，小便不通，淋沥涩痛，肺热喘咳，吐血，衄血，尿血，崩漏。', '石韦是侗族民间治疗淋证的常用药。传说古时侗寨有人小便涩痛带血，服用石韦后症状缓解。石韦也是侗族治疗肺热咳嗽的重要药材，具有清肺止咳的功效。', '[{\"name\": \"shiwei1.jpg\", \"path\": \"images/plants/shiwei1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"shiwei2.jpg\", \"path\": \"images/plants/shiwei2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"石韦.mp4\", \"path\": \"videos/plants/石韦.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"四川峨眉山\",\"浙江天台\"]', 'medium', '2026-03-04 04:47:10', NULL, 4, 0, 8, '[{\"id\": 1773145682036, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：石韦\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (37, '冬葵子', 'Dongl kuix zix', 'Abutilon theophrasti', '种子类', '内服', '生于路旁、荒地、田野间，分布极广', '清热利尿，消肿。用于尿闭，水肿，口渴，尿少涩痛，乳汁不通。', '冬葵子是侗族民间常用的利尿药。传说古时侗寨有人小便不利，服用冬葵子后症状改善。冬葵子也是侗族通乳的重要药材，常用于产后乳汁不通。', '[{\"name\": \"dongkuizi1.jpg\", \"path\": \"images/plants/dongkuizi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dongkuizi2.jpg\", \"path\": \"images/plants/dongkuizi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"冬葵子.mp4\", \"path\": \"videos/plants/冬葵子.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"河南南阳\",\"山东济南\"]', 'easy', '2026-03-04 04:47:10', NULL, 5, 0, 5, '[{\"id\": 1773145682037, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：冬葵子\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (38, '灯心草', 'Denl xinl caox', 'Juncus effusus', '全草类', '内服', '生于水旁、田边、潮湿处，分布极广', '清心火，利小便。用于心烦失眠，尿少涩痛，口舌生疮。', '灯心草是侗族民间常用的清心药。传说古时侗寨有人心烦失眠，口舌生疮。侗族药师让他服用灯心草，症状很快缓解。灯心草也是侗族治疗小儿夜啼的常用药。', '[{\"name\": \"dengxincao1.jpg\", \"path\": \"images/plants/dengxincao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dengxincao2.jpg\", \"path\": \"images/plants/dengxincao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"灯心草植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"path\": \"videos/plants/灯心草植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江苏苏州\",\"浙江杭州\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 3, '[{\"id\": 1773145682038, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：灯心草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (39, '地肤子', 'Dix fux zix', 'Kochia scoparia', '果实类', '内服', '生于村边、屋旁、路旁、荒地，分布极广', '清热利湿，祛风止痒。用于小便涩痛，阴痒带下，风疹，湿疹，皮肤瘙痒。', '地肤子是侗族民间治疗皮肤瘙痒的常用药。传说古时侗寨有人患湿疹，瘙痒难忍。侗族药师让他服用地肤子，症状很快缓解。地肤子也是侗族治疗妇科疾病的常用药。', '[{\"name\": \"difuzi1.jpg\", \"path\": \"images/plants/difuzi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"difuzi2.jpg\", \"path\": \"images/plants/difuzi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"倪海厦《神农本草经》第075味药：地肤子.mp4\", \"path\": \"videos/plants/倪海厦《神农本草经》第075味药：地肤子.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"河北安国\",\"山东平邑\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682039, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：地肤子\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (40, '茵陈', 'Yinv cenc', 'Artemisia capillaris', '全草类', '内服', '生于山坡、路旁、河岸、沙地，分布极广', '清利湿热，利胆退黄。用于黄疸尿少，湿温暑湿，湿疮瘙痒。', '茵陈是侗医治疗黄疸的特效药。传说古时侗寨有人患黄疸病，皮肤发黄。侗族药师让他服用茵陈，黄疸很快消退。茵陈是侗族治疗肝胆疾病的重要药材。', '[{\"name\": \"yinchen1.jpg\", \"path\": \"images/plants/yinchen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yinchen2.jpg\", \"path\": \"images/plants/yinchen2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"遇见菊科植物“茵陈”，有着草中之“人参”，能当野菜或制茶.mp4\", \"path\": \"videos/plants/遇见菊科植物“茵陈”，有着草中之“人参”，能当野菜或制茶.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"陕西蒲城\",\"江西樟树\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682040, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：茵陈\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (41, '金钱草', 'Jinl qianc caox', 'Lysimachia christinae', '全草类', '内服', '生于沟边、路旁阴湿处，海拔100-2000米', '利湿退黄，利尿通淋，解毒消肿。用于黄疸尿赤，热淋，石淋，小便涩痛，痈肿疔疮，毒蛇咬伤。', '金钱草是侗医治疗胆结石的特效药。传说古时侗寨有人患胆结石，疼痛难忍。侗族药师让他服用金钱草，结石逐渐排出。金钱草也是侗族治疗黄疸的重要药材。', '[{\"name\": \"jinqiancao1.jpg\", \"path\": \"images/plants/jinqiancao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jinqiancao2.jpg\", \"path\": \"images/plants/jinqiancao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"金钱草的功效与作用.mp4\", \"path\": \"videos/plants/金钱草的功效与作用.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"四川乐山\",\"贵州黔东南\",\"浙江杭州\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682041, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：金钱草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (42, '虎杖', 'Hux zhangx', 'Polygonum cuspidatum', '根茎类', '内服', '生于山谷、溪边、路旁，海拔100-2000米', '利湿退黄，清热解毒，散瘀止痛，止咳化痰。用于湿热黄疸，淋浊，带下，风湿痹痛，痈肿疮毒，水火烫伤，经闭，癥瘕，跌打损伤，肺热咳嗽。', '虎杖是侗族民间常用的清热解毒药。传说古时侗寨有人患黄疸，服用虎杖后症状改善。虎杖也是侗族治疗跌打损伤的重要药材，具有散瘀止痛的功效。', '[{\"name\": \"huzhang1.jpg\", \"path\": \"images/plants/huzhang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huzhang2.jpg\", \"path\": \"images/plants/huzhang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"虎杖的功效与作用和用量你知道多少.mp4\", \"path\": \"videos/plants/虎杖的功效与作用和用量你知道多少.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682042, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：虎杖\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (43, '垂盆草', 'Cuix penc caox', 'Sedum sarmentosum', '全草类', '内服', '生于山坡岩石上、沟边、路旁湿润处，海拔1600米以下', '利湿退黄，清热解毒。用于湿热黄疸，小便不利，痈肿疮疡。', '垂盆草是侗医治疗黄疸的常用药。传说古时侗寨有人患黄疸病，服用垂盆草后黄疸消退。垂盆草也是侗族治疗痈肿疮疡的重要药材，外用内服均可。', '[{\"name\": \"chuipencao1.jpg\", \"path\": \"images/plants/chuipencao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"chuipencao2.jpg\", \"path\": \"images/plants/chuipencao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"央视4台（中华医药)里介绍的“仙”草，原来长这样！学名垂盆草.mp4\", \"path\": \"videos/plants/央视4台（中华医药)里介绍的“仙”草，原来长这样！学名垂盆草.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682043, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：垂盆草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (44, '附子', 'Fux zix', 'Aconitum carmichaeli', '根茎类', '内服', '生于山地草坡、灌丛中，海拔1000-2500米', '回阳救逆，补火助阳，散寒止痛。用于亡阳虚脱，肢冷脉微，心阳不足，胸痹心痛，虚寒吐泻，脘腹冷痛，肾阳虚衰，阳痿宫冷，阴寒水肿，阳虚外感，寒湿痹痛。', '附子是侗医治疗亡阳虚脱的急救药。传说古时侗寨有人虚脱昏迷，侗族药师用附子煎水灌服，患者转危为安。因附子有毒，侗医在用药前会严格炮制，确保用药安全。', '[{\"name\": \"fuzi1.jpg\", \"path\": \"images/plants/fuzi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"fuzi2.jpg\", \"path\": \"images/plants/fuzi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"【百草故事】“回阳救逆”第一品——附子.mp4\", \"path\": \"videos/plants/【百草故事】“回阳救逆”第一品——附子.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"四川江油\",\"贵州黔东南\",\"云南丽江\"]', 'hard', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682044, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：附子\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (45, '干姜', 'Ganl jiangl', 'Zingiber officinale', '根茎类', '内服', '栽培于温暖湿润的环境', '温中散寒，回阳通脉，温肺化饮。用于脘腹冷痛，呕吐泄泻，肢冷脉微，寒饮喘咳。', '干姜是侗族民间常用的温中药。侗家人常在冬季用干姜煲汤驱寒。传说古时侗寨有人脘腹冷痛，服用干姜后症状缓解。干姜也是侗族治疗寒饮喘咳的重要药材。', '[{\"name\": \"ganjiang1.jpg\", \"path\": \"images/plants/ganjiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"ganjiang2.jpg\", \"path\": \"images/plants/ganjiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"认识国药之干姜.mp4\", \"path\": \"videos/plants/认识国药之干姜.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"四川犍为\",\"云南罗平\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682045, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：干姜\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (46, '肉桂', 'Rouc guix', 'Cinnamomum cassia', '皮类', '内服', '生于常绿阔叶林中，但多为栽培', '补火助阳，引火归元，散寒止痛，温通经脉。用于阳痿宫冷，腰膝冷痛，肾虚作喘，眩晕目赤，心腹冷痛，虚寒吐泻，寒疝腹痛，痛经经闭。', '肉桂是侗医治疗肾阳虚的常用药。传说古时侗寨有人腰膝冷痛，服用肉桂后症状改善。肉桂也是侗族食疗的重要调料，常用于煲汤调味，既美味又养生。', '[{\"name\": \"rougui1.jpg\", \"path\": \"images/plants/rougui1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"rougui2.jpg\", \"path\": \"images/plants/rougui2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"每天学习认识一味中药材——肉桂.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——肉桂.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广西防城\",\"广东高要\",\"贵州黔东南\"]', 'medium', '2026-03-04 04:47:10', NULL, 3, 0, 1, '[{\"id\": 1773145682046, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：肉桂\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (48, '小茴香', 'Xiaox huix xangl', 'Foeniculum vulgare', '果实类', '内服', '栽培于园圃、田边，适应性极强', '散寒止痛，理气和胃。用于寒疝腹痛，睾丸偏坠，痛经，少腹冷痛，脘腹胀痛，食少吐泻。', '小茴香是侗族民间常用的温里药。侗家人常用小茴香作为调料，也用它治疗寒疝腹痛。传说古时侗寨有人患寒疝，服用小茴香后症状缓解。小茴香也是侗族治疗胃寒的常用药。', '[{\"name\": \"xiaohuixiang1.jpg\", \"path\": \"images/plants/xiaohuixiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"xiaohuixiang2.jpg\", \"path\": \"images/plants/xiaohuixiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"神奇中草药：小茴香的功效和作用-健康视频-搜狐视频.mp4\", \"path\": \"videos/plants/神奇中草药：小茴香的功效和作用-健康视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"山西太谷\",\"贵州黔东南\",\"甘肃民勤\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682048, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：小茴香\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (49, '丁香', 'Dingl xangl', 'Syzygium aromaticum', '花蕾类', '内服', '原产马来群岛及印度尼西亚，现我国广东、海南有栽培', '温中降逆，补肾助阳。用于脾胃虚寒，呃逆呕吐，食少吐泻，心腹冷痛，肾虚阳痿。', '丁香是侗医治疗呃逆的特效药。传说古时侗寨有人呃逆不止，服用丁香后呃逆停止。丁香也是侗族食疗的重要调料，常用于炖肉调味，既美味又温中。', '[{\"name\": \"dingxiang1.jpg\", \"path\": \"images/plants/dingxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dingxiang2.jpg\", \"path\": \"images/plants/dingxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"认识中草药——丁香-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/认识中草药——丁香-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广东广州\",\"海南万宁\",\"广西南宁\"]', 'medium', '2026-03-04 04:47:10', NULL, 8, 0, 1, '[{\"id\": 1773145682049, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：丁香\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (50, '高良姜', 'Gaol liangc jiangl', 'Alpinia officinarum', '根茎类', '内服', '生于山坡、疏林下，海拔100-800米', '温胃止呕，散寒止痛。用于脘腹冷痛，胃寒呕吐，嗳气吞酸。', '高良姜是侗族民间常用的温胃药。传说古时侗寨有人胃寒呕吐，服用高良姜后症状缓解。高良姜也是侗族治疗脘腹冷痛的重要药材，常与干姜配伍使用。', '[{\"name\": \"gaoliangjiang1.jpg\", \"path\": \"images/plants/gaoliangjiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"gaoliangjiang2.jpg\", \"path\": \"images/plants/gaoliangjiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"高良姜 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/高良姜 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广东徐闻\",\"海南万宁\",\"广西防城\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682050, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：高良姜\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (51, '花椒', 'Huax jiaol', 'Zanthoxylum bungeanum', '果实类', '内服', '生于山坡、路旁、灌丛中，海拔200-2500米', '温中止痛，杀虫止痒。用于脘腹冷痛，呕吐泄泻，虫积腹痛，蛔虫症，湿疹瘙痒。', '花椒是侗族民间最常见的调料和药材。侗家人常用花椒调味，也用它治疗脘腹冷痛。传说古时侗寨有人腹痛，服用花椒后症状缓解。花椒也是侗族治疗湿疹的常用药。', '[{\"name\": \"huajiao1.jpg\", \"path\": \"images/plants/huajiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huajiao2.jpg\", \"path\": \"images/plants/huajiao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"花椒的功效与作用.mp4\", \"path\": \"videos/plants/花椒的功效与作用.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"陕西韩城\",\"贵州黔东南\",\"四川汉源\"]', 'easy', '2026-03-04 04:47:10', NULL, 1, 0, 1, '[{\"id\": 1773145682051, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：花椒\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (52, '胡椒', 'Hux jiaol', 'Piper nigrum', '果实类', '内服', '原产东南亚，现我国海南、广东、广西有栽培', '温中散寒，下气，消痰。用于胃寒呕吐，腹痛泄泻，食欲不振，癫痫痰多。', '胡椒是侗族民间常用的调料和药材。侗家人常用胡椒调味，也用它治疗胃寒呕吐。传说古时侗寨有人胃寒呕吐，服用胡椒后症状缓解。胡椒也是侗族治疗癫痫的辅助药材。', '[{\"name\": \"hujiao1.jpg\", \"path\": \"images/plants/hujiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"hujiao2.jpg\", \"path\": \"images/plants/hujiao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药-胡椒.mp4\", \"path\": \"videos/plants/中药-胡椒.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"中药-胡椒.mp4\", \"path\": \"videos/plants/中药-胡椒.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"海南万宁\",\"广东湛江\",\"广西防城\"]', 'easy', '2026-03-04 04:47:10', NULL, 3, 0, 1, '[{\"id\": 1773145682052, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：胡椒\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (53, '延胡索', 'Yanc huf suox', 'Corydalis yanhusuo', '根茎类', '内服', '生于山地林下、灌丛中，海拔100-2000米', '活血，行气，止痛。用于胸胁、脘腹疼痛，胸痹心痛，经闭痛经，产后瘀阻，跌扑肿痛。', '延胡索是侗医治疗疼痛的特效药。传说古时侗寨有人胸胁疼痛，服用延胡索后疼痛消失。延胡索是侗族活血止痛的重要药材，被誉为\"止痛圣药\"。', '[{\"name\": \"yanhusuo1.jpg\", \"path\": \"images/plants/yanhusuo1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yanhusuo2.jpg\", \"path\": \"images/plants/yanhusuo2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"每天学习认识一味中药材——延胡索.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——延胡索.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"浙江东阳\",\"贵州黔东南\",\"四川都江堰\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682053, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：延胡索\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (54, '郁金', 'Yuv jinl', 'Curcuma aromatica', '根茎类', '内服', '生于山坡、林下、灌丛中，海拔100-2000米', '活血止痛，行气解郁，清心凉血，利胆退黄。用于胸胁刺痛，胸痹心痛，经闭痛经，乳房胀痛，热病神昏，癫痫发狂，血热吐衄，黄疸尿赤。', '郁金是侗医治疗黄疸的常用药。传说古时侗寨有人患黄疸，服用郁金后黄疸消退。郁金也是侗族治疗胸胁疼痛的重要药材，具有活血行气的功效。', '[{\"name\": \"yujin1.jpg\", \"path\": \"images/plants/yujin1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yujin2.jpg\", \"path\": \"images/plants/yujin2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药精讲——郁金，带药量的中药应用讲解。.mp4\", \"path\": \"videos/plants/中药精讲——郁金，带药量的中药应用讲解。.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"浙江瑞安\",\"贵州黔东南\",\"四川双流\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682054, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：郁金\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (55, '姜黄', 'Jiangl wangc', 'Curcuma longa', '根茎类', '内服', '生于向阳山坡、林下，海拔100-1500米', '破血行气，通经止痛。用于胸胁刺痛，胸痹心痛，痛经经闭，癥瘕，风湿肩臂疼痛，跌扑肿痛。', '姜黄是侗族民间常用的活血药。侗家人常用姜黄作为调料，也用它治疗胸胁疼痛。传说古时侗寨有人跌打损伤，服用姜黄后瘀血消散。姜黄也是侗族治疗风湿的重要药材。', '[{\"name\": \"jianghuang1.jpg\", \"path\": \"images/plants/jianghuang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jianghuang2.jpg\", \"path\": \"images/plants/jianghuang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"姜黄 一种传统古老的着色原料，也是药食同源的一种药材.mp4\", \"path\": \"videos/plants/姜黄 一种传统古老的着色原料，也是药食同源的一种药材.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"四川犍为\",\"贵州黔东南\",\"广东佛山\"]', 'easy', '2026-03-04 04:47:10', NULL, 3, 0, 1, '[{\"id\": 1773145682055, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：姜黄\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (56, '乳香', 'Rux xangl', 'Boswellia carterii', '树脂类', '内服', '产于索马里、埃塞俄比亚等地', '活血定痛，消肿生肌。用于胸痹心痛，胃脘疼痛，痛经经闭，产后瘀阻，癥瘕腹痛，风湿痹痛，筋脉拘挛，跌打损伤，痈肿疮疡。', '乳香是侗医治疗跌打损伤的常用药。传说古时侗寨有人跌打损伤，疼痛难忍。侗族药师用乳香配伍其他药物，患者服用后疼痛缓解。乳香也是侗族治疗风湿痹痛的重要药材。', '[{\"name\": \"ruxiang1.jpg\", \"path\": \"images/plants/ruxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"ruxiang2.jpg\", \"path\": \"images/plants/ruxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"乳香 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/乳香 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"进口药材\",\"广东广州\",\"广西南宁\"]', 'hard', '2026-03-04 04:47:10', NULL, 4, 1, 1, '[{\"id\": 1773145682056, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：乳香\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (57, '没药', 'Moc yaoc', 'Commiphora myrrha', '树脂类', '内服', '产于索马里、埃塞俄比亚等地', '散瘀定痛，消肿生肌。用于胸痹心痛，胃脘疼痛，痛经经闭，产后瘀阻，癥瘕腹痛，风湿痹痛，筋脉拘挛，跌打损伤，痈肿疮疡。', '没药是侗医治疗跌打损伤的常用药。传说古时侗寨有人跌打损伤，瘀血肿痛。侗族药师用没药配伍其他药物，患者服用后瘀血消散。没药常与乳香配伍使用，是侗族活血止痛的经典组合。', '[{\"name\": \"moyao1.jpg\", \"path\": \"images/plants/moyao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"moyao2.jpg\", \"path\": \"images/plants/moyao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"没药 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/没药 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"进口药材\",\"广东广州\",\"广西南宁\"]', 'hard', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682057, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：没药\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (58, '丹参', 'Danl senl', 'Salvia miltiorrhiza', '根茎类', '内服', '生于山坡、林下、溪边，海拔120-1300米', '活血祛瘀，通经止痛，清心除烦，凉血消痈。用于胸痹心痛，脘腹胁痛，癥瘕积聚，热痹疼痛，心烦不眠，月经不调，痛经经闭，疮疡肿痛。', '丹参是侗医治疗胸痹的常用药。传说古时侗寨有人胸痹心痛，服用丹参后症状缓解。丹参也是侗族治疗妇科疾病的重要药材，具有活血调经的功效。', '[{\"name\": \"danshen1.jpg\", \"path\": \"images/plants/danshen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"danshen2.jpg\", \"path\": \"images/plants/danshen2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"丹参.mp4\", \"path\": \"videos/plants/丹参.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"山东平邑\",\"贵州黔东南\",\"四川中江\"]', 'medium', '2026-03-04 04:47:10', NULL, 13, 0, 1, '[{\"id\": 1773145682058, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：丹参\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (59, '红花', 'Hongc faix', 'Carthamus tinctorius', '花类', '内服', '栽培于向阳、干燥的环境', '活血通经，散瘀止痛。用于经闭，痛经，恶露不行，癥瘕痞块，胸痹心痛，瘀滞腹痛，胸胁刺痛，跌扑损伤，疮疡肿痛。', '红花是侗族民间常用的活血药。侗家人常用红花治疗妇科疾病。传说古时侗寨有人痛经，服用红花后症状缓解。红花也是侗族治疗跌打损伤的重要药材。', '[{\"name\": \"honghua1.jpg\", \"path\": \"images/plants/honghua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"honghua2.jpg\", \"path\": \"images/plants/honghua2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"【百草故事】活血化瘀良药——红花.mp4\", \"path\": \"videos/plants/【百草故事】活血化瘀良药——红花.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"新疆塔城\",\"贵州黔东南\",\"河南新乡\"]', 'easy', '2026-03-04 04:47:10', NULL, 3, 0, 1, '[{\"id\": 1773145682059, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：红花\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (60, '桃仁', 'Taoc renl', 'Prunus persica', '种子类', '内服', '栽培于平原、丘陵地区', '活血祛瘀，润肠通便，止咳平喘。用于经闭痛经，癥瘕痞块，肺痈肠痈，跌打损伤，肠燥便秘，咳嗽气喘。', '桃仁是侗族民间常用的活血药。侗家人常用桃仁治疗妇科疾病。传说古时侗寨有人肠燥便秘，服用桃仁后症状缓解。桃仁也是侗族治疗跌打损伤的重要药材。', '[{\"name\": \"taoren1.jpg\", \"path\": \"images/plants/taoren1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"taoren2.jpg\", \"path\": \"images/plants/taoren2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"桃仁 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/桃仁 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"山东泰安\",\"贵州黔东南\",\"河北赞皇\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682060, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：桃仁\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (61, '益母草', 'Yiv mux caox', 'Leonurus japonicus', '全草类', '内服', '生于路旁、田边、荒地，分布极广', '活血调经，利尿消肿，清热解毒。用于月经不调，痛经经闭，恶露不尽，水肿尿少，疮疡肿毒。', '益母草是侗族妇女的常用药。传说古时侗寨一位妇女月经不调，服用益母草后症状改善。益母草是侗族治疗妇科疾病的重要药材，被誉为\"妇科圣药\"。', '[{\"name\": \"yimucao1.jpg\", \"path\": \"images/plants/yimucao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yimucao2.jpg\", \"path\": \"images/plants/yimucao2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药精讲：益母草.mp4\", \"path\": \"videos/plants/中药精讲：益母草.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"贵州黔东南\",\"河南禹州\",\"安徽亳州\"]', 'easy', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682061, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：益母草\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (62, '牛膝', 'Niuc xil', 'Achyranthes bidentata', '根茎类', '内服', '生于山坡林下、灌丛中，海拔200-1700米', '逐瘀通经，补肝肾，强筋骨，利尿通淋，引血下行。用于经闭，痛经，腰膝酸痛，筋骨无力，淋证，水肿，头痛，眩晕，牙痛，口疮，吐血，衄血。', '牛膝是侗医治疗腰膝酸痛的常用药。传说古时侗寨有人腰膝酸痛，服用牛膝后症状缓解。牛膝也是侗族治疗妇科疾病的重要药材，具有逐瘀通经的功效。', '[{\"name\": \"niuxi1.jpg\", \"path\": \"images/plants/niuxi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"niuxi2.jpg\", \"path\": \"images/plants/niuxi2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"牛膝（怀牛膝）深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/牛膝（怀牛膝）深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"河南武陟\",\"贵州黔东南\",\"河北安国\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682062, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：牛膝\", \"operator\": \"系统\"}]');
INSERT INTO `plants` VALUES (63, '鸡血藤', 'Jix xeeb tongc', 'Spatholobus suberectus', '藤本类', '内服', '生于山谷林下、灌丛中，攀援于树上', '活血补血，调经止痛，舒筋活络。用于月经不调，痛经，经闭，血虚萎黄，麻木瘫痪，风湿痹痛。', '鸡血藤是侗族妇女的常用药。传说古时侗寨一位妇女月经不调，服用鸡血藤后症状改善。鸡血藤是侗族治疗妇科疾病的重要药材，也是补血活血的佳品。', '[{\"name\": \"jixueteng1.jpg\", \"path\": \"images/plants/jixueteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jixueteng2.jpg\", \"path\": \"images/plants/jixueteng2.jpg\", \"size\": 0, \"type\": \"image\"}]', '[{\"name\": \"中药精讲：鸡血藤.mp4\", \"path\": \"videos/plants/中药精讲：鸡血藤.mp4\", \"size\": 0, \"type\": \"video\"}]', NULL, '[\"广西百色\",\"贵州黔东南\",\"云南文山\"]', 'medium', '2026-03-04 04:47:10', NULL, 2, 0, 1, '[{\"id\": 1773145682063, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：鸡血藤\", \"operator\": \"系统\"}]');
INSERT INTO `qa` VALUES (1, '侗药常识', '什么是侗族医药？', '侗族医药是侗族人民在长期的生产生活实践中，与疾病斗争中积累的医药知识和经验的总和。侗族医药具有鲜明的民族特色和地域特色，是中华民族传统医药的重要组成部分。侗族医药以草药为主，结合药浴、艾灸、推拿、拔罐等外治疗法，形成了独特的诊疗体系。', 256, '2026-03-04 04:47:10', NULL, 31, 2);
INSERT INTO `qa` VALUES (2, '侗药常识', '侗族医药有哪些特点？', '侗族医药具有以下特点：1.以草药为主，善用药浴、艾灸等外治疗法；2.注重整体观念，强调人与自然的和谐统一；3.诊疗方法独特，有望、闻、问、切四诊；4.药物来源广泛，多采用当地野生药材；5.传承方式以口传心授为主；6.具有鲜明的民族文化和地域特色。', 238, '2026-03-04 04:47:10', NULL, 6, 2);
INSERT INTO `qa` VALUES (3, '侗药常识', '侗族常用的药材有哪些？', '侗族常用药材包括：钩藤（清热平肝）、透骨草（祛风除湿）、九节茶（活血消斑）、八角莲（清热解毒）、七叶一枝花（消肿止痛）、血藤（补血活血）、杜仲（补肝肾）、黄精（补气养阴）、金银花（清热解毒）、艾叶（温经止血）等。这些药材多生长在侗族聚居区，是侗医临床常用的道地药材。', 245, '2026-03-04 04:47:10', NULL, 10, 0);
INSERT INTO `qa` VALUES (4, '侗药常识', '侗族药浴有什么功效？', '侗族药浴具有以下功效：1.祛风除湿，治疗风湿痹痛；2.活血化瘀，促进血液循环；3.舒筋活络，缓解肌肉酸痛；4.清热解毒，治疗皮肤病；5.养生保健，增强体质。侗族药浴是侗族传统疗法的重要组成部分，通过药物煎汤浸泡全身或局部，达到防治疾病的目的。', 267, '2026-03-04 04:47:10', NULL, 12, 1);
INSERT INTO `qa` VALUES (5, '侗医疗法', '侗族艾灸疗法如何操作？', '侗族艾灸疗法的操作步骤：1.选取穴位：根据病情选择相应穴位，如关元、气海、三阴交等；2.准备艾条：将艾叶制成艾条或艾柱；3.点燃艾条：点燃艾条一端；4.熏灼穴位：将艾条对准穴位，距离皮肤2-3cm，以患者感觉温热舒适为度；5.控制时间：每次15-20分钟；6.注意事项：防止烫伤，灸后保暖。', 198, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `qa` VALUES (6, '侗医疗法', '侗族推拿疗法有哪些手法？', '侗族推拿疗法常用的手法包括：1.推法：用指腹或掌根沿经络方向推动；2.拿法：用拇指和食指捏拿肌肉；3.按法：用指腹或掌根按压穴位；4.摩法：用手掌在体表做环形摩擦；5.揉法：用指腹或掌根做环形揉动；6.捏法：用拇指和食指捏起皮肤。这些手法可单独使用，也可配合使用。', 187, '2026-03-04 04:47:10', NULL, 1, 0);
INSERT INTO `qa` VALUES (7, '侗医疗法', '侗族如何治疗风湿骨痛？', '侗族治疗风湿骨痛的方法：1.药浴疗法：用透骨草、艾叶、钩藤等药物煎汤浸泡；2.艾灸疗法：艾灸患处及相关穴位；3.推拿疗法：运用推、拿、按、摩等手法治疗；4.内服药物：服用九节茶、血藤、杜仲等药物；5.拔罐疗法：在患处拔罐祛风除湿；6.熏蒸疗法：用药物蒸汽熏蒸患处。多种方法配合使用效果更佳。', 223, '2026-03-04 04:47:10', NULL, 2, 0);
INSERT INTO `qa` VALUES (8, '侗医疗法', '侗族如何治疗跌打损伤？', '侗族治疗跌打损伤的方法：1.外敷药物：用透骨草、八角莲、七叶一枝花等捣烂外敷；2.内服药物：服用活血化瘀的药物；3.推拿疗法：运用推拿手法舒筋活络；4.拔罐疗法：在患处拔罐活血化瘀；5.药浴疗法：用药物煎汤浸泡患处；6.正骨手法：对骨折脱臼进行复位。严重者需及时就医。', 212, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (9, '侗医疗法', '侗族如何治疗妇科疾病？', '侗族治疗妇科疾病的方法：1.艾灸疗法：艾灸关元、气海、三阴交等穴位；2.药浴疗法：用艾叶、血藤等药物煎汤坐浴；3.内服药物：服用血藤、艾叶、杜仲等药物；4.熏蒸疗法：用药物蒸汽熏蒸；5.推拿疗法：运用推拿手法调理气血；6.食疗调理：配合药膳食疗。侗族妇科疗法对产后调理、月经不调有显著疗效。', 201, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (10, '侗医疗法', '侗族如何治疗小儿疾病？', '侗族治疗小儿疾病的方法：1.小儿推拿：运用推、揉、捏、拿等手法作用于特定穴位；2.药浴疗法：用温和药物煎汤洗浴；3.敷贴疗法：将药物敷贴于特定部位；4.内服药物：服用温和的药物煎剂；5.食疗调理：配合食疗调理脾胃；6.艾灸疗法：艾灸特定穴位。侗族儿科疗法对小儿发热、咳嗽、消化不良有良好疗效。', 195, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (11, '文化背景', '侗族医药的历史渊源是什么？', '侗族医药历史悠久，起源可追溯到侗族先民的原始医疗活动。侗族先民在长期的生产生活中，通过观察动物自救行为、尝试各种植物，逐渐积累了医药知识。经过代代相传，形成了独特的侗族医药体系。侗族医药与侗族的宗教信仰、生活习俗密切相关，是侗族文化的重要组成部分。', 178, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (12, '文化背景', '侗族医药如何传承？', '侗族医药的传承方式主要有：1.家族传承：父传子、母传女，代代相传；2.师徒传承：拜师学艺，口传心授；3.社区传承：在侗族社区中通过实践学习；4.文献传承：通过侗族古歌、传说等形式传承医药知识。近年来，政府大力支持侗族医药的传承发展，建立了传承人制度，开设了侗医药培训班，使侗族医药得到更好的保护和传承。', 186, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (13, '文化背景', '侗族医药有哪些文化内涵？', '侗族医药蕴含丰富的文化内涵：1.天人合一的整体观念；2.阴阳平衡的哲学思想；3.预防为主的养生理念；4.药食同源的饮食文化；5.敬畏自然的生态意识；6.团结互助的社区精神。侗族医药不仅是一种医疗技术，更是侗族文化的重要载体，体现了侗族人民的智慧和哲学思想。', 169, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (14, '文化背景', '侗族医药的现状如何？', '目前侗族医药面临机遇与挑战并存的局面。机遇方面：国家大力支持民族医药发展，侗族医药被列入非物质文化遗产保护名录，传承人得到认定和资助。挑战方面：年轻一代对侗族医药兴趣不足，传承人老龄化严重，部分传统疗法面临失传风险。需要加强保护传承，推动侗族医药创新发展。', 172, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (15, '文化背景', '如何学习和了解侗族医药？', '学习和了解侗族医药的途径：1.阅读侗族医药相关书籍和文献；2.参观侗族医药博物馆和文化展览；3.参加侗族医药培训班和讲座；4.拜访侗族医药传承人，拜师学艺；5.深入侗族地区，实地考察学习；6.关注侗族医药相关的网站和公众号。建议从基础知识学起，循序渐进，理论与实践相结合。', 165, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (16, '侗药常识', '侗族药材如何采集和炮制？', '侗族药材采集讲究时节和方法：1.根茎类药材多在秋冬季节采集；2.全草类药材多在花期采集；3.花叶类药材多在春夏采集；4.果实类药材在成熟时采集。炮制方法包括：晒干、阴干、炒制、蒸制、酒制、醋制等。侗族认为正确的采集和炮制方法能保证药材质量，提高疗效。', 189, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (17, '侗医疗法', '侗族拔罐疗法如何操作？', '侗族拔罐疗法的操作步骤：1.患者取舒适体位，暴露治疗部位；2.选择拔罐部位，清洁皮肤；3.准备竹罐或玻璃罐；4.用火燃烧法或抽气法产生负压；5.将罐吸附于皮肤上；6.留罐10-15分钟；7.取罐时先按压皮肤，使空气进入，再取下罐子。注意：皮肤破损、孕妇腹部不宜拔罐。', 176, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (18, '侗医疗法', '侗族熏蒸疗法如何操作？', '侗族熏蒸疗法的操作步骤：1.准备药物：艾叶、透骨草、钩藤等；2.加水煎煮，产生蒸汽；3.患者取坐位或卧位，暴露治疗部位；4.用蒸汽熏蒸患处，距离以患者感觉温热舒适为度；5.每次熏蒸20-30分钟；6.熏蒸后擦干保暖。注意：防止烫伤，心脏病患者慎用。', 182, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (19, '侗药常识', '侗族药材如何保存？', '侗族药材保存方法：1.干燥保存：将药材晒干或阴干，置于干燥通风处；2.密封保存：将干燥药材装入密封容器，防止受潮；3.防虫保存：在药材中放入花椒、大蒜等防虫；4.冷藏保存：部分鲜药可冷藏保存；5.定期检查：定期检查药材，发现霉变及时处理。正确的保存方法能保证药材质量，延长保存期限。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (20, '文化背景', '侗族医药与现代医学如何结合？', '侗族医药与现代医学结合的方式：1.运用现代科技研究侗族药材的有效成分；2.用现代医学理论解释侗族医药的作用机理；3.将侗族传统疗法与现代诊疗技术相结合；4.开发侗族医药新产品，如侗药制剂、保健品等；5.建立侗族医药与现代医学结合的诊疗模式。这种结合既能传承侗族医药精华，又能提高诊疗效果。', 175, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (21, '侗药常识', '钩藤有什么功效和用途？', '钩藤具有清热平肝、息风定惊的功效。主要用于治疗：1.头痛眩晕；2.感冒夹惊；3.惊痫抽搐；4.妊娠子痫；5.高血压引起的头晕头痛。侗族民间常用钩藤治疗小儿惊风，效果显著。用法：煎汤内服，常用量10-15g。注意事项：不宜久煎，一般后下。', 198, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (22, '侗药常识', '透骨草有什么功效和用途？', '透骨草具有祛风除湿、舒筋活血、止痛的功效。主要用于治疗：1.风湿痹痛；2.筋骨挛缩；3.寒湿脚气；4.疮癣肿毒；5.跌打损伤。侗族民间常用透骨草治疗跌打损伤和风湿疼痛，可内服也可外用。用法：煎汤内服或捣烂外敷，常用量15-30g。', 185, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (23, '侗药常识', '八角莲有什么功效和用途？', '八角莲具有清热解毒、化痰散结、祛瘀消肿的功效。主要用于治疗：1.痈肿疔疮；2.瘰疬；3.咽喉肿痛；4.跌打损伤；5.毒蛇咬伤。八角莲是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。用法：煎汤内服或捣烂外敷。注意：八角莲有毒，需在医师指导下使用。', 192, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (24, '侗药常识', '天麻有什么功效和用途？', '天麻具有息风止痉、平抑肝阳、祛风通络的功效。主要用于治疗：1.肝风内动，惊痫抽搐；2.眩晕头痛；3.肢体麻木；4.手足不遂；5.风湿痹痛。天麻是贵州道地药材，侗族民间常用天麻治疗头晕头痛。用法：煎汤内服或研末冲服，常用量3-10g。', 178, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (25, '侗药常识', '金银花有什么功效和用途？', '金银花具有清热解毒、疏散风热的功效。主要用于治疗：1.痈肿疔疮；2.喉痹；3.丹毒；4.热毒血痢；5.风热感冒；6.温病发热。金银花是侗族民间常用的清热解毒药，每年春夏之交采摘晒干备用。用法：煎汤内服或泡茶饮用，常用量10-30g。', 186, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (26, '侗药常识', '艾叶有什么功效和用途？', '艾叶具有温经止血、散寒止痛、祛湿止痒的功效。主要用于治疗：1.吐血、衄血、崩漏；2.月经过多；3.胎漏下血；4.少腹冷痛；5.经寒不调；6.宫冷不孕。艾叶是侗族艾灸疗法的主要材料，也是药浴的重要药材。用法：煎汤内服、外用熏洗或艾灸，常用量3-10g。', 195, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (27, '侗药常识', '杜仲有什么功效和用途？', '杜仲具有补肝肾、强筋骨、安胎的功效。主要用于治疗：1.肾虚腰痛；2.筋骨无力；3.妊娠漏血；4.胎动不安；5.高血压。杜仲是贵州道地药材，侗族民间常用杜仲治疗腰膝酸痛。用法：煎汤内服或泡酒服用，常用量6-10g。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (28, '侗药常识', '黄精有什么功效和用途？', '黄精具有补气养阴、健脾、润肺、益肾的功效。主要用于治疗：1.脾胃气虚，体倦乏力；2.胃阴不足，口干食少；3.肺虚燥咳；4.精血不足，腰膝酸软。黄精是侗族常用的滋补药，也是侗族食疗的重要材料。用法：煎汤内服或煲汤食用，常用量9-15g。', 172, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (29, '侗药常识', '血藤有什么功效和用途？', '血藤具有补血、活血、通络的功效。主要用于治疗：1.月经不调；2.血虚萎黄；3.麻木瘫痪；4.风湿痹痛。血藤是侗族妇女的常用药，侗族民间常用血藤治疗妇科疾病和风湿疼痛。用法：煎汤内服或泡酒服用，常用量10-30g。', 165, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (30, '侗医疗法', '侗族药浴疗法有什么禁忌？', '侗族药浴疗法的禁忌：1.孕妇慎用，部分药材可能影响胎儿；2.月经期妇女不宜全身药浴；3.严重心脏病、高血压患者慎用；4.皮肤破损、溃烂处不宜药浴；5.饭后不宜立即药浴，应间隔1-2小时；6.药浴时间不宜过长，一般20-30分钟；7.药浴后应及时擦干保暖，避免受凉。', 188, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (31, '侗医疗法', '侗族艾灸疗法有什么禁忌？', '侗族艾灸疗法的禁忌：1.孕妇腹部、腰骶部不宜艾灸；2.高热患者不宜艾灸；3.皮肤破损、溃烂处不宜艾灸；4.阴虚火旺者慎用；5.大血管处、心脏部位不宜艾灸；6.艾灸后不宜立即洗澡，应间隔2-3小时；7.艾灸时应注意防止烫伤，保持适当距离。', 176, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (32, '侗医疗法', '侗族推拿疗法有什么禁忌？', '侗族推拿疗法的禁忌：1.急性传染病、高热患者不宜推拿；2.皮肤破损、溃烂处不宜推拿；3.骨折、脱臼未复位者不宜推拿；4.孕妇腹部、腰骶部不宜推拿；5.严重心脏病、高血压患者慎用；6.饭后不宜立即推拿，应间隔1-2小时；7.推拿力度应适中，不宜过重。', 169, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (33, '侗医疗法', '侗族拔罐疗法有什么禁忌？', '侗族拔罐疗法的禁忌：1.孕妇腹部、腰骶部不宜拔罐；2.皮肤破损、溃烂处不宜拔罐；3.高热患者不宜拔罐；4.严重心脏病、高血压患者慎用；5.有出血倾向者不宜拔罐；6.拔罐时间不宜过长，一般10-15分钟；7.拔罐后不宜立即洗澡，应间隔2-3小时。', 172, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (34, '侗医疗法', '侗族熏蒸疗法有什么禁忌？', '侗族熏蒸疗法的禁忌：1.孕妇慎用，高温可能影响胎儿；2.严重心脏病、高血压患者慎用；3.高热患者不宜熏蒸；4.皮肤破损、溃烂处不宜熏蒸；5.熏蒸时间不宜过长，一般20-30分钟；6.熏蒸时应注意防止烫伤，保持适当距离；7.熏蒸后应及时擦干保暖，避免受凉。', 165, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (35, '侗医疗法', '侗族如何治疗感冒？', '侗族治疗感冒的方法：1.内服药物：服用金银花、鱼腥草、车前草等清热解毒药物；2.药浴疗法：用艾叶、金银花等药物煎汤洗浴；3.刮痧疗法：刮拭背部经络祛风解表；4.艾灸疗法：艾灸大椎、风池等穴位；5.食疗调理：多饮温水，食用清淡易消化食物；6.注意休息，避免过度劳累。', 198, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (36, '侗医疗法', '侗族如何治疗咳嗽？', '侗族治疗咳嗽的方法：1.内服药物：服用半夏、茯苓、鱼腥草等化痰止咳药物；2.药浴疗法：用艾叶、金银花等药物煎汤熏蒸；3.艾灸疗法：艾灸肺俞、定喘等穴位；4.推拿疗法：推拿胸部和背部经络；5.食疗调理：食用梨、蜂蜜等润肺食物；6.注意保暖，避免受凉。', 186, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (37, '侗医疗法', '侗族如何治疗胃痛？', '侗族治疗胃痛的方法：1.内服药物：服用吴茱萸、高良姜、陈皮等温胃止痛药物；2.艾灸疗法：艾灸中脘、足三里等穴位；3.推拿疗法：推拿腹部经络；4.药浴疗法：用艾叶、吴茱萸等药物煎汤熏蒸；5.食疗调理：少食多餐，忌食生冷油腻；6.保持心情舒畅，避免过度劳累。', 178, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (38, '侗医疗法', '侗族如何治疗失眠？', '侗族治疗失眠的方法：1.内服药物：服用茯苓、何首乌、天麻等养心安神药物；2.艾灸疗法：艾灸神门、三阴交等穴位；3.推拿疗法：推拿头部和背部经络；4.药浴疗法：用艾叶、茯苓等药物煎汤泡脚；5.食疗调理：睡前饮用温牛奶或蜂蜜水；6.保持心情舒畅，睡前避免剧烈活动。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (39, '侗医疗法', '侗族如何治疗高血压？', '侗族治疗高血压的方法：1.内服药物：服用钩藤、天麻、菊花等平肝降压药物；2.药浴疗法：用钩藤、菊花等药物煎汤泡脚；3.艾灸疗法：艾灸足三里、太冲等穴位；4.推拿疗法：推拿头部和背部经络；5.食疗调理：低盐饮食，多食蔬菜水果；6.保持心情舒畅，定期监测血压。', 175, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (40, '文化背景', '侗族医药的哲学思想是什么？', '侗族医药的哲学思想包括：1.天人合一的整体观念：认为人与自然是一个整体，疾病的发生与自然环境密切相关；2.阴阳平衡的哲学思想：认为人体健康取决于阴阳平衡，疾病是阴阳失调的表现；3.预防为主的养生理念：强调\"治未病\"，注重养生保健；4.药食同源的饮食文化：认为食物和药物同源，食疗是治病养生的重要方法。', 182, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (41, '文化背景', '侗族医药与中医有什么区别？', '侗族医药与中医的区别：1.理论体系：中医有完整的理论体系，侗族医药理论相对朴素；2.诊断方法：中医有四诊八纲，侗医有望闻问切；3.治疗方法：中医方法多样，侗医以外治法见长；4.药物来源：中医用药广泛，侗医多用当地野生药材；5.传承方式：中医有系统的教育体系，侗医以口传心授为主；6.文化背景：中医受儒家文化影响，侗医受侗族文化影响。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (42, '文化背景', '侗族医药的保护措施有哪些？', '侗族医药的保护措施：1.列入非物质文化遗产保护名录；2.认定和保护传承人；3.建立侗族医药博物馆和文化展览馆；4.开展侗族医药培训和教育活动；5.整理出版侗族医药文献资料；6.支持侗族医药科研和开发；7.建立侗族医药保护区和种植基地。这些措施有助于保护和传承侗族医药文化。', 175, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (43, '文化背景', '侗族医药的发展前景如何？', '侗族医药的发展前景广阔：1.国家政策支持民族医药发展；2.人们对传统医药的需求增加；3.现代科技为侗族医药研究提供新方法；4.侗族医药产业化发展潜力巨大；5.侗族医药文化旅游兴起；6.国际社会对传统医药的关注度提高。同时，侗族医药也面临传承人老龄化、年轻一代兴趣不足等挑战，需要加强保护和传承。', 172, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (44, '侗药常识', '侗族药材如何鉴别真伪？', '侗族药材鉴别真伪的方法：1.外观鉴别：观察药材的形状、大小、颜色、质地等特征；2.气味鉴别：闻药材的气味，真品有特殊香气；3.味道鉴别：尝药材的味道，真品有特定味道；4.水试鉴别：将药材放入水中观察变化；5.火试鉴别：用火烧药材观察变化；6.经验鉴别：传承人的经验判断。建议到正规渠道购买药材，避免购买假冒伪劣产品。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (45, '侗药常识', '侗族药材如何配伍使用？', '侗族药材配伍使用的原则：1.君臣佐使：主药为君，辅药为臣，佐药为佐，引药为使；2.相须相使：性能相似的药物配伍可增强疗效；3.相畏相杀：一种药物可减轻另一种药物的毒性；4.相反相恶：某些药物配伍会产生不良反应，应避免；5.剂量配比：根据病情和药物性能确定剂量配比。侗族药师在长期实践中积累了丰富的配伍经验。', 175, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (46, '侗药常识', '侗族药材有哪些常用剂型？', '侗族药材常用剂型：1.汤剂：将药物加水煎煮，取汁服用；2.散剂：将药物研成粉末，冲服或外敷；3.丸剂：将药物粉末加蜜或水制成丸剂；4.酒剂：将药物浸泡在白酒中，取酒服用；5.膏剂：将药物煎熬浓缩成膏；6.熏蒸剂：将药物加水煎煮，用蒸汽熏蒸；7.药浴剂：将药物加水煎煮，用于洗浴。不同剂型适用于不同病症。', 168, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (47, '侗药常识', '侗族药材的用量如何确定？', '侗族药材用量的确定原则：1.根据药物性能：毒性大的药物用量小，毒性小的药物用量大；2.根据病情轻重：病情重用量大，病情轻用量小；3.根据患者体质：体质强者用量可大，体质弱者用量宜小；4.根据患者年龄：成人用量大，儿童用量小；5.根据配伍关系：单味药用量大，复方中用量小；6.根据季节气候：夏季用量宜小，冬季用量可大。侗族药师在长期实践中积累了丰富的用量经验。', 165, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (48, '侗药常识', '侗族药材有哪些注意事项？', '侗族药材使用的注意事项：1.辨证用药：根据病情选择合适的药物；2.注意用量：严格按照规定用量使用，不宜过量；3.注意禁忌：孕妇、儿童、老人等特殊人群用药需谨慎；4.注意配伍：避免相反相恶的药物配伍；5.注意炮制：部分药材需炮制后使用；6.注意保存：正确保存药材，防止霉变虫蛀；7.注意疗程：按照疗程用药，不宜长期服用。建议在医师指导下使用。', 172, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (49, '侗医疗法', '侗医药线点灸疗法是什么？', '药线点灸是侗族独特的灸法，以浸泡药液的苎麻线点燃后快速点灸穴位，兼具药物与温热双重作用。操作时将药线点燃，快速点灸患处或穴位，每穴点灸3-5次，以皮肤微红为度。此法对风湿骨痛、关节僵硬有显著疗效，是侗医外治法的特色之一。', 155, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (50, '侗医疗法', '侗医角吸疗法如何操作？', '角吸疗法是侗族传统拔罐的变体，使用黄牛角作为吸具。操作时将牛角尖端磨平，内壁涂茶油，点燃酒精棉球放入角内，迅速扣在患处，利用负压吸附皮肤，留置10-15分钟后取下。角吸疗法具有祛风散寒、活血通络的功效，常用于治疗风湿痹痛。', 148, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (51, '侗医疗法', '侗医刮痧疗法有什么特点？', '侗医刮痧疗法使用牛角刮板配合茶油或姜汁，在体表特定部位刮拭，使皮肤出现红色粟粒状出血点（出痧），达到疏通经络、清热解毒的功效。侗医刮痧的特点是使用茶油或姜汁作为润滑介质，茶油可润肤活血，姜汁可温经散寒，增强刮痧疗效。', 152, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (52, '侗医疗法', '侗医熏蒸疗法适用于哪些疾病？', '侗医熏蒸疗法利用药物煎煮产生的蒸汽熏蒸患处，通过皮肤吸收药力，达到祛风除湿、温经散寒的效果。适用于：1.风湿性关节炎；2.肩周炎；3.腰肌劳损；4.风寒感冒；5.皮肤瘙痒等。熏蒸温度以患者感觉温热舒适为度，每次20-30分钟。', 160, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (53, '文化背景', '侗族医药的\"三气\"理论是什么？', '侗医\"三气\"理论认为天气、地气、人气三者相互影响，人体疾病的发生与三气失调密切相关。天气指气候环境对人体的影响，地气指地理水土对人体的影响，人气指人体自身的气血运行状态。侗医强调三气调和则身体健康，三气失调则疾病丛生，这是侗医独特的理论体系。', 145, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (54, '文化背景', '侗族医药的\"歌诀传承\"是什么？', '侗族医药的\"歌诀传承\"是将药方、疗法、诊断经验编成歌谣口诀，便于记忆和口耳相传。这种传承方式是侗医在无文字记录条件下保存医药知识的重要手段，歌诀内容涵盖药材识别、配伍禁忌、诊疗方法等，是侗医独特的知识传承方式。', 140, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (55, '文化背景', '侗族医药中\"冷骨风\"是什么病？', '\"冷骨风\"是侗族医药对风湿性关节炎的侗语称谓，因患者自觉骨节冷痛如风吹而得名，是侗医常见病证。侗医认为此病多因风寒湿邪侵袭关节，气血运行不畅所致，治疗以祛风散寒、除湿通络为主，常用药浴、熏蒸、火针等外治法配合内服药物。', 138, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (56, '侗医疗法', '侗医\"药引子\"是什么？', '\"药引子\"是侗族医药的特色概念，指在方剂中加入特定药材作为引导，使药力直达病所，增强整体疗效。例如治疗头痛用川芎为引，治疗腰痛用牛膝为引，治疗上肢用桂枝为引。药引子体现了侗医\"引经报使\"的用药智慧。', 150, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (57, '侗药常识', '九节茶在侗医中有什么用途？', '九节茶具有清热解毒、祛风通络、活血止痛的功效，侗医常用于治疗风湿关节痛、跌打损伤、疮疡肿毒等症。九节茶在侗族地区分布广泛，是侗医常用草药之一，既可内服也可外用。', 135, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (58, '侗药常识', '蛇不过（杠板归）在侗医中有什么功效？', '蛇不过（杠板归）具有清热解毒、利湿退黄、消肿散瘀的功效，侗医常用于治疗蛇虫咬伤、湿热黄疸、痢疾、湿疹等症。此药因蛇遇到此草会绕行而得名，在侗族山区是治疗蛇伤的常用草药。', 130, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (59, '文化背景', '侗族医药的\"摸诊\"是什么？', '\"摸诊\"是侗族医药特色诊断方法，通过触摸患处检查其形态变化、皮肤温度、压痛程度等来判断病情。摸诊是侗医\"望闻问切摸\"五诊之一，特别在骨伤科和外科疾病的诊断中具有重要价值，传承人凭手感即可判断骨折类型和软组织损伤程度。', 142, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (60, '侗医疗法', '侗族药浴的药液如何制备？', '侗族药浴的药液制备方法是先将药材加水煎煮30-40分钟，取药汁兑入浴水中，使药效充分释放。常用药材包括艾叶、透骨草、钩藤等。药浴水温控制在40-45℃，浸泡时间20-30分钟，以夏季最为盛行，因夏季毛孔开泄，药力更易渗透。', 155, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (61, '侗医疗法', '侗医推拿治疗小儿积食常用哪些手法？', '侗医推拿治疗小儿积食常用推三关、揉中脘、摩腹等手法配合使用。推三关可温阳散寒，揉中脘可健脾和胃，摩腹可消食导滞。三种手法配合起到健脾和胃、消食导滞的效果，是侗医儿科的特色疗法。', 128, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (62, '文化背景', '侗族医药的寒热辨证有什么特点？', '侗族医药的寒热辨证在中医基础上更注重南方山区多湿多雾的地域特点，强调湿邪致病的特殊性。侗医认为南方山区湿气重，疾病多夹湿邪，因此辨证时特别关注湿邪与寒热的兼夹关系，治疗时注重祛湿与清热/散寒的配合。', 136, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (63, '侗药常识', '土茯苓在侗医中有什么用途？', '土茯苓具有解毒除湿、通利关节的功效，侗医常用于治疗梅毒、汞中毒、湿热淋浊、筋骨挛痛等症。土茯苓在侗族地区是治疗湿热疮毒的常用药，既可内服也可外洗。', 125, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (64, '侗医疗法', '侗族拔罐疗法常配合什么一起使用？', '侗族拔罐疗法常配合药酒擦涂患处使用，药酒活血通络，拔罐祛风散寒，两者配合疗效更佳。操作时先用药酒擦涂患处，再进行拔罐，拔罐后再次擦涂药酒，形成\"药酒-拔罐-药酒\"的三步疗法。', 132, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `qa` VALUES (65, '文化背景', '侗族医药保护面临哪些挑战？', '侗族医药保护面临的主要挑战：1.传承人老龄化严重，年轻一代学习意愿不足；2.口传心授的传承方式导致知识流失风险高；3.部分药材资源因过度采挖而减少；4.现代医学冲击使传统医药使用率下降；5.缺乏标准化数字化归档；6.知识产权保护不足。需要通过数字化保护、传承人培养、药材资源保护等多方面措施加以应对。', 148, '2026-03-04 04:47:10', NULL, 0, 0);
INSERT INTO `quiz_questions` VALUES (1, '钩藤的主要功效是什么？', '[\"清热平肝，息风定惊\", \"补气养血，健脾益肺\", \"滋阴补肾，益精填髓\", \"活血化瘀，通络止痛\"]', '清热平肝，息风定惊', '侗药常识', 'easy', 'A', '钩藤具有清热平肝、息风定惊的功效，常用于治疗头痛眩晕、惊痫抽搐、妊娠子痫等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (2, '侗族药浴疗法的主要功效不包括以下哪项？', '[\"祛风除湿\", \"活血化瘀\", \"清热解毒\", \"滋阴补肾\"]', '滋阴补肾', '侗医疗法', 'easy', 'D', '侗族药浴疗法主要功效包括祛风除湿、活血化瘀、舒筋活络、清热解毒等，滋阴补肾不是其主要功效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (3, '八角莲在侗医中主要用于治疗什么疾病？', '[\"感冒发热\", \"毒蛇咬伤\", \"消化不良\", \"失眠多梦\"]', '毒蛇咬伤', '侗药常识', 'easy', 'B', '八角莲具有清热解毒、化痰散结的功效，是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (4, '侗族艾灸疗法常用的穴位不包括以下哪个？', '[\"关元穴\", \"气海穴\", \"三阴交穴\", \"太阳穴\"]', '太阳穴', '侗医疗法', 'easy', 'D', '侗族艾灸疗法常用穴位包括关元、气海、三阴交等，太阳穴一般不用于艾灸。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (5, '以下哪种药材具有补血活血的功效？', '[\"钩藤\", \"透骨草\", \"血藤\", \"金银花\"]', '血藤', '侗药常识', 'easy', 'C', '血藤具有补血、活血、通络的功效，常用于治疗月经不调、血虚萎黄、风湿痹痛等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (6, '侗族医药的主要传承方式是什么？', '[\"学校教育\", \"书籍传承\", \"口传心授\", \"网络学习\"]', '口传心授', '文化背景', 'easy', 'C', '侗族医药的主要传承方式是口传心授，包括家族传承、师徒传承等形式。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (7, '天麻的主要功效是什么？', '[\"清热解毒\", \"息风止痉，平抑肝阳\", \"补气养血\", \"健脾益肺\"]', '息风止痉，平抑肝阳', '侗药常识', 'easy', 'B', '天麻具有息风止痉、平抑肝阳、祛风通络的功效，常用于治疗眩晕头痛、惊痫抽搐、肢体麻木等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (8, '侗族药浴的水温一般控制在多少度？', '[\"30-35℃\", \"40-45℃\", \"50-55℃\", \"60℃以上\"]', '40-45℃', '侗医疗法', 'easy', 'B', '侗族药浴的水温一般控制在40-45℃，温度过高容易烫伤，过低则影响药效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (9, '以下哪种药材是侗医治疗蛇伤的要药？', '[\"钩藤\", \"透骨草\", \"八角莲\", \"金银花\"]', '八角莲', '侗药常识', 'easy', 'C', '八角莲具有清热解毒、化痰散结的功效，是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (10, '侗族医药主要分布在哪些地区？', '[\"西藏地区\", \"侗族聚居区（贵州、广西、湖南）\", \"东北地区\", \"华北地区\"]', '侗族聚居区（贵州、广西、湖南）', '文化背景', 'easy', 'B', '侗族医药主要分布在侗族聚居区，包括贵州黔东南、广西三江、湖南通道等地。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (11, '艾叶在侗医中的主要用途不包括？', '[\"艾灸疗法\", \"药浴疗法\", \"治疗风湿\", \"治疗糖尿病\"]', '治疗糖尿病', '侗医疗法', 'easy', 'D', '艾叶在侗医中主要用于艾灸疗法、药浴疗法、治疗风湿等，不是治疗糖尿病的主要药物。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (12, '七叶一枝花的主要功效是什么？', '[\"清热解毒，消肿止痛\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]', '清热解毒，消肿止痛', '侗药常识', 'easy', 'A', '七叶一枝花具有清热解毒、消肿止痛、凉肝定惊的功效，常用于治疗疔疮痈肿、蛇虫咬伤等。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (13, '侗族医药被列入哪一级非物质文化遗产？', '[\"县级\", \"市级\", \"省级\", \"国家级\"]', '国家级', '文化背景', 'easy', 'D', '侗族医药已被列入国家级非物质文化遗产名录，是中华民族传统医药的重要组成部分。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (14, '以下哪种药材具有清热解毒的功效？', '[\"杜仲\", \"血藤\", \"金银花\", \"黄精\"]', '金银花', '侗药常识', 'easy', 'C', '金银花具有清热解毒、疏散风热的功效，常用于治疗痈肿疔疮、喉痹、热毒血痢等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (15, '侗医治疗跌打损伤常用的药材组合是？', '[\"钩藤+天麻\", \"透骨草+八角莲+七叶一枝花\", \"金银花+艾叶\", \"杜仲+黄精\"]', '透骨草+八角莲+七叶一枝花', '侗医疗法', 'hard', 'B', '侗医治疗跌打损伤常用透骨草、八角莲、七叶一枝花等药材组合，具有活血化瘀、消肿止痛的功效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (16, '鱼腥草在侗族地区的用途是？', '[\"仅作药用\", \"仅作食用\", \"药食两用\", \"观赏植物\"]', '药食两用', '侗药常识', 'easy', 'C', '鱼腥草在侗族地区既是常见野菜，也是清热解毒的药材，是典型的药食两用植物。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (17, '侗族艾灸疗法的操作距离是？', '[\"直接接触皮肤\", \"距离皮肤2-3cm\", \"距离皮肤10cm\", \"距离皮肤20cm\"]', '距离皮肤2-3cm', '侗医疗法', 'easy', 'B', '侗族艾灸疗法操作时，艾条点燃后对准穴位，距离皮肤2-3cm，以患者感觉温热舒适为度。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (18, '以下哪种药材具有祛风除湿的功效？', '[\"钩藤\", \"透骨草\", \"金银花\", \"茯苓\"]', '透骨草', '侗药常识', 'easy', 'B', '透骨草具有祛风除湿、舒筋活血、止痛的功效，常用于治疗风湿痹痛、筋骨挛缩等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (19, '侗族药浴疗法的浸泡时间一般是？', '[\"5-10分钟\", \"20-30分钟\", \"1小时以上\", \"2小时以上\"]', '20-30分钟', '侗医疗法', 'easy', 'B', '侗族药浴疗法的浸泡时间一般为20-30分钟，时间过短效果不佳，过长则容易疲劳。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (20, '何首乌的主要功效是什么？', '[\"清热解毒\", \"补肝肾，益精血，乌须发\", \"祛风除湿\", \"健脾益肺\"]', '补肝肾，益精血，乌须发', '侗药常识', 'easy', 'B', '何首乌制用具有补肝肾、益精血、乌须发的功效，生用具有解毒、消痈、润肠通便的功效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (21, '侗族医药的理论体系主要基于？', '[\"现代医学理论\", \"中医理论+侗族民间经验\", \"西医理论\", \"印度医学理论\"]', '中医理论+侗族民间经验', '文化背景', 'medium', 'B', '侗族医药的理论体系主要基于中医理论，结合侗族民间长期积累的医疗经验，形成了独特的民族医药体系。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (22, '以下哪种药材适合用于药浴？', '[\"钩藤\", \"艾叶\", \"天麻\", \"何首乌\"]', '艾叶', '侗医疗法', 'easy', 'B', '艾叶是侗族药浴疗法的主要药材之一，具有温经止血、散寒止痛、祛湿止痒的功效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (23, '侗医治疗小儿惊风的代表方剂是？', '[\"钩藤+天麻+金银花+茯苓\", \"透骨草+艾叶\", \"八角莲+七叶一枝花\", \"杜仲+黄精\"]', '钩藤+天麻+金银花+茯苓', '侗医疗法', 'hard', 'A', '侗医治疗小儿惊风的代表方剂由钩藤、天麻、金银花、茯苓组成，具有息风止痉、清热安神的功效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (24, '杜仲的主要功效是什么？', '[\"清热解毒\", \"补肝肾，强筋骨\", \"活血化瘀\", \"祛风除湿\"]', '补肝肾，强筋骨', '侗药常识', 'easy', 'B', '杜仲具有补肝肾、强筋骨、安胎的功效，常用于治疗肾虚腰痛、筋骨无力等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (25, '侗族医药的文化价值体现在？', '[\"仅是医疗技术\", \"医疗技术+民族文化传承\", \"仅是文化展示\", \"仅是经济价值\"]', '医疗技术+民族文化传承', '文化背景', 'easy', 'B', '侗族医药不仅是医疗技术，更是侗族文化的重要组成部分，承载着侗族人民的智慧和文化遗产。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (26, '黄精的主要功效是什么？', '[\"清热解毒\", \"补气养阴，健脾润肺\", \"活血化瘀\", \"祛风除湿\"]', '补气养阴，健脾润肺', '侗药常识', 'easy', 'B', '黄精具有补气养阴、健脾、润肺、益肾的功效，常用于治疗脾胃气虚、体倦乏力等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (27, '侗族推拿疗法的手法不包括？', '[\"推法\", \"拿法\", \"针灸法\", \"揉法\"]', '针灸法', '侗医疗法', 'easy', 'C', '侗族推拿疗法的手法包括推法、拿法、按法、摩法、揉法、捏法等，针灸法不属于推拿手法。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (28, '茯苓的主要功效是什么？', '[\"清热解毒\", \"利水渗湿，健脾宁心\", \"活血化瘀\", \"祛风除湿\"]', '利水渗湿，健脾宁心', '侗药常识', 'easy', 'B', '茯苓具有利水渗湿、健脾、宁心的功效，常用于治疗水肿尿少、痰饮眩悸、脾虚食少等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (29, '侗族拔罐疗法的留罐时间是？', '[\"5分钟以下\", \"10-15分钟\", \"30分钟以上\", \"1小时以上\"]', '10-15分钟', '侗医疗法', 'easy', 'B', '侗族拔罐疗法的留罐时间一般为10-15分钟，时间过长容易造成皮肤损伤。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (30, '车前草的主要功效是什么？', '[\"清热利尿，祛痰止咳\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]', '清热利尿，祛痰止咳', '侗药常识', 'easy', 'A', '车前草具有清热利尿、祛痰止咳的功效，常用于治疗水肿尿少、热淋涩痛、痰热咳嗽等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (31, '侗族熏蒸疗法的温度控制是？', '[\"以患者感觉温热舒适为度\", \"越热越好\", \"常温即可\", \"需要冰镇\"]', '以患者感觉温热舒适为度', '侗医疗法', 'easy', 'A', '侗族熏蒸疗法的温度以患者感觉温热舒适为度，距离适当，防止烫伤。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (32, '半夏的主要功效是什么？', '[\"清热解毒\", \"燥湿化痰，降逆止呕\", \"活血化瘀\", \"祛风除湿\"]', '燥湿化痰，降逆止呕', '侗药常识', 'easy', 'B', '半夏具有燥湿化痰、降逆止呕、消痞散结的功效，常用于治疗痰多咳喘、痰饮眩悸等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (33, '侗族医药的\"四诊\"是指？', '[\"望闻问切\", \"视触叩听\", \"望闻问切+摸\", \"望触叩听\"]', '望闻问切+摸', '文化背景', 'medium', 'C', '侗族医药的诊断方法包括望、闻、问、切四诊，此外还有\"摸\"诊，即触诊患处。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (34, '吴茱萸的主要功效是什么？', '[\"清热解毒\", \"散寒止痛，降逆止呕\", \"活血化瘀\", \"祛风除湿\"]', '散寒止痛，降逆止呕', '侗药常识', 'easy', 'B', '吴茱萸具有散寒止痛、降逆止呕、助阳止泻的功效，常用于治疗厥阴头痛、寒疝腹痛等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (35, '侗族药浴疗法不适合的人群是？', '[\"风湿病患者\", \"孕妇\", \"健康人群\", \"老年人\"]', '孕妇', '侗医疗法', 'easy', 'B', '侗族药浴疗法不适合孕妇、月经期妇女、严重心脏病患者等人群，需谨慎使用。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (36, '高良姜的主要功效是什么？', '[\"清热解毒\", \"温胃散寒，消食止痛\", \"活血化瘀\", \"祛风除湿\"]', '温胃散寒，消食止痛', '侗药常识', 'easy', 'B', '高良姜具有温胃散寒、消食止痛的功效，常用于治疗脘腹冷痛、胃寒呕吐等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (37, '侗族医药的\"天人合一\"思想是指？', '[\"人与自然和谐统一\", \"人与社会和谐统一\", \"人与他人和谐统一\", \"人与动物和谐统一\"]', '人与自然和谐统一', '文化背景', 'medium', 'A', '侗族医药的\"天人合一\"思想认为人与自然是一个整体，疾病的发生与自然环境密切相关。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (38, '陈皮的主要功效是什么？', '[\"清热解毒\", \"理气健脾，燥湿化痰\", \"活血化瘀\", \"祛风除湿\"]', '理气健脾，燥湿化痰', '侗药常识', 'easy', 'B', '陈皮具有理气健脾、燥湿化痰的功效，常用于治疗脘腹胀满、食少吐泻、咳嗽痰多等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (39, '侗族艾灸疗法的禁忌不包括？', '[\"孕妇腹部\", \"高热患者\", \"皮肤破损处\", \"健康人群\"]', '健康人群', '侗医疗法', 'easy', 'D', '侗族艾灸疗法的禁忌包括孕妇腹部、高热患者、皮肤破损处等，健康人群可以进行艾灸保健。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (40, '菊花的主要功效是什么？', '[\"清热解毒，平肝明目\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]', '清热解毒，平肝明目', '侗药常识', 'easy', 'A', '菊花具有散风清热、平肝明目、清热解毒的功效，常用于治疗风热感冒、头痛眩晕等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (41, '侗族医药的发展前景包括？', '[\"国家政策支持\", \"传承人老龄化\", \"年轻一代兴趣不足\", \"以上都是\"]', '以上都是', '文化背景', 'medium', 'D', '侗族医药的发展前景广阔，但也面临传承人老龄化、年轻一代兴趣不足等挑战。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (42, '郁金的主要功效是什么？', '[\"清热解毒\", \"活血止痛，行气解郁\", \"补气养血\", \"祛风除湿\"]', '活血止痛，行气解郁', '侗药常识', 'easy', 'B', '郁金具有活血止痛、行气解郁、清心凉血、利胆退黄的功效，常用于治疗胸胁刺痛、黄疸等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (43, '侗族正骨疗法主要用于治疗？', '[\"感冒发热\", \"骨折脱臼\", \"消化不良\", \"失眠多梦\"]', '骨折脱臼', '侗医疗法', 'easy', 'B', '侗族正骨疗法主要用于治疗骨折、脱臼、跌打损伤等骨伤科疾病。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (44, '茵陈的主要功效是什么？', '[\"清热解毒\", \"清利湿热，利胆退黄\", \"活血化瘀\", \"祛风除湿\"]', '清利湿热，利胆退黄', '侗药常识', 'easy', 'B', '茵陈具有清利湿热、利胆退黄的功效，是治疗黄疸的要药，常用于治疗黄疸尿少、湿温暑湿等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (45, '侗族医药的传承方式不包括？', '[\"家族传承\", \"师徒传承\", \"学校教育\", \"网络传承\"]', '网络传承', '文化背景', 'easy', 'D', '侗族医药的传统传承方式主要是家族传承和师徒传承，现代也有学校教育，网络传承不是传统方式。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (46, '金钱草的主要功效是什么？', '[\"清热解毒\", \"利湿退黄，利尿通淋\", \"活血化瘀\", \"祛风除湿\"]', '利湿退黄，利尿通淋', '侗药常识', 'easy', 'B', '金钱草具有利湿退黄、利尿通淋、解毒消肿的功效，常用于治疗黄疸、胆胀胁痛、石淋等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (47, '侗族医药与中医的主要区别是？', '[\"理论体系不同\", \"传承方式不同\", \"药物来源不同\", \"以上都是\"]', '以上都是', '文化背景', 'hard', 'D', '侗族医药与中医在理论体系、传承方式、药物来源、治疗方法等方面都有所不同。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (48, '虎杖的主要功效是什么？', '[\"清热解毒\", \"利湿退黄，清热解毒，散瘀止痛\", \"补气养血\", \"祛风除湿\"]', '利湿退黄，清热解毒，散瘀止痛', '侗药常识', 'easy', 'B', '虎杖具有利湿退黄、清热解毒、散瘀止痛、止咳化痰的功效，常用于治疗湿热黄疸、淋浊等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (49, '侗族药浴疗法的主要药材不包括？', '[\"艾叶\", \"透骨草\", \"钩藤\", \"金银花\"]', '金银花', '侗医疗法', 'easy', 'D', '侗族药浴疗法的主要药材包括艾叶、透骨草、钩藤等，金银花一般用于清热解毒，不是药浴主要药材。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (50, '侗医\"三气\"理论中的\"三气\"是指？', '[\"天气、地气、人气\", \"寒气、热气、湿气\", \"阳气、阴气、中气\", \"风气、寒气、暑气\"]', '天气、地气、人气', '文化背景', 'hard', 'A', '侗医\"三气\"理论认为天气、地气、人气三者相互影响，人体疾病的发生与三气失调密切相关，这是侗医独特的理论体系。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (51, '九节茶在侗医中的主要用途是？', '[\"清热解毒，祛风通络\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]', '清热解毒，祛风通络', '侗药常识', 'medium', 'A', '九节茶具有清热解毒、祛风通络、活血止痛的功效，侗医常用于治疗风湿关节痛、跌打损伤等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (52, '侗医刮痧疗法常用的润滑介质是？', '[\"清水\", \"茶油或姜汁\", \"酒精\", \"凡士林\"]', '茶油或姜汁', '侗医疗法', 'medium', 'B', '侗医刮痧疗法常用茶油或姜汁作为润滑介质，茶油可润肤活血，姜汁可温经散寒，增强刮痧疗效。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (53, '侗族医药的\"寒热辨证\"与中医相比有何特点？', '[\"完全相同\", \"更注重地域湿邪特点\", \"只辨寒不辨热\", \"不进行辨证\"]', '更注重地域湿邪特点', '文化背景', 'hard', 'B', '侗族医药的寒热辨证在中医基础上更注重南方山区多湿多雾的地域特点，强调湿邪致病的特殊性。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (54, '白及的主要功效是什么？', '[\"清热解毒\", \"收敛止血，消肿生肌\", \"活血化瘀\", \"祛风除湿\"]', '收敛止血，消肿生肌', '侗药常识', 'easy', 'B', '白及具有收敛止血、消肿生肌的功效，常用于治疗咯血、吐血、外伤出血、疮疡肿毒等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (55, '侗族药浴疗法的最佳季节是？', '[\"春季\", \"夏季\", \"秋季\", \"冬季\"]', '夏季', '侗医疗法', 'easy', 'B', '侗族药浴疗法以夏季最为盛行，夏季毛孔开泄，药力更易渗透，祛风除湿效果最佳。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (56, '侗医\"以毒攻毒\"疗法的典型应用是？', '[\"用八角莲治疗蛇伤\", \"用钩藤治疗头痛\", \"用杜仲强筋骨\", \"用陈皮理气\"]', '用八角莲治疗蛇伤', '侗医疗法', 'hard', 'A', '侗医\"以毒攻毒\"疗法的典型应用是用八角莲等有毒药物治疗毒蛇咬伤，利用其解毒散结之力对抗蛇毒。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (57, '侗族医药保护面临的最大的挑战是？', '[\"药材资源丰富\", \"传承人老龄化严重\", \"政府不支持\", \"西医已完全替代\"]', '传承人老龄化严重', '文化背景', 'easy', 'B', '侗族医药保护面临的最大挑战是传承人老龄化严重，年轻一代学习意愿不足，传统知识面临失传风险。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (58, '板蓝根在侗医中的主要用途是？', '[\"清热解毒，凉血利咽\", \"补气养血\", \"祛风除湿\", \"健脾益肺\"]', '清热解毒，凉血利咽', '侗药常识', 'easy', 'A', '板蓝根具有清热解毒、凉血利咽的功效，侗医常用于治疗温毒发斑、风热感冒、咽喉肿痛等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (59, '侗族火针疗法的操作要点是？', '[\"将针烧红后快速刺入穴位\", \"将针加热后缓慢刺入\", \"常温针刺入后加热\", \"用电针刺激\"]', '将针烧红后快速刺入穴位', '侗医疗法', 'hard', 'A', '侗族火针疗法是将特制针具在火上烧红后快速刺入穴位或患处，利用温热刺激达到温经散寒、通络止痛的效果。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (60, '以下哪种药材是侗族地区特有的药食两用植物？', '[\"人参\", \"折耳根（鱼腥草）\", \"冬虫夏草\", \"灵芝\"]', '折耳根（鱼腥草）', '侗药常识', 'easy', 'B', '折耳根（鱼腥草）是侗族地区最常见的药食两用植物，既是日常蔬菜，也是清热解毒的常用药材。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (61, '侗医\"摸诊\"主要检查的内容是？', '[\"患者体温\", \"患处的形态、温度、压痛\", \"患者面色\", \"患者脉搏\"]', '患处的形态、温度、压痛', '文化背景', 'medium', 'B', '侗医\"摸诊\"是侗族医药特色诊断方法，通过触摸患处检查其形态变化、皮肤温度、压痛程度等来判断病情。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (62, '侗族药浴的药液制备方法是？', '[\"直接将药材放入热水中\", \"先煎煮药材取汁再兑水\", \"用冷水浸泡药材\", \"用酒精提取药效\"]', '先煎煮药材取汁再兑水', '侗医疗法', 'medium', 'B', '侗族药浴的药液制备方法是先将药材加水煎煮30-40分钟，取药汁兑入浴水中，使药效充分释放。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (63, '薏苡仁在侗医中的主要功效是？', '[\"清热解毒\", \"利水渗湿，健脾止泻\", \"活血化瘀\", \"祛风除湿\"]', '利水渗湿，健脾止泻', '侗药常识', 'easy', 'B', '薏苡仁具有利水渗湿、健脾止泻、除痹、清热排脓的功效，侗医常用于治疗水肿、脚气、湿痹拘挛等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (64, '侗族医药中\"冷骨风\"指的是？', '[\"感冒\", \"风湿性关节炎\", \"胃寒\", \"肾虚\"]', '风湿性关节炎', '文化背景', 'hard', 'B', '侗族医药中\"冷骨风\"是对风湿性关节炎的侗语称谓，因患者自觉骨节冷痛如风吹而得名，是侗医常见病证。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (65, '侗医推拿疗法治疗小儿积食常用手法是？', '[\"只揉腹部\", \"推三关、揉中脘、摩腹\", \"只捏脊柱\", \"只按足三里\"]', '推三关、揉中脘、摩腹', '侗医疗法', 'hard', 'B', '侗医推拿治疗小儿积食常用推三关、揉中脘、摩腹等手法配合，起到健脾和胃、消食导滞的效果。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (66, '土茯苓在侗医中的主要用途是？', '[\"清热解毒，除湿通络\", \"补气养血\", \"滋阴补肾\", \"活血化瘀\"]', '清热解毒，除湿通络', '侗药常识', 'easy', 'A', '土茯苓具有解毒除湿、通利关节的功效，侗医常用于治疗梅毒、汞中毒、湿热淋浊、筋骨挛痛等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (67, '侗族拔罐疗法常配合什么一起使用？', '[\"艾灸\", \"药酒擦涂\", \"西药口服\", \"手术切除\"]', '药酒擦涂', '侗医疗法', 'medium', 'B', '侗族拔罐疗法常配合药酒擦涂患处使用，药酒活血通络，拔罐祛风散寒，两者配合疗效更佳。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (68, '侗族医药的\"歌诀传承\"是指？', '[\"用歌谣形式记忆药方和疗法\", \"用文字记录药方\", \"用图画描绘药材\", \"用视频教学\"]', '用歌谣形式记忆药方和疗法', '文化背景', 'medium', 'A', '侗族医药的\"歌诀传承\"是将药方、疗法、诊断经验编成歌谣口诀，便于记忆和口耳相传，是侗医独特的传承方式。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (69, '蛇不过在侗医中的主要功效是？', '[\"清热解毒，利湿退黄\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]', '清热解毒，利湿退黄', '侗药常识', 'easy', 'A', '蛇不过（杠板归）具有清热解毒、利湿退黄、消肿散瘀的功效，侗医常用于治疗蛇虫咬伤、湿热黄疸等症。', '2026-04-29 16:54:31');
INSERT INTO `quiz_questions` VALUES (70, '侗医\"药引子\"的作用是？', '[\"替代主药\", \"引导药力到达病所，增强疗效\", \"降低药效\", \"仅作调味用\"]', '引导药力到达病所，增强疗效', '侗医疗法', 'hard', 'B', '侗医\"药引子\"是侗族医药的特色概念，指在方剂中加入特定药材作为引导，使药力直达病所，增强整体疗效。', '2026-04-29 16:54:31');
