INSERT INTO `resources` VALUES (1, '黔东南地区侗族药物系统研究', '专业', '[{\"path\":\"documents/pdf/resources/黔东南地区侗族药物研究_杨晓琼.pdf\",\"name\":\"黔东南地区侗族药物研究_杨晓琼.pdf\",\"size\":421560,\"type\":\"pdf\"}]', '本文通过8年实地调查，系统梳理黔东南侗族734种药物的构成、分类、命名及临床应用，建立侗族药物凭证标本室，完成500余种侗药标本数字化并实现互联网共享，为侗医药传承提供重要物质与理论基础。', 18, 215, '2026-03-05 09:20:00', 29, 22, '[{\"id\":1773739539994,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533825,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682003,\"time\":\"2026-03-05\",\"content\":\"创建学习资源：黔东南地区侗族药物系统研究\",\"operator\":\"系统\"}]', '2026-04-30 00:26:52');
INSERT INTO `resources` VALUES (2, '侗族药食两用药物理论与应用', '入门', '[{\"path\":\"documents/pdf/resources/侗族药食两用药物的理论研究_龙运光.pdf\",\"name\":\"侗族药食两用药物的理论研究_龙运光.pdf\",\"size\":378920,\"type\":\"pdf\"}]', '本文梳理侗族142种药食两用物种，涵盖植物、动物、矿物三类，解析药食同源文化渊源与饮食养生理念，详解侗家油茶、牛瘪等特色药膳的养生功效，内容通俗易懂，适合侗医药养生入门学习。', 35, 380, '2026-03-06 10:15:00', 43, 36, '[{\"id\":1773739539995,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533826,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682004,\"time\":\"2026-03-06\",\"content\":\"创建学习资源：侗族药食两用药物理论与应用\",\"operator\":\"系统\"}]', '2026-04-30 01:04:41');
INSERT INTO `resources` VALUES (3, '侗医常用蕨类植物图鉴与药用经验', '进阶', '[{\"path\":\"documents/pdf/resources/侗医常用的蕨类植物_吴洁.pdf\",\"name\":\"侗医常用的蕨类植物_吴洁.pdf\",\"size\":321540,\"type\":\"pdf\"}]', '本文整理凤尾蕨、石松、金毛狗等17种侗族常用蕨类药用植物，详细标注侗药名、基源、生长环境、性味功用及临床应用经验，是侗医临床应用蕨类药材的实用工具书。', 22, 246, '2026-03-07 14:30:00', 30, 24, '[{\"id\":1773739539996,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533827,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682005,\"time\":\"2026-03-07\",\"content\":\"创建学习资源：侗医常用蕨类植物图鉴与药用经验\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (4, '少数民族医药保护与标准化发展', '入门', '[{\"path\":\"documents/pdf/resources/完善少数民族医药 彰显传统精华 - 中国非物质文化遗产网·中国非物质文化遗产数字博物馆.pdf\",\"name\":\"完善少数民族医药 彰显传统精华 - 中国非物质文化遗产网·中国非物质文化遗产数字博物馆.pdf\",\"size\":286300,\"type\":\"pdf\"}]', '本文分析少数民族医药的地域特色、传承现状与发展瓶颈，重点介绍侗医药（过路黄药制作工艺）等非遗项目，提出标准化、人才培养、专利保护等发展建议，适合民族医药文化普及。', 29, 320, '2026-03-08 08:45:00', 36, 31, '[{\"id\":1773739539997,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533828,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682006,\"time\":\"2026-03-08\",\"content\":\"创建学习资源：少数民族医药保护与标准化发展\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (5, '侗族常用蔷薇科植物药详解与验方集', '进阶', '[{\"path\":\"documents/pdf/resources/侗医治疗疾病常用的蔷薇科植物药_何康.pdf\",\"name\":\"侗医治疗疾病常用的蔷薇科植物药_何康.pdf\",\"size\":356200,\"type\":\"pdf\"}]', '本文收录多花蔷薇、金樱子、龙芽草等15种侗族常用蔷薇科植物药，涵盖侗药名、基源、化学成分、药理作用、性味功效及民间验方，适用于侗医临床用药参考与进阶学习。', 26, 278, '2026-03-09 11:20:00', 33, 28, '[{\"id\":1773739539998,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533829,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682007,\"time\":\"2026-03-09\",\"content\":\"创建学习资源：侗族常用蔷薇科植物药详解与验方集\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (6, '侗药学基础理论体系研究', '专业', '[{\"path\":\"documents/pdf/resources/试论侗药学理论特色_田兰.pdf\",\"name\":\"试论侗药学理论特色_田兰.pdf\",\"size\":307900,\"type\":\"pdf\"}]', '本文系统阐释侗药学核心理论，包括药物命名方法、性味功能、分类体系、采收炮制、配伍原则及用药特色，解析“天、地、气、水、人”五位一体学术思想对侗药应用的指导作用，是侗医药理论研究权威文献。', 14, 192, '2026-03-10 15:40:00', 21, 19, '[{\"id\":1773739539999,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533830,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682008,\"time\":\"2026-03-10\",\"content\":\"创建学习资源：侗药学基础理论体系研究\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (7, '侗族传统医药文化与民间疗法', '入门', '[{\"path\":\"documents/pdf/resources/侗族的传统医药_阿土.pdf\",\"name\":\"侗族的传统医药_阿土.pdf\",\"size\":265800,\"type\":\"pdf\"}]', '本文介绍侗族传统医药的历史渊源，包括茶叶药用、寒泉疗法、麻疹预防等民间经验，详解刮痧、炸灯火、滚蛋法等特色诊疗技术，展现侗族医药“简、便、廉、验”的特点，适合文化普及入门。', 31, 345, '2026-03-11 09:10:00', 39, 33, '[{\"id\":1773739540000,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533831,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682009,\"time\":\"2026-03-11\",\"content\":\"创建学习资源：侗族传统医药文化与民间疗法\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (8, '侗族医药临床特点与行医规范', '进阶', '[{\"path\":\"documents/pdf/resources/浅谈侗族医药特点及行医事宜_杨光团.pdf\",\"name\":\"浅谈侗族医药特点及行医事宜_杨光团.pdf\",\"size\":298600,\"type\":\"pdf\"}]', '本文总结侗族医药“就地取材、副作用小、价格低廉”的临床特点，涵盖药物治疗与非药物治疗两大类方法，提出行医过程中的病例登记、随访管理、知识更新等规范建议，适用于侗医从业者参考。', 23, 254, '2026-03-12 13:30:00', 28, 25, '[{\"id\":1773739540001,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533832,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682010,\"time\":\"2026-03-12\",\"content\":\"创建学习资源：侗族医药临床特点与行医规范\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (9, '侗族药物分类与命名方法系统研究', '专业', '[{\"path\":\"documents/pdf/resources/侗族药物的类别和命名方法_龙运光.pdf\",\"name\":\"侗族药物的类别和命名方法_龙运光.pdf\",\"size\":312500,\"type\":\"pdf\"}]', '本文以705种侗族药物为样本，解析植物药、动物药、矿物药的类别构成，系统研究“类别词+特征词”“药用器官+专指名”等三大命名方法及汉语借词应用规律，揭示侗药命名的民族文化特色。', 16, 208, '2026-03-13 10:00:00', 24, 21, '[{\"id\":1773739540002,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533833,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682011,\"time\":\"2026-03-13\",\"content\":\"创建学习资源：侗族药物分类与命名方法系统研究\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (10, '侗族药用植物物种普查与文化研究', '专业', '[{\"path\":\"documents/pdf/resources/侗族药用植物_郭伟伟.pdf\",\"name\":\"侗族药用植物_郭伟伟.pdf\",\"size\":416800,\"type\":\"pdf\"}]', '本文基于2011-2016年调查，记录侗族药用植物750种，占药用物种的87.01%，详解其分类、命名规律及物种构成，分析侗语固有词与汉语借词在药名中的应用，为侗药资源保护提供数据支撑。', 19, 226, '2026-03-14 14:20:00', 27, 23, '[{\"id\":1773739540003,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533834,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682012,\"time\":\"2026-03-14\",\"content\":\"创建学习资源：侗族药用植物物种普查与文化研究\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (11, '侗族医学发展史考证', '专业', '[{\"path\":\"documents/pdf/resources/侗族医学史略_田华咏.pdf\",\"name\":\"侗族医学史略_田华咏.pdf\",\"size\":334200,\"type\":\"pdf\"}]', '本文系统考证侗族医药从神话传说时代、巫傩医学时代、近代“医药合一”到现代系统发展的完整历程，梳理手抄本医籍、传统疗法演变及多元文化影响，是侗医药历史研究的核心资料。', 12, 178, '2026-03-15 09:50:00', 204, 18, '[{\"id\":1773739540004,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533835,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682013,\"time\":\"2026-03-15\",\"content\":\"创建学习资源：侗族医学发展史考证\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (12, '全国侗医药学术研讨会成果综述', '入门', '[{\"path\":\"documents/pdf/resources/侗族医药备受关注_记者__黄岚.pdf\",\"name\":\"侗族医药备受关注_记者__黄岚.pdf\",\"size\":245600,\"type\":\"pdf\"}]', '本文报道全国第三届侗医药学术研讨会盛况，汇集近500名专家学者的研究成果，展示少数民族民间医师医技及义诊活动，反映侗医药事业的发展机遇与行业关注热点。', 27, 302, '2026-03-16 11:30:00', 348, 29, '[{\"id\":1773739540005,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533836,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682014,\"time\":\"2026-03-16\",\"content\":\"创建学习资源：全国侗医药学术研讨会成果综述\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (13, '侗族医药传承模式与发展策略', '进阶', '[{\"path\":\"documents/pdf/resources/侗族医药传承与发展思考_龙彦合.pdf\",\"name\":\"侗族医药传承与发展思考_龙彦合.pdf\",\"size\":289700,\"type\":\"pdf\"}]', '本文回顾侗族医药“口传-文传”的传承历史，分析师带徒、家族传承的现状与局限，提出人员普查、经验整理、标准制定、教材编写等发展对策，为侗医药可持续发展提供理论参考。', 24, 265, '2026-03-17 15:10:00', 298, 26, '[{\"id\":1773739540006,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533837,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682015,\"time\":\"2026-03-17\",\"content\":\"创建学习资源：侗族医药传承模式与发展策略\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (14, '侗族医药研究现状与学术进展', '专业', '[{\"path\":\"documents/pdf/resources/侗族医药研究概述_刘艺兰.pdf\",\"name\":\"侗族医药研究概述_刘艺兰.pdf\",\"size\":356890,\"type\":\"pdf\"}]', '本文综述侗族医药理论体系形成过程，梳理临床疗效验证、药物研发、文化哲学研究等领域的学术成果，分析研究手段与跨学科合作的现状及不足，为后续研究提供方向指引。', 15, 19, '2026-03-18 10:40:00', 232, 20, '[{\"id\":1773739540007,\"time\":\"2026-03-18\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533838,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682016,\"time\":\"2026-03-18\",\"content\":\"创建学习资源：侗族医药研究现状与学术进展\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (15, '侗族常用百合科植物药详解与验方', '进阶', '[{\"path\":\"documents/pdf/resources/侗族治疗疾病常用的百合科植物药_刘亚华.pdf\",\"name\":\"侗族治疗疾病常用的百合科植物药_刘亚华.pdf\",\"size\":298630,\"type\":\"pdf\"}]', '本文收录多花黄精、麦冬、七叶一枝花等12种侗族常用百合科植物药，系统阐述侗药名、基源、化学成分、药理活性、性味功效及配伍验方，适用于侗医临床用药与进阶学习。', 21, 23, '2026-03-19 14:00:00', 276, 24, '[{\"id\":1773739540008,\"time\":\"2026-03-20\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533839,\"time\":\"2026-03-19\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682017,\"time\":\"2026-03-19\",\"content\":\"创建学习资源：侗族常用百合科植物药详解与验方\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (16, '侗族常用菊科植物药临床应用指南', '进阶', '[{\"path\":\"documents/pdf/resources/侗族治疗疾病常用的菊科植物_邹娟.pdf\",\"name\":\"侗族治疗疾病常用的菊科植物_邹娟.pdf\",\"size\":341600,\"type\":\"pdf\"}]', '本文整理大蓟、黄花蒿、蒲公英等17种侗族常用菊科植物药，详细介绍侗药名、基源、化学成分、药理作用、性味功效及民间验方，覆盖感冒发热、肠胃疾病、皮肤病症等常见病治疗。', 20, 22, '2026-03-20 09:25:00', 258, 22, '[{\"id\":1773739540009,\"time\":\"2026-03-21\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533840,\"time\":\"2026-03-20\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682018,\"time\":\"2026-03-20\",\"content\":\"创建学习资源：侗族常用菊科植物药临床应用指南\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (17, '历代本草中的侗药考证', '专业', '[{\"path\":\"documents/pdf/resources/历代本草侗药考_滕建卓.pdf\",\"name\":\"历代本草侗药考_滕建卓.pdf\",\"size\":326780,\"type\":\"pdf\"}]', '本文系统考证宋代《本草图经》至明清《本草纲目》等历代本草文献中记载的侗区药材，梳理桂、朱砂、三七、山獭阴茎等数十种侗药的收录与应用历史，是侗医药本草考证权威文献。', 10, 15, '2026-03-21 13:50:00', 189, 16, '[{\"id\":1773739540010,\"time\":\"2026-03-22\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533841,\"time\":\"2026-03-21\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682019,\"time\":\"2026-03-21\",\"content\":\"创建学习资源：历代本草中的侗药考证\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (18, '侗族医药特色诊疗技法全解', '进阶', '[{\"path\":\"documents/pdf/resources/论侗族医药的特色诊疗_萧成纹.pdf\",\"name\":\"论侗族医药的特色诊疗_萧成纹.pdf\",\"size\":365700,\"type\":\"pdf\"}]', '本文全面讲解侗医“看、摸、算、划”四诊辨证技法，详解推捏、爆灸、刮痧、熏蒸等18种特色治疗方法，以及药鱼、药衣、药佩等独特用药方式，附临床案例，实操性强。', 28, 30, '2026-03-22 10:15:00', 353, 30, '[{\"id\":1773739540011,\"time\":\"2026-03-23\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533842,\"time\":\"2026-03-22\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682020,\"time\":\"2026-03-22\",\"content\":\"创建学习资源：侗族医药特色诊疗技法全解\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (19, '民间侗医药资源保护与开发对策', '专业', '[{\"path\":\"documents/pdf/resources/民间侗医药资源保护现状及开发利用对策研究_湖南医药学院__丁燕.pdf\",\"name\":\"民间侗医药资源保护现状及开发利用对策研究_湖南医药学院__丁燕.pdf\",\"size\":312480,\"type\":\"pdf\"}]', '本文深度分析民间侗医药资源的分布现状、保护瓶颈与开发潜力，从政策支持、产学研融合、市场开拓、人才培养等维度提出系统对策，为侗药资源可持续利用提供理论支撑。', 11, 16, '2026-03-23 14:30:00', 198, 17, '[{\"id\":1773739540012,\"time\":\"2026-03-24\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533843,\"time\":\"2026-03-23\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682021,\"time\":\"2026-03-23\",\"content\":\"创建学习资源：民间侗医药资源保护与开发对策\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (20, '民间侗医药资源现状调查研究', '专业', '[{\"path\":\"documents/pdf/resources/民间侗医药资源现状调查及分析_欧立军.pdf\",\"name\":\"民间侗医药资源现状调查及分析_欧立军.pdf\",\"size\":298650,\"type\":\"pdf\"}]', '本文通过实地调研，系统梳理民间侗医药资源的种类构成、分布特征及传承现状，分析资源流失风险与成因，为制定针对性的保护措施提供数据支撑与决策参考。', 9, 14, '2026-03-24 09:45:00', 165, 14, '[{\"id\":1773739540013,\"time\":\"2026-03-25\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533844,\"time\":\"2026-03-24\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682022,\"time\":\"2026-03-24\",\"content\":\"创建学习资源：民间侗医药资源现状调查研究\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (21, '侗医药与中医药核心差异探析', '专业', '[{\"path\":\"documents/pdf/resources/侗医药与中医药差异之浅析_欧世洪.pdf\",\"name\":\"侗医药与中医药差异之浅析_欧世洪.pdf\",\"size\":286300,\"type\":\"pdf\"}]', '本文从理论体系、病因认知、诊疗方法、用药特色、传承模式等维度，系统对比侗医药与中医药的核心差异，梳理侗医药“天、地、气、水、人”五位一体学术思想，为民族医药差异化研究提供参考。', 13, 18, '2026-03-25 13:20:00', 214, 19, '[{\"id\":1773739540014,\"time\":\"2026-03-26\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533845,\"time\":\"2026-03-25\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682023,\"time\":\"2026-03-25\",\"content\":\"创建学习资源：侗医药与中医药核心差异探析\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (22, '侗药资源保护与产业化发展对策', '专业', '[{\"path\":\"documents/pdf/resources/侗药资源保护开发利用现状及发展对策_吴卫华.pdf\",\"name\":\"侗药资源保护开发利用现状及发展对策_吴卫华.pdf\",\"size\":302480,\"type\":\"pdf\"}]', '本文分析侗药资源的种类分布、研究现状与开发困境，从知识产权保护、标准化生产、市场推广、人才培养等方面提出产业化发展策略，为侗医药产业升级提供理论支持。', 10, 15, '2026-03-26 10:00:00', 178, 15, '[{\"id\":1773739540015,\"time\":\"2026-03-27\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533846,\"time\":\"2026-03-26\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682024,\"time\":\"2026-03-26\",\"content\":\"创建学习资源：侗药资源保护与产业化发展对策\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (23, '侗族常用果类药物临床应用经验集', '进阶', '[{\"path\":\"documents/pdf/resources/侗族常用果类药物研究_龙滢任.pdf\",\"name\":\"侗族常用果类药物研究_龙滢任.pdf\",\"size\":245630,\"type\":\"pdf\"}]', '本文收录山吴萸、枫树果、金樱子果等11种侗族常用果类药物，详细讲解侗医应用经验、验方配伍与临床主治病症，涵盖内、外、妇、儿各科常见病治疗，实操性强。', 19, 22, '2026-03-27 14:40:00', 242, 21, '[{\"id\":1773739540016,\"time\":\"2026-03-28\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533847,\"time\":\"2026-03-27\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682025,\"time\":\"2026-03-27\",\"content\":\"创建学习资源：侗族常用果类药物临床应用经验集\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (24, '天柱县侗医药传承与发展实践', '入门', '[{\"path\":\"documents/pdf/resources/天柱：传承发展好侗医药_贵州日报天眼新闻记者__余光燕__通讯员__伍丽.pdf\",\"name\":\"天柱：传承发展好侗医药_贵州日报天眼新闻记者__余光燕__通讯员__伍丽.pdf\",\"size\":278900,\"type\":\"pdf\"}]', '本文报道天柱县在侗医药传承发展中的实践成果，包括人才培养、诊疗机构建设、特色疗法推广等举措，展现地方政府对民族医药的扶持政策与落地成效，适合政策研究与文化普及。', 26, 29, '2026-03-28 09:30:00', 326, 28, '[{\"id\":1773739540017,\"time\":\"2026-03-29\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533848,\"time\":\"2026-03-28\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682026,\"time\":\"2026-03-28\",\"content\":\"创建学习资源：天柱县侗医药传承与发展实践\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (25, '贵州凯里药市侗族药用植物图鉴', '进阶', '[{\"path\":\"documents/pdf/resources/《贵州凯里药市的侗族药用植物》.pdf\",\"name\":\"《贵州凯里药市的侗族药用植物》.pdf\",\"size\":365400,\"type\":\"pdf\"}]', '本文以贵州凯里药市为调研对象，收录常见侗族药用植物，详细记录其形态特征、药用部位、性味功效及市场流通情况，为侗药采购、鉴别与临床应用提供实用参考。', 23, 25, '2026-03-29 13:10:00', 289, 25, '[{\"id\":1773739540018,\"time\":\"2026-03-30\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533849,\"time\":\"2026-03-29\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682027,\"time\":\"2026-03-29\",\"content\":\"创建学习资源：贵州凯里药市侗族药用植物图鉴\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (26, '侗医药（过路黄药制作工艺）-国家级非遗', '专业', '[{\"path\":\"documents/pdf/resources/【传统医学】 侗医药（过路黄药制作工艺）（贵州省黔东南苗族侗族自治州 国家级） - 非遗网-非遗商城-非物质文化遗产交易平台.pdf\",\"name\":\"【传统医学】 侗医药（过路黄药制作工艺）（贵州省黔东南苗族侗族自治州 国家级） - 非遗网-非遗商城-非物质文化遗产交易平台.pdf\",\"size\":302563,\"type\":\"pdf\"}]', '本文详细介绍国家级非遗项目“侗医药（过路黄药制作工艺）”的历史渊源、制作流程、药用功效及传承现状，附工艺细节与应用案例，是非遗技艺保护与研究的核心资料。', 17, 20, '2026-03-30 10:20:00', 228, 20, '[{\"id\":1773739540019,\"time\":\"2026-03-31\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533850,\"time\":\"2026-03-30\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682028,\"time\":\"2026-03-30\",\"content\":\"创建学习资源：侗医药（过路黄药制作工艺）-国家级非遗\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (27, '广西非遗体验店与侗医药文化传播', '入门', '[{\"path\":\"documents/pdf/resources/第二批广西非遗形象体验店和广西非遗美食体验店评估结果公示 - 通知公告 - 广西壮族自治区文化和旅游厅网站.pdf\",\"name\":\"第二批广西非遗形象体验店和广西非遗美食体验店评估结果公示 - 通知公告 - 广西壮族自治区文化和旅游厅网站.pdf\",\"size\":265800,\"type\":\"pdf\"}]', '本文公示广西第二批非遗形象体验店与美食体验店评估结果，分析非遗体验店在侗医药文化传播、药膳推广中的作用，为民族医药生活化、市场化提供实践参考。', 24, 27, '2026-03-31 14:50:00', 305, 26, '[{\"id\":1773739540020,\"time\":\"2026-04-01\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533851,\"time\":\"2026-03-31\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682029,\"time\":\"2026-03-31\",\"content\":\"创建学习资源：广西非遗体验店与侗医药文化传播\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (28, '侗族非遗养生文化与侗药应用', '入门', '[{\"path\":\"documents/pdf/resources/侗药养生带你体验非遗养生文化 - 三江县总工会 - 柳州市总工会.pdf\",\"name\":\"侗药养生带你体验非遗养生文化 - 三江县总工会 - 柳州市总工会.pdf\",\"size\":289600,\"type\":\"pdf\"}]', '本文介绍三江县侗族非遗养生文化，详解侗药养生理念、药膳制作、药浴疗法等实操内容，结合工会推广案例，展现侗医药在日常养生中的应用价值，通俗易懂。', 32, 35, '2026-04-01 09:10:00', 390, 34, '[{\"id\":1773739540021,\"time\":\"2026-04-02\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533852,\"time\":\"2026-04-01\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682030,\"time\":\"2026-04-01\",\"content\":\"创建学习资源：侗族非遗养生文化与侗药应用\",\"operator\":\"系统\"}]', '2026-04-30 01:05:08');
INSERT INTO `resources` VALUES (29, '侗医药（过路黄药制作工艺）非遗技艺详解', '专业', '[{\"path\":\"documents/pdf/resources/侗医药（过路黄药制作工艺） - 中国非物质文化遗产网·中国非物质文化遗产数字博物馆.pdf\",\"name\":\"侗医药（过路黄药制作工艺） - 中国非物质文化遗产网·中国非物质文化遗产数字博物馆.pdf\",\"size\":312600,\"type\":\"pdf\"}]', '本文从非遗保护视角，详细解析过路黄药制作工艺的技术要点、传承谱系、文化内涵及药用价值，附高清工艺步骤图，为非遗技艺传承与研究提供权威资料。', 15, 18, '2026-04-02 13:30:00', 212, 18, '[{\"id\":1773739540022,\"time\":\"2026-04-03\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533853,\"time\":\"2026-04-02\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682031,\"time\":\"2026-04-02\",\"content\":\"创建学习资源：侗医药（过路黄药制作工艺）非遗技艺详解\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (30, '侗族村寨多元医疗模式个案研究', '专业', '[{\"path\":\"documents/pdf/resources/多元医疗-一个侗族村寨的个案研究.pdf\",\"name\":\"多元医疗-一个侗族村寨的个案研究.pdf\",\"size\":345800,\"type\":\"pdf\"}]', '本文以某侗族村寨为研究对象，探讨传统侗医药与现代医疗、巫傩疗法的多元共存模式，分析各类医疗方式的应用场景、文化内涵及社会功能，为民族医疗人类学研究提供典型案例。', 12, 16, '2026-04-03 10:00:00', 185, 15, '[{\"id\":1773739540023,\"time\":\"2026-04-04\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533854,\"time\":\"2026-04-03\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682032,\"time\":\"2026-04-03\",\"content\":\"创建学习资源：侗族村寨多元医疗模式个案研究\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (31, '侗族医药文化遗产保护与发掘', '进阶', '[{\"path\":\"documents/pdf/resources/发掘保护侗族医药文化遗产.pdf\",\"name\":\"发掘保护侗族医药文化遗产.pdf\",\"size\":298700,\"type\":\"pdf\"}]', '本文分析侗族医药文化遗产的核心价值与面临的传承危机，提出文献整理、技艺抢救、人才培养、数字化保护等具体措施，为民族医药文化遗产保护提供实操指南。', 21, 24, '2026-04-04 14:10:00', 268, 23, '[{\"id\":1773739540024,\"time\":\"2026-04-05\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533855,\"time\":\"2026-04-04\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682033,\"time\":\"2026-04-04\",\"content\":\"创建学习资源：侗族医药文化遗产保护与发掘\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (32, '非遗扶贫与侗医药产业发展', '入门', '[{\"path\":\"documents/pdf/resources/非遗助力扶贫攻坚 - 安全生产 - 广西柳州市文化广电和旅游局网站.pdf\",\"name\":\"非遗助力扶贫攻坚 - 安全生产 - 广西柳州市文化广电和旅游局网站.pdf\",\"size\":276500,\"type\":\"pdf\"}]', '本文介绍柳州市通过非遗保护助力扶贫攻坚的实践，重点阐述侗医药产业在带动就业、增收致富中的作用，展现“非遗+产业+扶贫”的融合发展模式，适合政策参考与普及。', 25, 28, '2026-04-05 09:40:00', 312, 27, '[{\"id\":1773739540025,\"time\":\"2026-04-06\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533856,\"time\":\"2026-04-05\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682034,\"time\":\"2026-04-05\",\"content\":\"创建学习资源：非遗扶贫与侗医药产业发展\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (33, '广西自治区级侗医药非遗传承人名录', '入门', '[{\"path\":\"documents/docx/resources/广西第八批自治区级非物质文化遗产代表性传承人初选名单.docx\",\"name\":\"广西第八批自治区级非物质文化遗产代表性传承人初选名单.docx\",\"size\":245300,\"type\":\"docx\"}]', '本文公示广西第八批自治区级非物质文化遗产代表性传承人初选名单，收录侗医药领域传承人信息，展现侗医药技艺的传承谱系与地方扶持力度，为传承研究提供基础数据。', 20, 23, '2026-04-06 13:20:00', 278, 22, '[{\"id\":1773739540026,\"time\":\"2026-04-07\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533857,\"time\":\"2026-04-06\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682035,\"time\":\"2026-04-06\",\"content\":\"创建学习资源：广西自治区级侗医药非遗传承人名录\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
