INSERT INTO `resources` VALUES (35, '粤桂协作侗医药健康行活动成果', '入门', '[{\"path\":\"documents/docx/resources/江川情深 “医”路同行！粤桂协作·2025年侗医药健康行活动成功举办.docx\",\"name\":\"江川情深 “医”路同行！粤桂协作·2025年侗医药健康行活动成功举办.docx\",\"size\":268700,\"type\":\"docx\"}]', '本文报道粤桂协作2025年侗医药健康行活动盛况，包括义诊服务、技艺交流、人才培训等内容，展现跨区域协作对侗医药推广与发展的推动作用，适合行业交流参考。', 28, 32, '2026-04-08 14:30:00', 342, 30, '[{\"id\":1773739540028,\"time\":\"2026-04-09\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533859,\"time\":\"2026-04-08\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682037,\"time\":\"2026-04-08\",\"content\":\"创建学习资源：粤桂协作侗医药健康行活动成果\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (36, '柳州非遗美食体验店与侗药药膳推广', '入门', '[{\"path\":\"documents/pdf/resources/来柳州，这12家非遗美食体验店满足你的味蕾 - 图片新闻 - 广西柳州市文化广电和旅游厅网站.pdf\",\"name\":\"来柳州，这12家非遗美食体验店满足你的味蕾 - 图片新闻 - 广西柳州市文化广电和旅游厅网站.pdf\",\"size\":275600,\"type\":\"pdf\"}]', '本文推荐柳州12家非遗美食体验店，重点介绍融入侗药元素的特色药膳，详解其食材搭配、养生功效及制作方法，为侗药药膳的生活化、旅游化推广提供参考。', 30, 33, '2026-04-09 09:50:00', 367, 32, '[{\"id\":1773739540029,\"time\":\"2026-04-10\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533860,\"time\":\"2026-04-09\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682038,\"time\":\"2026-04-09\",\"content\":\"创建学习资源：柳州非遗美食体验店与侗药药膳推广\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (37, '柳州市侗医药非遗传承人与传承团体名录', '入门', '[{\"path\":\"documents/pdf/resources/柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":286400,\"type\":\"pdf\"}]', '本文公示柳州市第三批非遗传承人与第一批传承团体名单，收录侗医药领域传承主体信息，展现地方对侗医药技艺传承的规范化支持，为传承研究提供数据支撑。', 22, 25, '2026-04-10 13:40:00', 284, 24, '[{\"id\":1773739540030,\"time\":\"2026-04-11\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533861,\"time\":\"2026-04-10\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682039,\"time\":\"2026-04-10\",\"content\":\"创建学习资源：柳州市侗医药非遗传承人与传承团体名录\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
INSERT INTO `resources` VALUES (38, '苗侗瑶医药传承与人才培养实践', '进阶', '[{\"path\":\"documents/docx/resources/苗侗瑶医薪火相传：中国传承人杨要仁与十六位第二代共绘民族医药新篇章.docx\",\"name\":\"苗侗瑶医薪火相传：中国传承人杨要仁与十六位第二代共绘民族医药新篇章.docx\",\"size\":298300,\"type\":\"docx\"}]', '本文讲述中国传承人杨要仁带领十六位第二代传承苗侗瑶医药的实践历程，分享师带徒、技艺传承、临床实践等经验，为民族医药人才培养提供典型案例。', 24, 27, '2026-04-11 10:30:00', 310, 27, '[{\"id\":1773739540031,\"time\":\"2026-04-12\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533862,\"time\":\"2026-04-11\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682040,\"time\":\"2026-04-11\",\"content\":\"创建学习资源：苗侗瑶医药传承与人才培养实践\",\"operator\":\"系统\"}]', '2026-04-29 16:54:30');
